const SKELETON_SRC="// src/components/Skeleton.jsx\n// Blocs \"squelette\" fa\u00e7on Facebook (shimmer) \u2014 utilis\u00e9s pendant le chargement\n// des pages, \u00e0 la place d'un simple \"Chargement...\".\nexport function SkeletonBlock({ w = '100%', h = 14, r = 8, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: w, height: h, borderRadius: r, ...style }} />\n  );\n}\n\nexport function SkeletonCircle({ size = 40, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: size, height: size, borderRadius: '50%', flexShrink: 0, ...style }} />\n  );\n}\n\n// Squelette d'une publication du fil d'actualit\u00e9s (avatar + lignes + image)\nexport function SkeletonPost() {\n  return (\n    <div className=\"card\" style={{ marginBottom: 12, padding: 14 }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>\n        <SkeletonCircle size={40} />\n        <div style={{ flex: 1 }}>\n          <SkeletonBlock w=\"45%\" h={13} style={{ marginBottom: 6 }} />\n          <SkeletonBlock w=\"25%\" h={10} />\n        </div>\n      </div>\n      <SkeletonBlock w=\"90%\" h={12} style={{ marginBottom: 6 }} />\n      <SkeletonBlock w=\"70%\" h={12} style={{ marginBottom: 12 }} />\n      <SkeletonBlock w=\"100%\" h={180} r={12} />\n    </div>\n  );\n}\n\n// Squelette d'une page \"canal\" (Artiste / Boutique) : banni\u00e8re, titre,\n// boutons, carte info, galerie horizontale \u2014 correspond au visuel Facebook.\nexport function SkeletonChannelPage() {\n  return (\n    <div style={{ paddingBottom: 20 }}>\n      <div className=\"skeleton-shimmer\" style={{ height: 170, borderRadius: 0 }} />\n      <div style={{ padding: '16px 16px 0' }}>\n        <SkeletonBlock w=\"60%\" h={22} style={{ marginBottom: 8 }} />\n        <SkeletonBlock w=\"35%\" h={13} style={{ marginBottom: 16 }} />\n        <div style={{ display: 'flex', gap: 10, marginBottom: 20 }}>\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n        </div>\n      </div>\n      <div style={{ height: 10, background: '#F0F2F5' }} />\n      <div style={{ padding: 16 }}>\n        <div style={{ background: '#F7F8FA', borderRadius: 14, padding: 16, marginBottom: 20 }}>\n          <SkeletonBlock w=\"70%\" h={14} style={{ marginBottom: 10 }} />\n          <SkeletonBlock w=\"95%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"80%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"55%\" h={12} />\n        </div>\n        <SkeletonBlock w=\"40%\" h={14} style={{ marginBottom: 12 }} />\n        <div style={{ display: 'flex', gap: 10 }}>\n          {[0, 1, 2].map((i) => (\n            <div key={i} style={{ flex: 1 }}>\n              <SkeletonBlock w=\"100%\" h={110} r={12} style={{ marginBottom: 6 }} />\n              <SkeletonBlock w=\"80%\" h={10} />\n            </div>\n          ))}\n        </div>\n      </div>\n      <div style={{ padding: '0 16px' }}>\n        <SkeletonPost />\n      </div>\n    </div>\n  );\n}\n";
const CSS_SRC="@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800;900&display=swap');\n@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   TRENGO \u2014 Ultra Premium design system (Facebook format)\n   Blanc \u00b7 Bleu Facebook \u00b7 Jaune \u00b7 Noir \u00b7 Rose cristal \u00b7\n   Dor\u00e9 brillant \u00b7 Argent\u00e9 brillant \u00b7 Orange\n   \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n:root {\n  --blue:        #1877F2;   /* Bleu Facebook */\n  --blue-dark:   #0E5FCB;\n  --blue-pale:   #E7F0FE;\n  --yellow:      #F2B300;   /* Dor\u00e9 (logo) */\n  --orange:      #F2B300;   /* Dor\u00e9 (logo) */\n  --black:       #050505;   /* Noir Facebook */\n  --gray-txt:    #65676B;\n  --pink:        #FF2D8D;   /* Rose cristal */\n  --pink-light:  #FF7AB8;\n  --pink-pale:   #FFE9F4;\n  --gold:        #F2B300;   /* Dor\u00e9 */\n  --gold-light:  #FFE066;\n  --silver:      #C7CCD6;   /* Argent\u00e9 */\n  --silver-light:#F2F4F8;\n  --white:       #FFFFFF;\n  --canvas:      #F0F2F5;   /* Fond gris FB tr\u00e8s clair sur desktop */\n  --line:        #E4E6EB;\n\n  /* Aliases h\u00e9rit\u00e9s (anciens noms utilis\u00e9s dans le code) */\n  --rose:       var(--pink);\n  --rose-light: var(--pink-light);\n  --rose-pale:  var(--pink-pale);\n  --gray-50:  #FFFFFF;\n  --gray-100: #F0F2F5;\n  --gray-200: #E4E6EB;\n  --gray-400: #8A8D91;\n  --gray-600: #65676B;\n  --gray-800: #3A3B3C;\n  --gray-900: #050505;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml {\n  overscroll-behavior-y: contain;   /* desactive le \"glow\" natif Android -> laisse notre pull-to-refresh JS gerer le geste */\n}\n\nbody {\n  font-family: 'Poppins', sans-serif;\n  background: var(--white);      /* fond blanc demand\u00e9 */\n  color: var(--black);\n  min-height: 100vh;\n  overscroll-behavior-y: contain;\n  touch-action: pan-y pan-x;\n}\n\n/* \u2500\u2500 Dark mode (conserv\u00e9) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n.dark body, .dark { background: #0B0D12 !important; color: #E7EAF0 !important; }\n.dark .card, .dark .card-fb { background: #15181F !important; border-color: #232733 !important; color: #E7EAF0 !important; }\n.dark .card p, .dark .card span, .dark .card div,\n.dark p, .dark span, .dark div, .dark h1, .dark h2, .dark h3 { color: #E7EAF0; }\n.dark .input { background: #1C2028 !important; color: #E7EAF0 !important; border-color: #2C3140 !important; }\n.dark .input::placeholder { color: #6E7686 !important; }\n.dark .navbar { background: #15181F !important; border-color: #232733 !important; }\n.dark .nav-item { color: #8A93A6 !important; }\n.dark .nav-item.active, .dark .nav-item.active span { color: var(--blue) !important; }\n.dark .msg-bubble-other { background: #232733; color: #E7EAF0 !important; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOUTONS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n\n/* Bouton principal \u2014 ROSE CRISTAL brillant */\n.btn-primary {\n  position: relative;\n  background: linear-gradient(135deg, #FF2D8D 0%, #FF5EA8 45%, #FF8FC6 100%);\n  color: white;\n  border: 1px solid rgba(255,255,255,0.55);\n  padding: 10px 20px;\n  border-radius: 25px;\n  font-weight: 700;\n  cursor: pointer;\n  transition: all .25s ease;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 4px 18px rgba(255,45,141,.45), inset 0 1px 0 rgba(255,255,255,.6), inset 0 -2px 6px rgba(180,0,90,.25);\n  overflow: hidden;\n}\n.btn-primary::after {              /* reflet cristal */\n  content: '';\n  position: absolute; top: 0; left: -80%;\n  width: 55%; height: 100%;\n  background: linear-gradient(105deg, transparent, rgba(255,255,255,.65), transparent);\n  transform: skewX(-20deg);\n  animation: crystalSweep 3.2s ease-in-out infinite;\n}\n.btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 26px rgba(255,45,141,.6), inset 0 1px 0 rgba(255,255,255,.7); }\n.btn-primary:disabled { opacity: .55; }\n\n/* Bouton bleu Facebook */\n.btn-blue {\n  background: linear-gradient(180deg, #1B84FF, #1877F2);\n  color: white; border: none;\n  padding: 10px 20px; border-radius: 10px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 12px rgba(24,119,242,.35);\n  transition: all .2s ease;\n}\n.btn-blue:hover { background: var(--blue-dark); transform: translateY(-1px); }\n\n/* Bouton secondaire \u2014 ARGENT\u00c9 brillant */\n.btn-secondary {\n  position: relative;\n  background: linear-gradient(135deg, #FDFEFF 0%, #DDE2EC 40%, #C7CCD6 60%, #F2F4F8 100%);\n  background-size: 220% 220%;\n  animation: metalShine 4.5s ease infinite;\n  color: #2B2F38;\n  border: 1px solid #C4CAD6;\n  padding: 8px 18px;\n  border-radius: 25px;\n  font-weight: 600; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 2px 10px rgba(120,130,150,.3), inset 0 1px 0 rgba(255,255,255,.9);\n  transition: all .25s ease;\n}\n.btn-secondary:hover { transform: translateY(-1px); box-shadow: 0 5px 16px rgba(120,130,150,.4); }\n\n/* Bouton DOR\u00c9 brillant */\n.btn-gold {\n  position: relative;\n  background: linear-gradient(135deg, #FFE066 0%, #F2B300 40%, #D99A00 60%, #FFD84D 100%);\n  background-size: 220% 220%;\n  animation: metalShine 4s ease infinite;\n  color: #4A3400;\n  border: 1px solid #E8B400;\n  padding: 8px 18px; border-radius: 25px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 14px rgba(242,179,0,.45), inset 0 1px 0 rgba(255,255,255,.7);\n  transition: all .25s ease;\n}\n.btn-gold:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(242,179,0,.6); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 Skeleton loading (chargement fa\u00e7on Facebook) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.skeleton-shimmer {\n  position: relative;\n  overflow: hidden;\n  background: #E4E6EB;\n}\n.skeleton-shimmer::after {\n  content: '';\n  position: absolute;\n  inset: 0;\n  transform: translateX(-100%);\n  background: linear-gradient(90deg, transparent, rgba(255,255,255,.55), transparent);\n  animation: skeletonSweep 1.4s ease-in-out infinite;\n}\n@keyframes skeletonSweep {\n  100% { transform: translateX(100%); }\n}\n@media (prefers-reduced-motion: reduce) {\n  .skeleton-shimmer::after { animation: none !important; }\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 Effet \"ressort\" (spring) sur TOUS les boutons \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   Appui -> l\u00e9ger r\u00e9tr\u00e9cissement ; rel\u00e2chement -> rebond \u00e9lastique (back-out).\n   Cible l'\u00e9l\u00e9ment <button> natif : couvre la quasi-totalit\u00e9 de l'app sans\n   modifier un seul fichier .jsx (z\u00e9ro risque de r\u00e9gression). */\nbutton {\n  transition: transform .28s cubic-bezier(.34, 1.56, .64, 1);\n}\nbutton:active {\n  transform: scale(.93);\n  transition: transform .08s ease-out;\n}\n/* Renforce l'effet m\u00eame sur les boutons \u00e0 classe d\u00e9di\u00e9e (sp\u00e9cificit\u00e9 CSS) */\n.btn-primary:active, .btn-secondary:active, .btn-gold:active,\n.dock-item:active, .post-action-btn:active {\n  transform: scale(.93);\n  transition: transform .08s ease-out;\n}\n\n/* Bouton orange */\n.btn-orange {\n  background: linear-gradient(135deg, #FFD84D, #F2B300);\n  color: #4A3400;\n  border: none;\n  padding: 8px 18px; border-radius: 25px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 14px rgba(242,179,0,.4);\n  transition: all .2s ease;\n}\n.btn-orange:hover { transform: translateY(-1px); }\n\n@keyframes crystalSweep {\n  0%   { left: -80%; }\n  55%  { left: 130%; }\n  100% { left: 130%; }\n}\n@keyframes metalShine {\n  0%   { background-position: 0% 50%; }\n  50%  { background-position: 100% 50%; }\n  100% { background-position: 0% 50%; }\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 CARTES \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.card {\n  background: white;\n  border-radius: 12px;\n  box-shadow: 0 1px 2px rgba(0,0,0,.1), 0 2px 12px rgba(24,119,242,.05);\n  border: 1px solid var(--line);\n}\n.card-fb {\n  background: white;\n  border-radius: 8px;\n  box-shadow: 0 1px 3px rgba(0,0,0,.12);\n  margin-bottom: 8px;\n  overflow: hidden;\n}\n\n/* Publications pleine largeur (format Facebook mobile) */\n.post-card {\n  border-radius: 0;\n  border-left: none;\n  border-right: none;\n  margin-bottom: 8px;\n  overflow: visible;\n  transition: box-shadow .2s;\n  width: 100%;\n}\n@media (min-width: 700px) {\n  .post-card { border-radius: 12px; border: 1px solid var(--line); }\n}\n.post-card:hover { box-shadow: 0 4px 20px rgba(24,119,242,.1); }\n.post-content-click { cursor: pointer; }\n\n/* M\u00e9dia pleine largeur, bord \u00e0 bord comme Facebook */\n.post-media-full { margin: 8px -16px 0; width: calc(100% + 32px); }\n.post-media-full img, .post-media-full video { width: 100%; display: block; border-radius: 0; }\n\n.input {\n  background: var(--canvas);\n  border: 1.5px solid var(--line);\n  border-radius: 20px;\n  padding: 10px 14px;\n  font-family: 'Poppins', sans-serif;\n  font-size: 14px;\n  color: var(--black);\n  transition: border-color .2s;\n  width: 100%;\n}\n.input:focus { outline: none; border-color: var(--blue); box-shadow: 0 0 0 3px rgba(24,119,242,.12); }\ninput::placeholder, textarea::placeholder { color: #8A8D91 !important; font-size: 13px; }\n.textbg-textarea::placeholder { color: rgba(255,255,255,0.65) !important; font-size: 22px; }\n\n/* Scrollbar */\n::-webkit-scrollbar { width: 5px; height: 5px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: var(--silver); border-radius: 10px; }\n::-webkit-scrollbar-thumb:hover { background: var(--blue); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 ANIMATIONS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n@keyframes fadeIn  { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n@keyframes slideIn { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n@keyframes pulse-blue { 0%,100% { box-shadow: 0 0 0 0 rgba(24,119,242,.4); } 50% { box-shadow: 0 0 0 8px rgba(24,119,242,0); } }\n.animate-fade  { animation: fadeIn .3s ease; }\n.animate-slide { animation: slideIn .3s ease; }\n.pulse-dot     { animation: pulse-blue 2s infinite; }\n\n/* Logo \u2014 halo DOR\u00c9 brillant */\n@keyframes logoShimmer {\n  0%   { filter: brightness(1)   drop-shadow(0 0 0px  #F2B300); }\n  50%  { filter: brightness(1.35) drop-shadow(0 0 14px #FFD84D) drop-shadow(0 0 28px rgba(24,119,242,.55)); }\n  100% { filter: brightness(1)   drop-shadow(0 0 0px  #F2B300); }\n}\n.logo-shimmer { animation: logoShimmer 2.4s ease-in-out infinite; }\n\n/* Texte dor\u00e9 brillant (nom de l'app) */\n.text-gold-shine {\n  background: linear-gradient(90deg, #B8860B, #FFD84D 30%, #F2B300 50%, #FFF2B0 70%, #B8860B);\n  background-size: 250% auto;\n  -webkit-background-clip: text; background-clip: text;\n  -webkit-text-fill-color: transparent; color: transparent;\n  animation: goldFlow 3.5s linear infinite;\n}\n@keyframes goldFlow { to { background-position: 250% center; } }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BADGES \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.notif-badge {\n  background: #FF1744; color: white; border-radius: 9px;\n  min-width: 17px; height: 17px; padding: 0 4px; font-size: 9px; font-weight: 700;\n  display: flex; align-items: center; justify-content: center;\n  position: absolute; top: -5px; right: -6px;\n  border: 2px solid white; box-sizing: border-box;\n  line-height: 1; z-index: 5; pointer-events: none;\n  box-shadow: 0 1px 3px rgba(0,0,0,.25);\n}\n.dark .notif-badge { border-color: #15181F; }\n.avatar { border-radius: 50%; object-fit: cover; border: 2px solid var(--line); }\n.avatar-ring { border: 2px solid var(--blue); }\n\n.sale-badge {\n  background: linear-gradient(135deg, #FFE066, #F2B300);\n  color: #4A3400; border-radius: 20px; padding: 4px 12px;\n  font-size: 12px; font-weight: 800;\n  box-shadow: 0 2px 8px rgba(242,179,0,.4);\n}\n.price-tag { color: var(--pink); font-weight: 800; font-size: 18px; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 MESSAGES (Messenger) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.msg-bubble-me {\n  background: linear-gradient(135deg, #1B84FF, #1877F2);\n  color: white;\n  border-radius: 18px 18px 4px 18px;\n  padding: 10px 14px; max-width: 100%;\n  word-break: break-word; white-space: pre-wrap;\n  line-height: 1.5; font-size: 15px;\n}\n.msg-bubble-other {\n  background: var(--canvas); color: var(--black);\n  border-radius: 18px 18px 18px 4px;\n  padding: 10px 14px; max-width: 100%;\n  word-break: break-word; white-space: pre-wrap;\n  line-height: 1.5; font-size: 15px;\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 DOCK FLOTTANT (style Telegram) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.floating-dock {\n  position: fixed;\n  left: 12px; right: 12px; bottom: 12px;\n  z-index: 100;\n  display: flex;\n  padding: 8px 6px;\n  background: rgba(255,255,255,.92);\n  backdrop-filter: blur(18px);\n  -webkit-backdrop-filter: blur(18px);\n  border: 1px solid rgba(228,230,235,.9);\n  border-radius: 26px;\n  box-shadow: 0 10px 34px rgba(5,5,5,.18), 0 2px 8px rgba(24,119,242,.12), inset 0 1px 0 rgba(255,255,255,.9);\n  max-width: 560px;\n  margin: 0 auto;\n}\n.dark .floating-dock { background: rgba(21,24,31,.92); border-color: #232733; }\n\n/* Animation \"emoji miakatra\" rehefa manao r\u00e9action amin'ny story (format Facebook) */\n.story-emoji-fly {\n  position: fixed; bottom: 90px; font-size: 32px; z-index: 320;\n  pointer-events: none; animation: emojiFly 1.2s ease-out forwards;\n}\n@keyframes emojiFly {\n  0%   { transform: translateY(0) scale(0.5); opacity: 0; }\n  15%  { transform: translateY(-20px) scale(1.3); opacity: 1; }\n  100% { transform: translateY(-220px) scale(1); opacity: 0; }\n}\n\n.dock-item {\n  flex: 1; display: flex; flex-direction: column; align-items: center;\n  gap: 2px; padding: 6px 2px;\n  background: none; border: none; cursor: pointer;\n  font-family: 'Poppins', sans-serif; font-size: 9.5px; font-weight: 500;\n  color: var(--gray-txt);\n  border-radius: 18px;\n  transition: transform .18s ease, background .18s ease;\n}\n.dock-item:active { transform: scale(.9); }\n@keyframes bellShake {\n  0%, 100% { transform: rotate(0deg); }\n  10%, 30% { transform: rotate(-14deg); }\n  20%, 40% { transform: rotate(14deg); }\n  50% { transform: rotate(-8deg); }\n  60% { transform: rotate(8deg); }\n  70% { transform: rotate(0deg); }\n}\n.bell-shake { animation: bellShake 0.7s ease-in-out; animation-iteration-count: 3; }\n\n.dock-icon {\n  width: 40px; height: 40px; border-radius: 14px;\n  display: flex; align-items: center; justify-content: center;\n  position: relative; overflow: hidden;\n  transition: all .2s ease;\n  box-shadow: inset 0 1px 2px rgba(255,255,255,.55), inset 0 -3px 6px rgba(0,0,0,.18), 0 2px 6px rgba(0,0,0,.15);\n}\n.dock-icon::before {\n  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 55%;\n  background: linear-gradient(180deg, rgba(255,255,255,.55), rgba(255,255,255,0));\n  pointer-events: none;\n}\n.dock-icon > * { position: relative; z-index: 1; }\n\n/* Badge d'ic\u00f4ne \"3D\" color\u00e9 (menu plein \u00e9cran, profil, etc.) */\n.icon-badge-3d {\n  position: relative; overflow: hidden;\n  display: flex; align-items: center; justify-content: center;\n  box-shadow: inset 0 2px 3px rgba(255,255,255,.65), inset 0 -4px 8px rgba(0,0,0,.25), 0 4px 12px rgba(0,0,0,.22);\n}\n.icon-badge-3d::before {\n  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 55%;\n  background: linear-gradient(180deg, rgba(255,255,255,.55), rgba(255,255,255,0));\n  pointer-events: none;\n}\n.icon-badge-3d > * { position: relative; z-index: 1; }\n\n/* Balayage lumineux p\u00e9riodique \u2014 .icon-sweep ihany (sidebar/menu), tsy amin'ny navbar/dock */\n.icon-sweep { position: relative; overflow: hidden; }\n.icon-sweep::after {\n  content: '';\n  position: absolute; top: 0; left: -60%; width: 40%; height: 100%;\n  background: linear-gradient(105deg, transparent, rgba(255,255,255,.8), transparent);\n  transform: skewX(-18deg);\n  animation: iconSweep 3.4s ease-in-out infinite;\n  animation-delay: calc(var(--sweep-delay, 0) * 1s);\n  pointer-events: none; z-index: 2;\n}\n@keyframes iconSweep {\n  0%   { left: -60%; }\n  35%  { left: 130%; }\n  100% { left: 130%; }\n}\n@media (prefers-reduced-motion: reduce) {\n  .icon-sweep::after { animation: none !important; }\n}\n/* Navbar : hauteur mitovy foana, tsy misy mihetsika/mamirapiratra */\n.dock-item.active .dock-icon {\n  box-shadow: 0 3px 10px var(--dock-glow, rgba(24,119,242,.45)), inset 0 1px 2px rgba(255,255,255,.6), inset 0 -3px 6px rgba(0,0,0,.22);\n}\n.dock-item.active { font-weight: 700; }\n\n/* Labelle navbar \u2014 soratra noire foana (tsy miloko araka ny ic\u00f4ne) */\n.dock-label {\n  font-size: 10px; font-weight: 600; margin-top: 3px;\n  color: #1C1E21; opacity: .68;\n  font-family: 'Poppins', sans-serif; letter-spacing: .1px;\n  transition: opacity .18s ease, font-weight .18s ease;\n}\n.dock-item.active .dock-label {\n  opacity: 1; font-weight: 700; color: #050505;\n}\n.dark .dock-label { color: #E4E6EB; opacity: .68; }\n.dark .dock-item.active .dock-label { color: #FFFFFF; opacity: 1; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 NAVIGATION RAPIDE (sidebar, horizontale premium) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.quicknav-row {\n  display: flex; gap: 6px; padding: 6px 14px 14px;\n  overflow-x: auto; -webkit-overflow-scrolling: touch;\n  scrollbar-width: none; flex-shrink: 0; min-height: 92px;\n}\n.quicknav-row::-webkit-scrollbar { display: none; }\n.quicknav-item {\n  flex: 1 0 auto; min-width: 62px;\n  display: flex; flex-direction: column; align-items: center; gap: 6px;\n  padding: 12px 6px 10px;\n  background: linear-gradient(160deg, rgba(255,255,255,.9), rgba(247,248,250,.7));\n  border: 1px solid rgba(228,230,235,.9); border-radius: 18px;\n  cursor: pointer; position: relative;\n  transition: transform .16s ease, box-shadow .2s ease, border-color .2s ease;\n  box-shadow: 0 2px 8px rgba(5,5,5,.05), inset 0 1px 0 rgba(255,255,255,.8);\n}\n.dark .quicknav-item {\n  background: linear-gradient(160deg, rgba(30,34,44,.95), rgba(21,24,31,.85));\n  border-color: #232733;\n  box-shadow: 0 2px 8px rgba(0,0,0,.3), inset 0 1px 0 rgba(255,255,255,.05);\n}\n.quicknav-item:active { transform: scale(.94); }\n.quicknav-item.active {\n  border-color: #1877F2;\n  box-shadow: 0 4px 16px rgba(24,119,242,.22), inset 0 1px 0 rgba(255,255,255,.8);\n}\n.quicknav-icon {\n  width: 40px; height: 40px; border-radius: 13px;\n  display: flex; align-items: center; justify-content: center; position: relative;\n  box-shadow: inset 0 2px 3px rgba(255,255,255,.55), inset 0 -3px 6px rgba(0,0,0,.2), 0 3px 8px var(--glow, rgba(0,0,0,.15));\n}\n.quicknav-label {\n  font-size: 10.5px; font-weight: 600; font-family: 'Poppins', sans-serif;\n  white-space: nowrap; letter-spacing: .1px;\n}\n.quicknav-item.active .quicknav-label { font-weight: 800; }\n\n/* Spinner buffering (Reels) \u2014 miseho rehefa tena mbuffer ny video */\n.reel-spinner {\n  width: 46px; height: 46px; border-radius: 50%;\n  border: 3px solid rgba(255,255,255,.25);\n  border-top-color: #fff;\n  animation: reelSpin .8s linear infinite;\n}\n@keyframes reelSpin { to { transform: rotate(360deg); } }\n.nav-item {\n  display: flex; flex-direction: column; align-items: center;\n  padding: 6px 4px; cursor: pointer; border-radius: 12px;\n  transition: all .2s; color: var(--gray-txt); font-size: 11px; gap: 3px;\n  flex: 1; position: relative; font-family: 'Poppins', sans-serif;\n}\n.nav-item:hover { color: var(--blue); background: var(--blue-pale); }\n.nav-item.active { color: var(--blue); }\n.nav-item.active svg { color: var(--blue); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 STORIES (format Facebook) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.stories-strip {\n  display: flex; gap: 8px; overflow-x: auto;\n  padding: 10px 12px; scrollbar-width: none;\n  background: white; border-bottom: 1px solid var(--line);\n}\n.stories-strip::-webkit-scrollbar { display: none; }\n.story-card {\n  flex-shrink: 0; width: 104px; height: 170px;\n  border-radius: 14px; overflow: hidden; position: relative;\n  cursor: pointer; background: #000;\n  box-shadow: 0 2px 10px rgba(0,0,0,.18);\n  transition: transform .18s ease;\n}\n.story-card:active { transform: scale(.96); }\n.story-card video, .story-card img { width: 100%; height: 100%; object-fit: cover; }\n/* L'avatar garde sa petite taille (prioritaire sur .story-card img) */\n.story-card img.story-avatar, .story-avatar {\n  position: absolute; top: 8px; left: 8px;\n  width: 34px !important; height: 34px !important;\n  border-radius: 50%; object-fit: cover;\n  border: 3px solid var(--blue);\n  box-shadow: 0 0 0 2px white;\n  z-index: 2;\n}\n.story-name {\n  position: absolute; bottom: 6px; left: 8px; right: 8px;\n  color: white; font-size: 11px; font-weight: 600;\n  text-shadow: 0 1px 4px rgba(0,0,0,.8);\n  overflow: hidden; text-overflow: ellipsis; white-space: nowrap;\n}\n.story-gradient {\n  position: absolute; inset: 0;\n  background: linear-gradient(transparent 55%, rgba(0,0,0,.65));\n  pointer-events: none;\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 ACTIONS FACEBOOK \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.post-actions-row { display: flex; border-top: 1px solid var(--line); }\n.post-action-btn {\n  flex: 1; display: flex; align-items: center; justify-content: center;\n  gap: 5px; padding: 9px 0;\n  background: none; border: none; cursor: pointer;\n  color: var(--gray-txt); font-size: 13px; font-weight: 600;\n  font-family: 'Poppins', sans-serif; transition: background .15s;\n}\n.post-action-btn:hover { background: var(--canvas); color: var(--blue); }\n.post-action-btn.active { color: #FF2D8D; }\n\n.reactions-bar {\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 8px 16px; border-bottom: 1px solid var(--line);\n}\n.reactions-bar-left  { display: flex; align-items: center; gap: 4px; color: var(--gray-txt); font-size: 13px; }\n.reactions-bar-right { color: var(--gray-txt); font-size: 13px; cursor: pointer; }\n.reactions-bar-right:hover { text-decoration: underline; }\n\n.text-muted { color: var(--gray-txt) !important; }\n.text-dark  { color: var(--black) !important; }\n\n/* Toast */\n.toast {\n  position: fixed; bottom: 90px; left: 50%; transform: translateX(-50%);\n  background: var(--black); color: white;\n  padding: 12px 24px; border-radius: 25px;\n  font-size: 14px; z-index: 9999;\n  animation: fadeIn .3s ease;\n  box-shadow: 0 4px 20px rgba(0,0,0,.25);\n}\n\n.no-scrollbar::-webkit-scrollbar { display: none; }\n.no-scrollbar { scrollbar-width: none; }\n\n.search-input {\n  background: var(--canvas); border: 1.5px solid var(--line);\n  border-radius: 30px; padding: 10px 16px;\n  font-family: 'Poppins', sans-serif; font-size: 14px;\n  color: var(--black); width: 100%;\n}\n.search-input::placeholder { color: #8A8D91; }\n.search-input:focus { outline: none; border-color: var(--blue); }\n\n@media (prefers-reduced-motion: reduce) {\n  .btn-primary::after, .btn-secondary, .btn-gold, .logo-shimmer, .text-gold-shine { animation: none !important; }\n  button, button:active, .btn-primary:active, .btn-secondary:active, .btn-gold:active, .dock-item:active, .post-action-btn:active { transform: none !important; transition: none !important; }\n}\n";
const HOME_SRC="// src/pages/Home.jsx\nimport { useState, useEffect, useRef } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport {\n  collection, addDoc, serverTimestamp, query, orderBy, onSnapshot, limit,\n  doc, updateDoc, arrayUnion, arrayRemove, deleteDoc, writeBatch, getDoc, getDocs, where\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport MediaViewer from '../components/MediaViewer';\nimport { SkeletonPost } from '../components/Skeleton';\nimport ReportModal from '../components/ReportModal';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport PullToRefresh from '../components/PullToRefresh';\nimport { useAuth } from '../context/AuthContext';\nimport { useLang } from '../context/LanguageContext';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { startBackgroundUpload } from '../utils/uploadManager';\nimport { captureVideoThumb } from '../utils/videoThumb';\nimport { trimVideoTo30s } from '../utils/trimVideo';\nimport { timeAgo } from '../utils/timeAgo';\nimport { isDataSaverOn, subscribeDataSaver } from '../utils/dataSaver';\nimport { downloadMedia } from '../utils/download';\nimport ShareModal from '../components/ShareModal';\nimport MusicPostCard from '../components/MusicPostCard';\nimport PhotoCarousel from '../components/PhotoCarousel';\nimport StoryRing from '../components/StoryRing';\nimport SponsoredPost, { useFeedAds } from '../components/SponsoredPost';\nimport StoryStudio, { StoryMusicPlayer } from '../components/StoryStudio';\nimport { useActiveStoryUids } from '../hooks/useActiveStoryUids';\nimport { NeonGlobe, NeonPeople, NeonLock, NeonMic, NeonLocation, NeonLike, NeonComment, NeonShare, NeonPlane, NeonPlaneWhite, NeonEye, NeonStar } from '../components/NeonIcons';\nimport { getChatId } from '../utils/chat';\nimport { ref as dbRef, push as dbPush, update as dbUpdate } from 'firebase/database';\nimport { rtdb } from '../firebase';\nimport { sendPushNotification } from '../utils/onesignal';\nimport { v4 as uuidv4 } from 'uuid';\nimport {\n  HiPhotograph, HiVideoCamera, HiTag, HiOutlineHeart, HiChat,\n  HiTrash, HiPencil, HiX, HiShare, HiFilm, HiOutlineChat,\n  HiDotsVertical, HiDownload, HiLightningBolt, HiPhone, HiLocationMarker,\n  HiReply, HiUserAdd, HiUserGroup, HiBookmark, HiFlag, HiBan, HiPaperAirplane, HiIdentification, HiShoppingBag, HiShoppingCart, HiCalendar, HiClipboardCopy, HiInformationCircle, HiCheck, HiGlobeAlt, HiStar, HiAtSymbol, HiTrendingUp} from 'react-icons/hi';\nimport { addToCart } from '../utils/cart';\nimport { increment } from 'firebase/firestore';\n\nconst MAX_POST    = 2000;\nconst MAX_COMMENT = 500;\nconst MAX_PRICE   = 999_999_999;\nconst REACTIONS   = ['\ud83d\udc4d','\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\ude21'];\nconst FB_REACTIONS = [\n  { emoji:'\ud83d\udc4d', label:\"J'aime\"    },\n  { emoji:'\u2764\ufe0f', label:\"J'adore\"   },\n  { emoji:'\ud83d\ude02', label:'Haha'      },\n  { emoji:'\ud83d\ude2e', label:'Wouah'     },\n  { emoji:'\ud83d\ude22', label:'Triste'    },\n  { emoji:'\ud83d\ude21', label:'En col\u00e8re' },\n];\nconst TEXT_BG_COLORS = [\n  null,\n  'linear-gradient(135deg,#1877F2,#42A5F5)',\n  'linear-gradient(135deg,#E91E8C,#FF6BB5)',\n  'linear-gradient(135deg,#FF7A00,#FFB347)',\n  'linear-gradient(135deg,#00C853,#69F0AE)',\n  'linear-gradient(135deg,#7C3AED,#A78BFA)',\n  'linear-gradient(135deg,#D32F2F,#FF8A80)',\n  'linear-gradient(135deg,#1A1A1A,#424242)',\n];\nconst SALE_CATEGORIES = ['V\u00eatements', '\u00c9lectronique', 'D\u00e9co & Maison', 'V\u00e9hicules', 'Alimentation', 'Beaut\u00e9', 'Autre'];\n\nfunction VIPBadge() {\n  return <img src='/vip-badge.png' style={{ width:32, height:32, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>;\n}\n\n// Video ao amin'ny fil d'actualit\u00e9s \u2014 milalao ho azy rehefa hita ~60% amin'ny \u00e9cran\n// (raha tsy activ\u00e9 ny \"\u00c9conomiser donn\u00e9es\"), ary mijanona rehefa scroll mivoaka.\nfunction FeedVideo({ src, poster, dataSaver, style, onOpenReels }) {\n  const vidRef = useRef(null);\n  const wrapRef = useRef(null);\n  const [playing, setPlaying] = useState(false);\n  const [muted, setMuted] = useState(true);\n\n  useEffect(() => {\n    if (dataSaver) { setPlaying(false); return; }\n    const el = wrapRef.current;\n    if (!el) return;\n    const io = new IntersectionObserver(\n      ([entry]) => {\n        if (entry.isIntersecting && entry.intersectionRatio >= 0.6) {\n          vidRef.current?.play?.().catch(() => {});\n          setPlaying(true);\n        } else {\n          vidRef.current?.pause?.();\n          setPlaying(false);\n        }\n      },\n      { threshold: [0, 0.6, 1] }\n    );\n    io.observe(el);\n    return () => io.disconnect();\n  }, [dataSaver]);\n\n  return (\n    <div ref={wrapRef} style={{ position: 'relative', cursor: 'pointer' }} onClick={() => {\n      onOpenReels?.();\n    }}>\n      <video\n        ref={vidRef}\n        src={src}\n        poster={poster || undefined}\n        preload={(dataSaver || poster) ? 'none' : 'metadata'}\n        style={style}\n        muted={muted}\n        loop\n        playsInline\n      />\n      {!playing && (\n        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n          <div style={{ width: 50, height: 50, background: 'rgba(0,0,0,0.5)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n            <span style={{ color: 'white', fontSize: 20 }}>\u25b6</span>\n          </div>\n        </div>\n      )}\n      {playing && (\n        <button\n          onClick={e => { e.stopPropagation(); setMuted(m => { const nx = !m; if (vidRef.current) { vidRef.current.muted = nx; if (!nx) vidRef.current.play?.().catch(() => {}); } return nx; }); }}\n          style={{ position: 'absolute', bottom: 10, right: 10, width: 34, height: 34, background: 'rgba(0,0,0,0.55)', border: 'none', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>\n          <span style={{ color: 'white', fontSize: 15 }}>{muted ? '\ud83d\udd07' : '\ud83d\udd0a'}</span>\n        </button>\n      )}\n    </div>\n  );\n}\n\n// \u2500\u2500 Barres d'onde d\u00e9terministes (stables par piste) \u2500\u2500\nfunction waveBars(seed, n = 56) {\n  let s = 0; for (let i = 0; i < seed.length; i++) s = (s * 31 + seed.charCodeAt(i)) % 100000;\n  const rnd = () => { s = (s * 9301 + 49297) % 233280; return s / 233280; };\n  return Array.from({ length: n }, (_, i) => 9 + Math.abs(Math.sin(i * 0.4 + s)) * 44 + rnd() * 16);\n}\n\nconst MUSIC_GRADS = [['#FF6FA5', '#FF2D8D'], ['#A66BFF', '#7A2DFF'], ['#3DBEFF', '#1877F2']];\n\nfunction MusicCard({ track, index, playing, onToggle, onArtist, onSave, onBlock, isSaved, isBlocked, onFollow, onMessage, isFollowing, onShare }) {\n  const [menuOpen, setMenuOpen] = useState(false);\n  const [infoOpen, setInfoOpen] = useState(false);\n  const [dur, setDur] = useState('');\n  const bars = useRef(waveBars(track.id || String(index)));\n  const grad = MUSIC_GRADS[index % 3];\n  useEffect(() => {\n    if (!track.mediaURL) return;\n    const a = new Audio(); a.preload = 'metadata'; a.src = track.mediaURL;\n    const on = () => { const d = a.duration; if (d && isFinite(d)) { const m = Math.floor(d/60), s = Math.floor(d%60); setDur(m + ':' + String(s).padStart(2,'0')); } };\n    a.addEventListener('loadedmetadata', on);\n    return () => { a.removeEventListener('loadedmetadata', on); a.src = ''; };\n  }, [track.mediaURL]);\n  const infoRows = [['Titre', track.songTitle],['Artiste', track.artistName],['Genre', track.genre],['Auteur / Compositeur', track.songAuthorComposer],['Label', track.songLabel],['Studio', track.songStudio],['Equipe', track.songTeam],['Direction artistique', track.songArt],['Description', track.content]].filter(([,v]) => v);\n  const Item = ({ icon, label, color, danger, onClick }) => (\n    <button onClick={onClick} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', color: danger ? '#FF2D8D' : '#050505', fontSize:15, fontWeight:600, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}>{icon} {label}</button>\n  );\n  return (\n    <div style={{ flex: '0 0 180px', background: '#0c0c12', borderRadius: 16, overflow: 'hidden', position: 'relative' }}>\n      <div style={{ position: 'relative', height: 110, display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>\n        <div onClick={() => onArtist?.(track.artistId)} style={{ position: 'absolute', top: 8, left: 8, width: 34, height: 34, borderRadius: '50%', overflow: 'hidden', border: '2px solid rgba(255,255,255,.85)', zIndex: 3, cursor: 'pointer', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n          {track.artistPhoto ? <img src={track.artistPhoto} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <span style={{ color: '#fff', fontWeight: 800, fontSize: 14 }}>{(track.artistName || '?')[0]}</span>}\n        </div>\n        <button onClick={() => setMenuOpen(true)} style={{ position: 'absolute', top: 8, right: 8, zIndex: 4, background: 'rgba(0,0,0,.35)', border: 'none', borderRadius: '50%', width: 26, height: 26, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', cursor: 'pointer' }}><HiDotsVertical size={16} /></button>\n        {track.thumbURL && <div style={{ position: 'absolute', inset: 0, backgroundImage: 'url(' + track.thumbURL + ')', backgroundSize: 'cover', backgroundPosition: 'center', filter: 'brightness(.45)', zIndex: 0 }} />}\n        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 2, padding: '0 10px', zIndex: 1 }}>\n          {bars.current.map((h, i) => (<div key={i} style={{ width: 3, height: h, borderRadius: 3, background: i / bars.current.length < 0.5 ? grad[0] : grad[1], opacity: playing ? 0.95 : 0.7 }} />))}\n        </div>\n        <div onClick={() => onToggle?.(track)} style={{ position: 'relative', zIndex: 2, width: 42, height: 42, borderRadius: '50%', background: 'rgba(0,0,0,.5)', border: '2px solid rgba(255,255,255,.92)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', boxShadow: '0 4px 14px rgba(0,0,0,.4)' }}>\n          {playing ? <svg width=\"16\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"#fff\"><rect x=\"6\" y=\"4\" width=\"4\" height=\"16\" rx=\"1.5\" /><rect x=\"14\" y=\"4\" width=\"4\" height=\"16\" rx=\"1.5\" /></svg> : <svg width=\"16\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"#fff\" style={{ marginLeft: 3 }}><path d=\"M6 4l14 8-14 8z\" /></svg>}\n        </div>\n      </div>\n      <div style={{ padding: '8px 10px 10px', background: '#0c0c12' }}>\n        <div style={{ display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between' }}>\n          <div style={{ minWidth: 0 }}>\n            <div style={{ fontWeight: 800, fontSize: 13, color: '#fff', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{track.songTitle || track.content || 'Sans titre'}</div>\n            <div style={{ fontSize: 11, color: '#b9b9c2', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{track.artistName}</div>\n          </div>\n          {dur && <div style={{ fontSize: 11, color: '#e6e6ea', fontWeight: 600, flexShrink: 0, marginLeft: 6 }}>{dur}</div>}\n        </div>\n        <div style={{ display: 'flex', gap: 6, marginTop: 8 }}>\n          <button onClick={() => onFollow?.(track.artistId)} style={{ flex: 1, background: isFollowing ? 'rgba(255,255,255,.14)' : 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', color: '#fff', border: 'none', borderRadius: 14, padding: '5px 0', fontSize: 11.5, fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3 }}>\n            {isFollowing ? <><HiCheck size={12} /> Abonn\u00e9</> : 'Suivre'}\n          </button>\n          <button onClick={() => onMessage?.(track.artistId)} style={{ flex: 1, background: 'rgba(255,255,255,.14)', color: '#fff', border: 'none', borderRadius: 14, padding: '5px 0', fontSize: 11.5, fontWeight: 600, cursor: 'pointer' }}>Message</button>\n        </div>\n      </div>\n      {menuOpen && (\n        <div onClick={() => setMenuOpen(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.5)', zIndex: 300, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: '18px 18px 0 0', width: '100%', maxWidth: 480, overflow: 'hidden', fontFamily: 'Poppins' }}>\n            <Item icon={<HiInformationCircle size={20} color=\"#1877F2\" />} label=\"Informations\" onClick={() => { setMenuOpen(false); setInfoOpen(true); }} />\n            <Item icon={<HiDownload size={20} color=\"#12A48D\" />} label=\"T\u00e9l\u00e9charger\" onClick={() => { setMenuOpen(false); downloadMedia(track.mediaURL, 'audio', track.songTitle || 'audio'); }} />\n            <Item icon={<HiShare size={20} color=\"#7A2DFF\" />} label=\"Partager\" onClick={() => { setMenuOpen(false); onShare?.(track); }} />\n            <Item icon={<HiBookmark size={20} color=\"#F2B300\" />} label={isSaved ? 'Retirer des enregistrements' : 'Enregistrer'} onClick={() => { setMenuOpen(false); onSave?.(track.id); }} />\n            <Item icon={<HiBan size={20} color=\"#FF2D8D\" />} label={isBlocked ? 'D\u00e9bloquer' : 'Bloquer'} danger onClick={() => { setMenuOpen(false); onBlock?.(track); }} />\n          </div>\n        </div>\n      )}\n      {infoOpen && (\n        <div onClick={() => setInfoOpen(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.55)', zIndex: 300, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: '18px 18px 0 0', width: '100%', maxWidth: 480, maxHeight: '80vh', overflowY: 'auto', padding: '18px 20px 26px', fontFamily: 'Poppins' }}>\n            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 14 }}>\n              <div style={{ width: 46, height: 46, borderRadius: '50%', overflow: 'hidden', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>\n                {track.artistPhoto ? <img src={track.artistPhoto} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <span style={{ color: '#fff', fontWeight: 800 }}>{(track.artistName || '?')[0]}</span>}\n              </div>\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <div style={{ fontWeight: 800, fontSize: 17 }}>{track.songTitle || 'Sans titre'}</div>\n                <div style={{ fontSize: 13, color: '#65676B' }}>{track.artistName}</div>\n              </div>\n              <button onClick={() => setInfoOpen(false)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', color: '#65676B', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><HiX size={18} /></button>\n            </div>\n            {infoRows.map(([k, v]) => (\n              <div key={k} style={{ display: 'flex', gap: 10, padding: '9px 0', borderTop: '1px solid #F0F2F5' }}>\n                <span style={{ fontSize: 12.5, color: '#65676B', fontWeight: 700, width: 130, flexShrink: 0 }}>{k}</span>\n                <span style={{ fontSize: 13.5, color: '#050505' }}>{v}</span>\n              </div>\n            ))}\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n\nfunction MusicRow({ tracks, playingId, onToggle, onArtist, onSave, onBlock, savedIds = [], blockedIds = [], onFollow, onMessage, followedArtists = [], onShare, onVoirTout }) {\n  if (!tracks || tracks.length === 0) return null;\n  return (\n    <div className=\"card\" style={{ marginBottom: 14, padding: '12px 0 6px' }}>\n      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 14px 10px' }}>\n        <span style={{ fontWeight: 800, fontSize: 17, color: '#050505' }}>Suggestions musicales pour vous</span>\n        <button onClick={onVoirTout} style={{ background:'none', border:'none', color:'#1877F2', fontWeight:700, fontSize:13, cursor:'pointer', padding:'2px 6px', fontFamily:'Poppins' }}>Voir tout</button>\n      </div>\n      <div style={{ display: 'flex', gap: 12, overflowX: 'auto', padding: '2px 14px 8px', WebkitOverflowScrolling: 'touch' }}>\n        {tracks.map((t, i) => (\n          <MusicCard key={t.id} track={t} index={i} playing={playingId === t.id} onToggle={onToggle} onArtist={onArtist} onSave={onSave} onBlock={onBlock} isSaved={savedIds.includes(t.id)} isBlocked={blockedIds.includes(t.uid)} onFollow={onFollow} onMessage={onMessage} isFollowing={followedArtists.includes(t.artistId)} onShare={onShare} />\n        ))}\n      </div>\n    </div>\n  );\n}\n\nexport default function Home() {\n  const { currentUser, userProfile, setUserProfile } = useAuth();\n  const activeStoryUids = useActiveStoryUids();\n  const { t } = useLang();\n  const navigate = useNavigate();\n\n  const [content, setContent]   = useState('');\n  const [mediaFile, setMF]      = useState(null);\n  const [mediaPreview, setMP]   = useState(null);\n  const [mediaType, setMT]      = useState('');\n  const [isSale, setIsSale]     = useState(false);\n  const [price, setPrice]       = useState('');\n  const [contact, setContact]   = useState('');\n  const [lieu, setLieu]         = useState('');\n  const [saleCategory, setSaleCategory] = useState(SALE_CATEGORIES[0]);\n  const [posting, setPosting]   = useState(false);\n  const [uploadPct, setUploadPct] = useState(0);\n  const [pageGroups, setPageGroups] = useState([]);   // groupes publics (suggestions)\n  const [shopSuggestions, setShopSuggestions] = useState([]); // boutiques suggestions\n\n  // \u2500\u2500 Stories (format Facebook) \u2500\u2500\n  const [storyGroups, setStoryGroups] = useState([]);       // [{uid, name, photo, items:[...]}]\n  const [storyViewer, setStoryViewer] = useState(null);     // {group, index}\n  const [addingStory, setAddingStory] = useState(false);\n  const [createStoryMenuOpen, setCreateStoryMenuOpen] = useState(false);\n  const [storyStudio, setStoryStudio] = useState(null);\n  const [storyPaused, setStoryPaused] = useState(false);\n  const storyPressTimer = useRef(null);\n  const storyPressedRef = useRef(false);\n  const storyVideoRef = useRef(null);\n  const [dataSaver, setDataSaverState] = useState(isDataSaverOn());\n  useEffect(() => subscribeDataSaver(setDataSaverState), []);\n  const [shareModalPost, setShareModalPost] = useState(null);\n  const [audience, setAudience] = useState('public');   // 'public' | 'friends' | 'me'\n  const [audienceMenuOpen, setAudienceMenuOpen] = useState(false);\n  const [composerMoreOpen, setComposerMoreOpen] = useState(false);\n  const [publishFullOpen, setPublishFullOpen] = useState(false);\n  const [isDecree, setIsDecree] = useState(false);\n  const [postLocation, setPostLocation] = useState('');\n  const [postMood, setPostMood] = useState('');\n  const [allowMessages, setAllowMessages] = useState(true);\n  const [locationPromptOpen, setLocationPromptOpen] = useState(false);\n  const [moodPickerOpen, setMoodPickerOpen] = useState(false);\n  const [composerTagOpen, setComposerTagOpen] = useState(false);\n  const [composerTagSel, setComposerTagSel] = useState({});\n  const [composerTagList, setComposerTagList] = useState([]);\n  const MOODS = ['\ud83d\ude0a se sent heureux(se)', '\ud83d\ude22 se sent triste', '\ud83e\udd73 fait la f\u00eate', '\ud83d\ude34 fatigu\u00e9(e)', '\ud83d\ude4f reconnaissant(e)', '\ud83d\udcaa motiv\u00e9(e)', '\ud83d\ude0d amoureux(se)', '\ud83e\udd12 malade'];\n  const [storyReactors, setStoryReactors] = useState(null);   // null | [{uid,name,photo,emoji}]\n  const storyFileRef = useRef();\n  const [textBg, setTextBg] = useState(null);\n\n  // \u2500\u2500 Suggestions d'amis \u2500\u2500\n  const [suggestions, setSuggestions] = useState([]);\n\n  const lpTimer = useRef(null);\n  const lpFired = useRef(false);\n\n  const [posts, setPosts]           = useState([]);\n  const [postsLoading, setPostsLoading] = useState(true);\n  const feedAds = useFeedAds();\n  const [visibleCount, setVisibleCount] = useState(10);   // affichage progressif\n  const [expandedPosts, setExpandedPosts] = useState({});\n  const [viewerState,   setViewerState]   = useState(null); // { post, index }\n  const [boostTarget,   setBoostTarget]    = useState(null); // { type, id, ownerUid, title, thumbnailURL }\n  const [reportTarget,  setReportTarget]   = useState(null); // post \u00e0 signaler\n  const [reactorNames, setReactorNames] = useState({});   // uid \u2192 prenom (ho an'ny \"X et N autres\")\n  const [mentionQuery, setMentionQuery] = useState(null); // { postId, q } rehefa manoratra @\n  const [mentionFriends, setMentionFriends] = useState([]);\n\n  // \u2500\u2500 Menus mikatona rehefa scroll na clic ivelany \u2500\u2500\n  useEffect(() => {\n    const close = () => { setPostMenu(null); setAudienceMenuOpen(false); setShowReact({}); setCmtReactionPicker(null); setMentionQuery(null); };\n    window.addEventListener('scroll', close, true);\n    return () => window.removeEventListener('scroll', close, true);\n  }, []);\n\n  // \u2500\u2500 Anaran'ny mpandray anjara r\u00e9action voalohany (format Facebook : \"X et N autres\") \u2500\u2500\n  useEffect(() => {\n    const need = [];\n    posts.forEach(pp => {\n      const uids = Object.keys(pp.reactions || {});\n      if (uids.length > 0) {\n        const first = uids.find(u => u !== currentUser?.uid) || uids[0];\n        if (first && reactorNames[first] === undefined) need.push(first);\n      }\n    });\n    const batch = [...new Set(need)].slice(0, 20);\n    if (!batch.length) return;\n    setReactorNames(prev => { const nx = { ...prev }; batch.forEach(u => { nx[u] = null; }); return nx; });\n    batch.forEach(u => {\n      getDoc(doc(db, 'users', u)).then(sn => {\n        const nm = sn.exists() ? (sn.data().fullName || '').split(' ')[0] : '';\n        setReactorNames(prev => ({ ...prev, [u]: nm }));\n      }).catch(() => {});\n    });\n  }, [posts]); // eslint-disable-line\n\n  // \u2500\u2500 Compteur vues (indray mandeha isaky ny session, publication rehetra) \u2500\u2500\n  useEffect(() => {\n    if (!posts.length || !currentUser) return;\n    let vs; try { vs = JSON.parse(sessionStorage.getItem('viewedPosts') || '[]'); } catch { vs = []; }\n    const seen = new Set(vs);\n    const fresh = posts.filter(pp => !seen.has(pp.id)).slice(0, 60);\n    if (!fresh.length) return;\n    fresh.forEach(pp => seen.add(pp.id));\n    try { sessionStorage.setItem('viewedPosts', JSON.stringify([...seen])); } catch {}\n    const b = writeBatch(db);\n    fresh.forEach(pp => b.update(doc(db, 'posts', pp.id), { views: increment(1) }));\n    b.commit().catch(() => {});\n  }, [posts.length]); // eslint-disable-line\n\n  // \u2500\u2500 Namana ho an'ny mention @ \u2500\u2500\n  async function loadMentionFriends() {\n    if (mentionFriends.length || !userProfile?.friends?.length) return;\n    const list = await Promise.all(userProfile.friends.slice(0, 60).map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, fullName: sn.data().fullName || '' } : null).catch(() => null)\n    ));\n    setMentionFriends(list.filter(Boolean));\n  }\n  const [audienceEditPost, setAudienceEditPost] = useState(null);\n  // \u2500\u2500 Lecture audio du fil (une seule piste \u00e0 la fois) \u2500\u2500\n  const [followedArtists, setFollowedArtists] = useState([]);\n  useEffect(() => {\n    if (!currentUser) return;\n    const unsub = onSnapshot(collection(db, 'artists'), snap => {\n      setFollowedArtists(snap.docs.filter(d => (d.data().followers || []).includes(currentUser.uid)).map(d => d.id));\n    }, () => {});\n    return () => unsub();\n  }, [currentUser]);\n  async function toggleFollowArtist(artistId) {\n    if (!artistId || !currentUser) return;\n    const on = followedArtists.includes(artistId);\n    try { await updateDoc(doc(db, 'artists', artistId), { followers: on ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) }); } catch {}\n  }\n  const musicAudioRef = useRef(null);\n  const [playingTrackId, setPlayingTrackId] = useState(null);\n  function toggleMusic(track) {\n    if (!track?.mediaURL) return;\n    if (!musicAudioRef.current) musicAudioRef.current = new Audio();\n    const a = musicAudioRef.current;\n    if (playingTrackId === track.id) { a.pause(); setPlayingTrackId(null); return; }\n    a.src = track.mediaURL;\n    a.onended = () => setPlayingTrackId(null);\n    a.play().catch(() => {});\n    setPlayingTrackId(track.id);\n  }\n  const [reelPosts, setReelPosts]   = useState([]);\n  const [openCmt, setOpenCmt]       = useState({});\n  const [cmtText, setCmtText]       = useState({});\n  const [cmtMedia, setCmtMedia]     = useState({});\n  const [showReact, setShowReact]   = useState({});\n  const [reactionModal, setRM] = useState(null);\n  const [cmtReactionPicker, setCmtReactionPicker] = useState(null);\n  const [cmtReactions, setCmtReactions] = useState({});\n  const [editPost, setEditPost]     = useState(null);\n  const [editContent, setEditContent] = useState('');\n  const [textCopyMenu, setTextCopyMenu] = useState(null);   // {id, content}\n  const [copyToast, setCopyToast]   = useState(false);\n  const textPressTimer = useRef(null);\n  const textPressedRef = useRef(false);\n  const [postMenu, setPostMenu]     = useState(null);\n  const [editCmt, setEditCmt]       = useState(null);\n  const [replyTo, setReplyTo]       = useState({});\n\n  const photoRef = useRef(); const videoRef = useRef();\n  const cPhotoRef = useRef({}); const cVideoRef = useRef({});\n\n  // Close menus on outside click\n  useEffect(() => {\n    const fn = () => setPostMenu(null);\n    document.addEventListener('click', fn);\n    return () => document.removeEventListener('click', fn);\n  }, []);\n\n  // Groupes publics (pour les suggestions du fil)\n  useEffect(() => {\n    const q = query(collection(db, 'groups'), where('type', '==', 'page'));\n    return onSnapshot(q, snap => setPageGroups(snap.docs.map(d => ({ id: d.id, ...d.data() }))), () => {});\n  }, []);\n\n  // Stories des derni\u00e8res 24h, group\u00e9es par utilisateur\n  useEffect(() => {\n    const q = query(collection(db, 'stories'), orderBy('ts', 'desc'), limit(150));\n    return onSnapshot(q, snap => {\n      const cutoff = Date.now() - 24 * 60 * 60 * 1000;\n      const myFriends = userProfile?.friends || [];\n      const fresh = snap.docs.map(d => ({ id: d.id, ...d.data() })).filter(st => {\n        if ((st.ts || 0) <= cutoff) return false;\n        if (st.uid === currentUser?.uid) return true;\n        if (st.audience === 'me') return false;\n        if (st.audience === 'friends') return myFriends.includes(st.uid);\n        return true;\n      });\n      const byUser = {};\n      fresh.forEach(st => {\n        if (!byUser[st.uid]) byUser[st.uid] = { uid: st.uid, name: st.authorName, photo: st.authorPhoto || '', items: [] };\n        byUser[st.uid].items.push(st);\n      });\n      Object.values(byUser).forEach(g => g.items.sort((a, b) => (a.ts || 0) - (b.ts || 0)));\n      // Ma story en premier\n      const list = Object.values(byUser).sort((a, b) => (a.uid === currentUser?.uid ? -1 : b.uid === currentUser?.uid ? 1 : 0));\n      setStoryGroups(list);\n    }, () => {});\n  }, [currentUser, userProfile?.friends?.length]);\n\n  // Boutiques suggestions\n  useEffect(() => {\n    if (!currentUser) return;\n    getDocs(query(collection(db, 'shops'), orderBy('createdAt', 'desc')))\n      .then(snap => setShopSuggestions(snap.docs.map(d => ({ id: d.id, ...d.data() })).slice(0, 16)))\n      .catch(() => {});\n  }, [currentUser]);\n\n  // Suggestions d'amis (personnes non amies)\n  useEffect(() => {\n    if (!currentUser || !userProfile) return;\n    let alive = true;\n    getDocs(collection(db, 'users')).then(snap => {\n      if (!alive) return;\n      const friends = userProfile.friends || [];\n      const sent = userProfile.sentRequests || [];\n      const list = snap.docs\n        .map(d => ({ uid: d.id, ...d.data() }))\n        .filter(u => u.uid !== currentUser.uid && u.fullName && !friends.includes(u.uid) && !sent.includes(u.uid));\n      // M\u00e9lange l\u00e9ger\n      for (let i = list.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [list[i], list[j]] = [list[j], list[i]]; }\n      setSuggestions(list.slice(0, 20));\n    }).catch(() => {});\n    return () => { alive = false; };\n  }, [currentUser, userProfile?.friends?.length]);\n\n  // Load posts\n  useEffect(() => {\n    const q = query(collection(db, 'posts'), orderBy('createdAt', 'desc'), limit(60));\n    return onSnapshot(q, snap => {\n      const blocked = userProfile?.blocked || [];\n      const myFriends = userProfile?.friends || [];\n      const all = snap.docs.map(d => ({ id: d.id, ...d.data() }))\n        .filter(p => !blocked.includes(p.uid))\n        // \ud83d\udd12 Audience \"Amis\" : hita amin'ny tompony sy ny namany ihany\n        .filter(p => p.uid === currentUser?.uid || (p.audience === 'friends' ? myFriends.includes(p.uid) : p.audience !== 'me'));\n      const now = new Date();\n      const sorted = [...all].sort((a, b) => {\n        const aB = a.isBoosted && a.boostUntil && new Date(a.boostUntil) > now;\n        const bB = b.isBoosted && b.boostUntil && new Date(b.boostUntil) > now;\n        return (aB && !bB) ? -1 : (!aB && bB) ? 1 : 0;\n      });\n      setPosts(sorted);\n      setReelPosts(all.filter(p => p.mediaType === 'video' && p.mediaURL));\n      setPostsLoading(false);\n    });\n  }, []);\n\n  const [multiPhotos, setMultiPhotos] = useState([]);   // File[] \u2014 mode \"plusieurs photos\" (2 \u00e0 10)\n  function handleMedia(e, type) {\n    const files = Array.from(e.target.files || []);\n    if (!files.length) return;\n    setTextBg(null);\n    const allowed = type === 'image'\n      ? ['image/jpeg','image/png','image/gif','image/webp']\n      : ['video/mp4','video/webm','video/quicktime'];\n\n    if (type === 'image' && files.length > 1) {\n      const valid = files.filter(f => allowed.includes(f.type)).slice(0, 10);\n      setMultiPhotos(valid);\n      setMF(null); setMP(null); setMT('');\n      e.target.value = '';\n      return;\n    }\n\n    const file = files[0];\n    if (!allowed.includes(file.type)) { alert('Type non accept\u00e9'); return; }\n    setMultiPhotos([]);\n    // no size limit\n    setMF(file); setMT(type); setMP(URL.createObjectURL(file));\n  }\n  function removeMedia() { setMF(null); setMP(null); setMT(''); setMultiPhotos([]); }\n  function removeOnePhoto(idx) { setMultiPhotos(p => p.filter((_, i) => i !== idx)); }\n\n  async function createPost() {\n    if (!content.trim() && !mediaFile && multiPhotos.length === 0) return;\n    if (content.length > MAX_POST) return;\n    if (isSale) {\n      const p = parseFloat(price);\n      if (isNaN(p) || p <= 0 || p > MAX_PRICE) { alert('Prix invalide'); return; }\n    }\n    setPosting(true); setUploadPct(0);\n\n    // Sary raikitra ny votoaty (snapshot) \u2014 ilaina amin'ny arri\u00e8re-plan\n    const asPage = false;\nconst fields = {\n      uid: currentUser.uid,\n      authorName: asPage ? _idn.name : userProfile.fullName,\n      authorUsername: asPage ? '' : userProfile.username,\n      authorPhoto: asPage ? (_idn.photoURL || '') : (userProfile.photoURL || ''),      authorIsVip: asPage ? false : (userProfile.isVip || false),\n      content: content.trim().slice(0, MAX_POST),\n      textBg: textBg || null,\n      isSale, price: isSale ? parseFloat(price) : '',\n      contact: isSale ? contact.trim() : '', lieu: isSale ? lieu.trim() : '', saleCategory: isSale ? saleCategory : '',\n      audience,\n      location: postLocation.trim(), mood: postMood, allowMessages,\n      isDecree,\n      taggedUids: Object.keys(composerTagSel).filter(k => composerTagSel[k]),\n      taggedNames: composerTagList.filter(f => composerTagSel[f.uid]).map(f => f.fullName),\n    };\n    // Miniature an'ny vid\u00e9o (poster) \u2014 alaina eto an-toerana, haingana\n    let thumbFile = null;\n    if (mediaFile && mediaFile.type.startsWith('video/')) {\n      try { thumbFile = await captureVideoThumb(mediaFile); } catch {}\n    }\n    const friendTargets = userProfile.friends || [];\n    const authorName = userProfile.fullName;\n    const authorPhoto = userProfile.photoURL || '';\n    const myUid = currentUser.uid;\n\n    async function publishPost(mediaURL, finalMT) {\n      let thumbURL = '';\n      if (thumbFile && finalMT === 'video') {\n        try { const tr = await uploadToTelegram(thumbFile); thumbURL = tr.url || ''; } catch {}\n      }\n      const postRef = await addDoc(collection(db, 'posts'), {\n        ...fields, mediaURL, mediaType: finalMT, thumbURL,\n        reactions: {}, comments: [], createdAt: serverTimestamp(),\n      });\n      if (friendTargets.length > 0) {\n        const batch = writeBatch(db);\n        friendTargets.forEach(fUid => batch.set(doc(collection(db,'notifications')), {\n          toUid: fUid, fromUid: myUid,\n          fromName: authorName, fromPhoto: authorPhoto,\n          type: 'post', postId: postRef.id,\n          message: `${authorName} a publi\u00e9 un nouveau post`,\n          read: false, createdAt: serverTimestamp(),\n        }));\n        await batch.commit();\n      }\n    }\n\n    // \u2500\u2500 Plusieurs photos (2 \u00e0 10) : upload s\u00e9quentiel, mediaURLs[] \u2500\u2500\n    if (multiPhotos.length > 0) {\n      try {\n        const urls = [];\n        for (let i = 0; i < multiPhotos.length; i++) {\n          const r = await uploadToTelegram(multiPhotos[i], pct => setUploadPct(Math.round(((i + pct / 100) / multiPhotos.length) * 100)));\n          urls.push(r.url);\n        }\n        const postRef = await addDoc(collection(db, 'posts'), {\n          ...fields, mediaURL: urls[0], mediaType: 'image', mediaURLs: urls, thumbURL: '',\n          reactions: {}, comments: [], createdAt: serverTimestamp(),\n        });\n        if (friendTargets.length > 0) {\n          const batch = writeBatch(db);\n          friendTargets.forEach(fUid => batch.set(doc(collection(db,'notifications')), {\n            toUid: fUid, fromUid: myUid, fromName: authorName, fromPhoto: authorPhoto,\n            type: 'post', postId: postRef.id, message: `${authorName} a publi\u00e9 un nouveau post`,\n            read: false, createdAt: serverTimestamp(),\n          }));\n          await batch.commit();\n        }\n        setContent(''); removeMedia(); setIsSale(false); setPrice(''); setContact(''); setLieu(''); setAudience('public'); setPostLocation(''); setPostMood(''); setAllowMessages(true); setComposerTagSel({}); setPublishFullOpen(false); setIsDecree(false);\n      } catch (err) { console.error(err); alert('Erreur lors de la publication'); }\n      setPosting(false); setUploadPct(0);\n      return;\n    }\n\n    // \u2500\u2500 Vid\u00e9o > 12 Mo : upload ARRI\u00c8RE-PLAN (afaka mifindra page) \u2500\u2500\n    if (mediaFile && mediaFile.type.startsWith('video/') && mediaFile.size > 12 * 1024 * 1024) {\n      const started = startBackgroundUpload(mediaFile, 'Vid\u00e9o', async r => {\n        await publishPost(r.url, 'video');\n      });\n      setPosting(false); setUploadPct(0);\n      if (started) {\n        setContent(''); removeMedia(); setIsSale(false); setPrice(''); setContact(''); setLieu(''); setAudience('public'); setPostLocation(''); setPostMood(''); setAllowMessages(true); setComposerTagSel({}); setPublishFullOpen(false); setIsDecree(false);\n      }\n      return;\n    }\n\n    try {\n      let mediaURL = '', finalMT = mediaType;\n      if (mediaFile) {\n        const r = await uploadToTelegram(mediaFile, pct => setUploadPct(pct));\n        mediaURL = r.url; finalMT = r.type === 'video' ? 'video' : 'image';\n      }\n      await publishPost(mediaURL, finalMT);\n      setContent(''); removeMedia(); setIsSale(false); setPrice(''); setContact(''); setLieu(''); setAudience('public'); setPostLocation(''); setPostMood(''); setAllowMessages(true); setComposerTagSel({}); setPublishFullOpen(false); setIsDecree(false);\n    } catch (err) { console.error(err); alert('Erreur lors de la publication'); }\n    setPosting(false); setUploadPct(0);\n  }\n\n  async function reactToCmt(postId, cmtId, emoji) {\n    if (!REACTIONS.includes(emoji)) return;\n    const post = posts.find(p => p.id === postId); if (!post) return;\n    const updated = post.comments.map(c => {\n      if (c.id !== cmtId) return c;\n      const reactions = c.reactions || {};\n      const my = reactions[currentUser.uid];\n      if (my === emoji) { const u = {...reactions}; delete u[currentUser.uid]; return {...c, reactions: u}; }\n      return {...c, reactions: {...reactions, [currentUser.uid]: emoji}};\n    });\n    await updateDoc(doc(db,\"posts\",postId), { comments: updated });\n    setCmtReactionPicker(null);\n  }\n\n  async function reactToPost(postId, emoji) {\n    if (!REACTIONS.includes(emoji)) return;\n    const post = posts.find(p => p.id === postId); if (!post) return;\n    const reactions = post.reactions || {};\n    const my = reactions[currentUser.uid];\n    if (my === emoji) {\n      const u = { ...reactions }; delete u[currentUser.uid];\n      await updateDoc(doc(db,'posts',postId), { reactions: u });\n    } else {\n      await updateDoc(doc(db,'posts',postId), { [`reactions.${currentUser.uid}`]: emoji });\n      if (post.uid !== currentUser.uid) {\n        await addDoc(collection(db,'notifications'), {\n          toUid: post.uid, fromUid: currentUser.uid,\n          fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n          type: 'reaction', postId, emoji,\n          message: `${userProfile.fullName} a r\u00e9agi ${emoji} \u00e0 votre publication`,\n          read: false, createdAt: serverTimestamp(),\n        });\n        sendPushNotification({ toExternalId: post.uid, title: userProfile.fullName, message: `a r\u00e9agi ${emoji}`, data: { type:'reaction', postId } });\n      }\n    }\n    setShowReact(p => ({ ...p, [postId]: false }));\n  }\n\n  async function openReactionModal(post) {\n    const reactions = post.reactions || {};\n    if (!Object.keys(reactions).length) return;\n    const userData = {};\n    await Promise.all(Object.keys(reactions).map(async uid => {\n      try {\n        const s = await getDoc(doc(db,'users',uid));\n        userData[uid] = s.exists() ? { name: s.data().fullName, photo: s.data().photoURL } : { name: uid, photo: '' };\n      } catch { userData[uid] = { name: uid, photo: '' }; }\n    }));\n    setRM({ reactions, userData });\n  }\n\n  async function addComment(postId) {\n    const rt = replyTo[postId];\n    const raw = rt ? `@${rt} ${cmtText[postId]||''}` : (cmtText[postId]||'');\n    const text = raw.trim(); const media = cmtMedia[postId];\n    if (!text && !media) return;\n    if (text.length > MAX_COMMENT) return;\n    let mediaURL = '', cMT = '';\n    if (media) { try { const r = await uploadToTelegram(media.file); mediaURL = r.url; cMT = r.type; } catch {} }\n    const post = posts.find(p => p.id === postId);\n    const cmt = {\n      id: uuidv4(), uid: currentUser.uid,\n      authorName: userProfile.fullName, authorPhoto: userProfile.photoURL || '',\n      authorIsVip: userProfile.isVip || false,\n      text: text.slice(0, MAX_COMMENT), mediaURL, mediaType: cMT,\n      createdAt: new Date().toISOString(),\n    };\n    await updateDoc(doc(db,'posts',postId), { comments: arrayUnion(cmt) });\n    setCmtText(p => ({ ...p, [postId]: '' }));\n    setCmtMedia(p => ({ ...p, [postId]: null }));\n    setReplyTo(p => ({ ...p, [postId]: null }));\n    if (post && post.uid !== currentUser.uid) {\n      await addDoc(collection(db,'notifications'), {\n        toUid: post.uid, fromUid: currentUser.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        type: 'comment', postId,\n        message: `${userProfile.fullName} a comment\u00e9 votre publication`,\n        read: false, createdAt: serverTimestamp(),\n      });\n      sendPushNotification({ toExternalId: post.uid, title: userProfile.fullName, message: text?`a comment\u00e9 : \"${text.slice(0,50)}\"`:' a comment\u00e9', data: { type:'comment', postId } });\n    }\n    // \u2500\u2500 Mentions @ : mampandre ny namana voatonona \u2500\u2500\n    if (text.includes('@') && mentionFriends.length) {\n      const low = text.toLowerCase();\n      const mentioned = mentionFriends.filter(f => {\n        const first = (f.fullName.split(' ')[0] || '').toLowerCase();\n        return first && low.includes('@' + first);\n      }).filter(f => f.uid !== currentUser.uid && f.uid !== post?.uid);\n      mentioned.slice(0, 10).forEach(f => {\n        addDoc(collection(db,'notifications'), {\n          toUid: f.uid, fromUid: currentUser.uid,\n          fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n          type: 'mention', postId,\n          message: `${userProfile.fullName} vous a mentionn\u00e9 dans un commentaire`,\n          read: false, createdAt: serverTimestamp(),\n        }).catch(() => {});\n        sendPushNotification({ toExternalId: f.uid, title: userProfile.fullName, message: 'vous a mentionn\u00e9 dans un commentaire \ud83d\udcac', data: { type:'mention', postId } });\n      });\n    }\n  }\n\n  async function deleteCmt(postId, cmt) {\n    const post = posts.find(p => p.id === postId);\n    if (cmt.uid !== currentUser.uid && post?.uid !== currentUser.uid) return;\n    if (!window.confirm('Supprimer ce commentaire ?')) return;\n    await updateDoc(doc(db,'posts',postId), { comments: arrayRemove(cmt) });\n  }\n\n  async function saveEditCmt(postId, oldCmt, newText) {\n    if (!newText.trim()) return;\n    const post = posts.find(p => p.id === postId); if (!post) return;\n    const updated = post.comments.map(c => c.id === oldCmt.id ? { ...c, text: newText.trim() } : c);\n    await updateDoc(doc(db,'posts',postId), { comments: updated });\n    setEditCmt(null);\n  }\n\n  async function deletePost(postId) {\n    const post = posts.find(p => p.id === postId);\n    if (!post || post.uid !== currentUser.uid) return;\n    if (!window.confirm('Supprimer cette publication ?')) return;\n    await deleteDoc(doc(db,'posts',postId));\n  }\n\n  function isFollowingUid(uid) { return (userProfile?.following || []).includes(uid); }\n  async function toggleFollowAuthor(uid, name) {\n    const already = isFollowingUid(uid);\n    try {\n      await updateDoc(doc(db, 'users', uid), { followers: already ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) });\n      await updateDoc(doc(db, 'users', currentUser.uid), { following: already ? arrayRemove(uid) : arrayUnion(uid) });\n      setUserProfile(p => ({ ...p, following: already ? (p.following||[]).filter(u=>u!==uid) : [...(p.following||[]), uid] }));\n      if (!already) {\n        await addDoc(collection(db, 'notifications'), {\n          toUid: uid, fromUid: currentUser.uid, fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n          type: 'general', message: `${userProfile.fullName} s'est abonn\u00e9(e) \u00e0 votre profil`, read: false, createdAt: serverTimestamp(),\n        });\n      }\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function reportPost(post) {\n    setReportTarget(post);\n  }\n  async function submitReport(motif, detail) {\n    const post = reportTarget;\n    try {\n      await addDoc(collection(db, 'reports'), {\n        type: 'post', targetId: post.id, targetUid: post.uid, targetAuthor: post.authorName,\n        reportedBy: currentUser.uid, reportedByName: userProfile.fullName,\n        motif, detail: detail || '',\n        createdAt: serverTimestamp(), status: 'pending',\n      });\n      setReportTarget(null);\n      alert('Signalement envoy\u00e9. Merci.');\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function toggleBlockAuthor(post) {\n    const already = (userProfile?.blocked || []).includes(post.uid);\n    const msg = already ? `D\u00e9bloquer ${post.authorName} ?` : `Bloquer ${post.authorName} ? Vous ne verrez plus ses publications.`;\n    if (!window.confirm(msg)) return;\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), {\n        blocked: already ? arrayRemove(post.uid) : arrayUnion(post.uid),\n      });\n      setUserProfile(p => ({ ...p, blocked: already ? (p.blocked||[]).filter(u=>u!==post.uid) : [...(p.blocked||[]), post.uid] }));\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function showAudienceInfo(post) {\n    alert(post.audience === 'friends' ? \"Cette publication est visible par ses amis uniquement.\" : \"Cette publication est publique.\");\n  }\n\n  const [tagModalPost, setTagModalPost] = useState(null);\n  const [tagSelected, setTagSelected] = useState({});\n  const [tagFriendsList, setTagFriendsList] = useState([]);\n  async function openComposerTagModal() {\n    setComposerTagOpen(true);\n    const myFriends = userProfile?.friends || [];\n    const list = await Promise.all(myFriends.map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, ...sn.data() } : null).catch(() => null)\n    ));\n    setComposerTagList(list.filter(Boolean));\n  }\n\n  async function openTagModal(post) {\n    setTagModalPost(post);\n    const init = {}; (post.taggedUids || []).forEach(u => { init[u] = true; });\n    setTagSelected(init);\n    const myFriends = userProfile?.friends || [];\n    const list = await Promise.all(myFriends.map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, ...sn.data() } : null).catch(() => null)\n    ));\n    setTagFriendsList(list.filter(Boolean));\n  }\n  async function saveTags() {\n    if (!tagModalPost) return;\n    const uids = Object.keys(tagSelected).filter(k => tagSelected[k]);\n    const names = tagFriendsList.filter(f => uids.includes(f.uid)).map(f => f.fullName);\n    try { await updateDoc(doc(db, 'posts', tagModalPost.id), { taggedUids: uids, taggedNames: names }); setTagModalPost(null); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  const [editAudience, setEditAudience] = useState('public');\n  useEffect(() => { if (editPost) setEditAudience(editPost.audience || 'public'); }, [editPost]);\n  async function saveEditPost() {\n    if (!editContent.trim() || !editPost || editPost.uid !== currentUser.uid) return;\n    const upd = { content: editContent.trim().slice(0,MAX_POST) };\n    if (!editPost.groupId) upd.audience = editAudience;\n    await updateDoc(doc(db,'posts',editPost.id), upd);\n    setEditPost(null);\n  }\n\n  function sharePost(post) {\n    setShareModalPost(post);\n  }\n\n  function countReactions(r = {}) {\n    const c = {}; Object.values(r).forEach(e => { c[e] = (c[e]||0)+1; }); return c;\n  }\n\n  function isFriend(uid) { return (userProfile?.friends||[]).includes(uid); }\n  function hasSentReq(uid) { return (userProfile?.sentRequests||[]).includes(uid); }\n\n  async function cancelFriendReq(toUid) {\n    try {\n      await updateDoc(doc(db,'users',currentUser.uid), { sentRequests: arrayRemove(toUid) });\n      setUserProfile(p => ({ ...p, sentRequests: (p.sentRequests||[]).filter(id => id !== toUid) }));\n      // Supprimer la notif friendRequest correspondante\n      const { getDocs, query, collection, where, deleteDoc } = await import('firebase/firestore');\n      const q = query(collection(db,'notifications'),\n        where('fromUid','==',currentUser.uid),\n        where('toUid','==',toUid),\n        where('type','==','friendRequest'));\n      const snap = await getDocs(q);\n      await Promise.all(snap.docs.map(d => deleteDoc(d.ref)));\n    } catch(e) { console.warn('cancelFriendReq:', e); }\n  }\n\n  async function sendFriendReq(toUid, toName) {\n    if (isFriend(toUid) || hasSentReq(toUid)) return;\n    await addDoc(collection(db,'friendRequests'), {\n      fromUid: currentUser.uid, toUid,\n      fromName: userProfile.fullName, fromPhoto: userProfile.photoURL||'',\n      status: 'pending', createdAt: serverTimestamp(),\n    });\n    await updateDoc(doc(db,'users',currentUser.uid), { sentRequests: arrayUnion(toUid) });\n    setUserProfile(p=>({...p, sentRequests:[...(p.sentRequests||[]),toUid]}));\n    await addDoc(collection(db,'notifications'), {\n      toUid, fromUid: currentUser.uid,\n      fromName: userProfile.fullName, fromPhoto: userProfile.photoURL||'',\n      type: 'friendRequest',\n      message: `${userProfile.fullName} vous a envoy\u00e9 une demande d'ami`,\n      read: false, createdAt: serverTimestamp(),\n    });\n    sendPushNotification({ toExternalId: toUid, title: userProfile.fullName, message:\"vous a envoy\u00e9 une demande d'ami \ud83d\udc65\", data:{ type:'friendRequest' } });\n  }\n\n  // \u2500\u2500 Enregistrer / retirer publication \u2500\u2500\n  async function toggleSave(postId) {\n    const saved = userProfile?.saved || [];\n    const isSaved = saved.includes(postId);\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), { saved: isSaved ? arrayRemove(postId) : arrayUnion(postId) });\n      setUserProfile(p => ({ ...p, saved: isSaved ? (p.saved||[]).filter(id => id !== postId) : [...(p.saved||[]), postId] }));\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  // \u2500\u2500 Stories \u2500\u2500\n  async function addStory(e) {\n    const file = e.target.files[0]; if (!file) return;\n    const okTypes = ['image/jpeg','image/png','image/gif','image/webp','video/mp4','video/webm','video/quicktime'];\n    if (!okTypes.includes(file.type)) { alert('Type non accept\u00e9'); return; }\n    setAddingStory(true);\n    try {\n      let finalFile = file;\n      if (file.type.startsWith('video/')) {\n        // Vid\u00e9o story : 30 segondra farafahabetsany \u2014 raccourci ho azy raha mihoatra\n        const trimmed = await trimVideoTo30s(file);\n        if (trimmed) finalFile = trimmed;\n      }\n      const r = await uploadToTelegram(finalFile);\n      await addDoc(collection(db, 'stories'), {\n        uid: currentUser.uid,\n        authorName: userProfile.fullName,\n        authorPhoto: userProfile.photoURL || '',\n        mediaURL: r.url,\n        mediaType: r.type === 'video' ? 'video' : 'image',\n        ts: Date.now(),\n        createdAt: serverTimestamp(),\n      });\n    } catch (err) { alert('Erreur story : ' + (err?.message || err)); }\n    setAddingStory(false);\n    if (e.target) e.target.value = '';\n    e.target.value = '';\n  }\n\n  // \u2500\u2500 Story texte (fond en couleur, format Facebook) \u2500\u2500\n  const STORY_BG_COLORS = [\n    'linear-gradient(135deg,#1877F2,#63A9FF)',\n    'linear-gradient(135deg,#FF2D8D,#FF7AB8)',\n    'linear-gradient(135deg,#F2B300,#FFE066)',\n    'linear-gradient(135deg,#8F6BFF,#B49BFF)',\n    'linear-gradient(135deg,#12A48D,#3DD9C4)',\n    'linear-gradient(135deg,#FF7A00,#FF9A3D)',\n    '#050505',\n  ];\n  const [textStoryOpen,  setTextStoryOpen]  = useState(false);\n  const [textStoryValue, setTextStoryValue] = useState('');\n  const [textStoryBg,    setTextStoryBg]    = useState(STORY_BG_COLORS[0]);\n  const [postingTextStory, setPostingTextStory] = useState(false);\n\n  async function publishTextStory() {\n    if (!textStoryValue.trim()) return;\n    setPostingTextStory(true);\n    try {\n      await addDoc(collection(db, 'stories'), {\n        uid: currentUser.uid,\n        authorName: userProfile.fullName,\n        authorPhoto: userProfile.photoURL || '',\n        mediaType: 'text',\n        text: textStoryValue.trim().slice(0, 280),\n        bgColor: textStoryBg,\n        ts: Date.now(),\n        createdAt: serverTimestamp(),\n      });\n      setTextStoryOpen(false); setTextStoryValue(''); setTextStoryBg(STORY_BG_COLORS[0]);\n    } catch (err) { alert('Erreur story : ' + (err?.message || err)); }\n    setPostingTextStory(false);\n  }\n\n  async function deleteStory(st) {\n    if (st.uid !== currentUser.uid) return;\n    if (!window.confirm('Supprimer cette story ?')) return;\n    await deleteDoc(doc(db, 'stories', st.id));\n    setStoryViewer(null);\n  }\n\n  // \u2500\u2500 R\u00e9pondre \u00e0 une story = hafatra mivantana any amin'ny DM an'ilay tompony \u2500\u2500\n  const [storyReply, setStoryReply] = useState('');\n  const [sendingStoryReply, setSendingStoryReply] = useState(false);\n  async function sendStoryReply(st) {\n    if (!storyReply.trim() || st.uid === currentUser.uid) return;\n    setSendingStoryReply(true);\n    try {\n      const chatId = getChatId(currentUser.uid, st.uid);\n      const preview = st.mediaType === 'text' ? (st.text || '').slice(0, 40) : (st.mediaType === 'video' ? '\ud83c\udfac Vid\u00e9o' : '\ud83d\udcf7 Photo');\n      await dbPush(dbRef(rtdb, `conversations/${chatId}/messages`), {\n        fromUid: currentUser.uid, toUid: st.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        text: `\u21aa\ufe0f En r\u00e9ponse \u00e0 votre story (${preview}) : ${storyReply.trim()}`,\n        ts: Date.now(), read: false,\n      });\n      await dbUpdate(dbRef(rtdb, `conversations/${chatId}/meta`), {\n        lastMessage: storyReply.trim(), lastTs: Date.now(),\n      }).catch(() => {});\n      setStoryReply('');\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setSendingStoryReply(false);\n  }\n\n  function openStories(group) {\n    setStoryViewer({ group, index: 0 });\n  }\n\n  // \u2500\u2500 Fanamarihana fa hitan'ilay olona ny story (Vu) \u2500\u2500\n  async function markStoryViewed(st) {\n    if (!st || st.uid === currentUser.uid) return;\n    if ((st.viewers || []).includes(currentUser.uid)) return;\n    try { await updateDoc(doc(db, 'stories', st.id), { viewers: arrayUnion(currentUser.uid) }); } catch {}\n  }\n\n  // \u2500\u2500 R\u00e9actions amin'ny story : AFAKA maro (toy Facebook) \u2014 array isaky ny olona \u2500\u2500\n  const [flyingEmojis, setFlyingEmojis] = useState([]);\n  async function reactToStory(st, emoji, evt) {\n    const mine = st.reactions?.[currentUser.uid] || [];\n    const already = mine.includes(emoji);\n    try {\n      await updateDoc(doc(db, 'stories', st.id), {\n        [`reactions.${currentUser.uid}`]: already ? mine.filter(e => e !== emoji) : [...mine, emoji],\n      });\n      if (!already) {\n        // \u2500\u2500 Animation : emoji miakatra sy manjavona (format story Facebook) \u2500\u2500\n        const fid = Date.now() + Math.random();\n        const x = evt?.clientX ?? window.innerWidth / 2;\n        setFlyingEmojis(p => [...p, { id: fid, emoji, x }]);\n        setTimeout(() => setFlyingEmojis(p => p.filter(f => f.id !== fid)), 1200);\n      }\n    } catch (err) { console.error('story react:', err?.message || err); }\n  }\n\n  // \u2500\u2500 Lisitry ny \"Vu\" + r\u00e9actions (mitambatra, ho an'ny tompony) \u2500\u2500\n  async function openStoryReactors(st) {\n    const uids = [...new Set([...(st.viewers || []), ...Object.keys(st.reactions || {})])];\n    setStoryReactors([]);\n    const list = await Promise.all(uids.slice(0, 80).map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists()\n        ? { uid, emojis: st.reactions?.[uid] || [], name: sn.data().fullName, photo: sn.data().photoURL || '' }\n        : null).catch(() => null)\n    ));\n    // Ny nanao r\u00e9action voalohany, avy eo ny nijery fotsiny\n    list.sort((a, b) => (b?.emojis.length || 0) - (a?.emojis.length || 0));\n    setStoryReactors(list.filter(Boolean));\n  }\n  function nextStory() {\n    setStoryViewer(v => {\n      if (!v) return null;\n      if (v.index + 1 < v.group.items.length) return { ...v, index: v.index + 1 };\n      const gi = storyGroups.findIndex(g => g.uid === v.group.uid);\n      if (gi >= 0 && gi + 1 < storyGroups.length) return { group: storyGroups[gi + 1], index: 0 };\n      return null;\n    });\n  }\n  function prevStory() {\n    setStoryViewer(v => {\n      if (!v) return null;\n      if (v.index > 0) return { ...v, index: v.index - 1 };\n      return v;\n    });\n  }\n\n  // Appui long sur le texte d'une publication = menu \"Copier le texte\"\n  function startTextPress(e, post) {\n    textPressedRef.current = false;\n    clearTimeout(textPressTimer.current);\n    textPressTimer.current = setTimeout(() => {\n      textPressedRef.current = true;\n      setTextCopyMenu({ id: post.id, content: post.content });\n    }, 500);\n  }\n  function endTextPress() {\n    clearTimeout(textPressTimer.current);\n  }\n  async function copyPostText(txt) {\n    try {\n      if (navigator.clipboard?.writeText) await navigator.clipboard.writeText(txt);\n      else {\n        const ta = document.createElement('textarea');\n        ta.value = txt; ta.style.position = 'fixed'; ta.style.opacity = '0';\n        document.body.appendChild(ta); ta.select();\n        document.execCommand('copy'); document.body.removeChild(ta);\n      }\n      setTextCopyMenu(null);\n      setCopyToast(true);\n      setTimeout(() => setCopyToast(false), 1600);\n    } catch { setTextCopyMenu(null); }\n  }\n\n  // Appui long = pause (tsy manao next). Tap fohy (<250ms) = navigate (prev/next).\n  function startStoryPress() {\n    storyPressedRef.current = false;\n    clearTimeout(storyPressTimer.current);\n    storyPressTimer.current = setTimeout(() => {\n      storyPressedRef.current = true;      // appui long d\u00e9tect\u00e9 -> pause\n      setStoryPaused(true);\n      try { storyVideoRef.current?.pause(); } catch {}\n    }, 250);\n  }\n  function endStoryPress(navFn) {\n    clearTimeout(storyPressTimer.current);\n    if (storyPressedRef.current) {\n      // C'\u00e9tait un appui long -> on rel\u00e2che : reprendre la lecture, PAS de navigation\n      setStoryPaused(false);\n      try { storyVideoRef.current?.play(); } catch {}\n    } else {\n      // Tap court -> navigation (prev/next)\n      if (navFn) navFn();\n    }\n    storyPressedRef.current = false;\n  }\n\n  // Avance automatique des images (5s) \u2014 mijanona raha appui long (pause)\n  useEffect(() => {\n    if (!storyViewer || storyPaused) return;\n    const cur = storyViewer.group.items[storyViewer.index];\n    if (!cur || cur.mediaType === 'video') return;\n    const tm = setTimeout(nextStory, 30000);\n    return () => clearTimeout(tm);\n  }, [storyViewer, storyPaused]);\n\n  // \u2705 Marquer \"Vu\" rehefa miseho ny story (raha tsy anao)\n  useEffect(() => {\n    if (!storyViewer) return;\n    setStoryPaused(false);   // reset pause rehefa miova story\n    const cur = storyViewer.group.items[storyViewer.index];\n    if (cur) markStoryViewed(cur);\n  }, [storyViewer]);\n\n  // \u2500\u2500 J'aime rapide (clic) + appui long = choix de r\u00e9action (format Facebook) \u2500\u2500\n  function quickLike(post) {\n    if (lpFired.current) { lpFired.current = false; return; }\n    const myR = post.reactions?.[currentUser.uid];\n    reactToPost(post.id, myR || '\ud83d\udc4d');\n  }\n  function startLongPress(postId) {\n    lpFired.current = false;\n    lpTimer.current = setTimeout(() => { lpFired.current = true; setShowReact(p => ({ ...p, [postId]: true })); }, 450);\n  }\n  function endLongPress() { clearTimeout(lpTimer.current); }\n\n  const rem = MAX_POST - content.length;\n  const charColor = rem < 50 ? '#ef4444' : rem < 200 ? '#f97316' : '#65676B';\n\n  return (\n    <div style={{ padding:0 }}>\n      <PullToRefresh />\n      {boostTarget && (\n        <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />\n      )}\n      {reportTarget && (\n        <ReportModal title=\"Signaler la publication\" onConfirm={submitReport} onClose={() => setReportTarget(null)} />\n      )}\n      {viewerState && (\n        <MediaViewer\n          post={viewerState.post}\n          startIndex={viewerState.index}\n          onClose={() => setViewerState(null)}\n          currentUser={currentUser}\n          userProfile={userProfile}\n          navigate={navigate}\n          myR={viewerState.post.reactions?.[currentUser.uid]}\n          rc={countReactions(viewerState.post.reactions)}\n          total={Object.keys(viewerState.post.reactions||{}).length}\n          reactorNames={reactorNames}\n          onReact={(emoji) => reactToPost(viewerState.post.id, emoji)}\n          onOpenReactionModal={() => openReactionModal(viewerState.post)}\n          onDownload={(url) => downloadMedia(url, 'image')}\n          onShare={() => sharePost(viewerState.post)}\n          reactToCmt={reactToCmt}\n          addComment={addComment}\n          deleteCmt={deleteCmt}\n          cmtText={cmtText}\n          setCmtText={setCmtText}\n          replyTo={replyTo}\n          setReplyTo={setReplyTo}\n          VIPBadge={VIPBadge}\n        />\n      )}\n\n      {postsLoading && posts.length === 0 && (\n        <div style={{ padding: '0 0 8px' }}>\n          <SkeletonPost />\n          <SkeletonPost />\n        </div>\n      )}\n\n      {/* \u2500\u2500 Stories (format Facebook) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      <div className=\"stories-strip\">\n        {/* Carte : Cr\u00e9er une story (menu unifi\u00e9 : texte / photo / vid\u00e9o) */}\n        <input ref={storyFileRef} type=\"file\" accept=\"image/*,video/mp4,video/webm,video/quicktime\" style={{ display:'none' }} onChange={addStory} />\n        <div className=\"story-card\" onClick={() => !addingStory && setCreateStoryMenuOpen(true)} style={{ background:'white', border:'1px solid #E4E6EB' }}>\n          <div style={{ height:'62%', overflow:'hidden' }}>\n            <img src={userProfile?.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`}\n              alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }} />\n          </div>\n          <div style={{ position:'absolute', top:'62%', left:'50%', transform:'translate(-50%,-50%)', width:34, height:34, borderRadius:'50%', background:'#1877F2', border:'3.5px solid white', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:20, fontWeight:700 }}>+</div>\n          <p style={{ position:'absolute', bottom:8, left:0, right:0, textAlign:'center', fontSize:11, fontWeight:600, color:'#050505' }}>\n            {addingStory ? 'Envoi...' : 'Cr\u00e9er une story'}\n          </p>\n        </div>\n\n        {/* Stories des utilisateurs */}\n        {storyGroups.map(g => {\n          const last = g.items[g.items.length - 1];\n          return (\n            <div key={g.uid} className=\"story-card\" onClick={() => openStories(g)} style={last.mediaType === 'text' ? { background: last.bgColor || '#1877F2' } : undefined}>\n              {last.mediaType === 'video'\n                ? <video src={last.mediaURL} muted playsInline preload=\"metadata\" />\n                : last.mediaType === 'text'\n                ? <div style={{ width:'100%', height:'100%', display:'flex', alignItems:'center', justifyContent:'center', padding:10 }}>\n                    <p style={{ color:'white', fontSize:13, fontWeight:700, textAlign:'center', overflow:'hidden', display:'-webkit-box', WebkitLineClamp:5, WebkitBoxOrient:'vertical' }}>{last.text}</p>\n                  </div>\n                : <img src={last.mediaURL} alt=\"\" />}\n              <div className=\"story-gradient\" />\n              <img className=\"story-avatar\"\n                src={g.photo || `https://ui-avatars.com/api/?name=${encodeURIComponent(g.name||'U')}&background=1877F2&color=fff`} alt=\"\" />\n              <span className=\"story-name\">{g.uid === currentUser.uid ? 'Votre story' : g.name?.split(' ')[0]}</span>\n            </div>\n          );\n        })}\n      </div>\n\n      {storyStudio && (\n        <StoryStudio mode={storyStudio} currentUser={currentUser} userProfile={userProfile}\n          onClose={() => setStoryStudio(null)} onPublished={() => setStoryStudio(null)} />\n      )}\n\n      {/* \u2500\u2500 Bottom sheet : Cr\u00e9er une story (choix texte / photo / vid\u00e9o) \u2500\u2500 */}\n      {createStoryMenuOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setCreateStoryMenuOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', width:'100%', maxWidth:520, padding:'10px 0 22px' }}>\n            <div style={{ width:40, height:4, borderRadius:2, background:'#CED0D4', margin:'6px auto 12px' }} />\n            <p style={{ fontWeight:800, fontSize:17, textAlign:'center', marginBottom:14, color:'#050505' }}>Cr\u00e9er une story</p>\n            <button onClick={() => { setCreateStoryMenuOpen(false); setStoryStudio('text'); }}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'14px 22px', background:'none', border:'none', cursor:'pointer', textAlign:'left' }}>\n              <span className=\"icon-badge-3d\" style={{ width:44, height:44, borderRadius:13, background:'linear-gradient(145deg,#8F7BFF,#5E4BDB)', flexShrink:0 }}>\n                <span style={{ color:'white', fontSize:22, fontWeight:800 }}>Aa</span>\n              </span>\n              <span><span style={{ display:'block', fontWeight:700, fontSize:15, color:'#050505' }}>Texte</span><span style={{ display:'block', fontSize:12, color:'#65676B' }}>Fond en couleur</span></span>\n            </button>\n            <button onClick={() => { setCreateStoryMenuOpen(false); setStoryStudio('photo'); }}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'14px 22px', background:'none', border:'none', cursor:'pointer', textAlign:'left' }}>\n              <span className=\"icon-badge-3d\" style={{ width:44, height:44, borderRadius:13, background:'linear-gradient(145deg,#3DD9C4,#12A48D)', flexShrink:0 }}>\n                <HiPhotograph size={22} color=\"white\" />\n              </span>\n              <span><span style={{ display:'block', fontWeight:700, fontSize:15, color:'#050505' }}>Photo</span><span style={{ display:'block', fontSize:12, color:'#65676B' }}>Depuis votre galerie</span></span>\n            </button>\n            <button onClick={() => { setCreateStoryMenuOpen(false); setStoryStudio('video'); }}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'14px 22px', background:'none', border:'none', cursor:'pointer', textAlign:'left' }}>\n              <span className=\"icon-badge-3d\" style={{ width:44, height:44, borderRadius:13, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', flexShrink:0 }}>\n                <HiVideoCamera size={22} color=\"white\" />\n              </span>\n              <span><span style={{ display:'block', fontWeight:700, fontSize:15, color:'#050505' }}>Vid\u00e9o</span><span style={{ display:'block', fontSize:12, color:'#65676B' }}>30 secondes max</span></span>\n            </button>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Cr\u00e9er une story texte \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {textStoryOpen && (\n        <div style={{ position:'fixed', inset:0, background: textStoryBg, zIndex:350, display:'flex', flexDirection:'column' }}>\n          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'14px 16px' }}>\n            <button onClick={() => setTextStoryOpen(false)} style={{ background:'rgba(255,255,255,.2)', border:'none', borderRadius:'50%', width:36, height:36, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiX size={20}/></button>\n            <button onClick={publishTextStory} disabled={postingTextStory || !textStoryValue.trim()} className=\"btn-gold\" style={{ padding:'9px 22px', fontSize:14 }}>\n              {postingTextStory ? '...' : 'Publier'}\n            </button>\n          </div>\n          <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:24 }}>\n            <textarea autoFocus value={textStoryValue} onChange={e => setTextStoryValue(e.target.value)} placeholder=\"\u00c9crivez quelque chose...\" maxLength={280}\n              style={{ width:'100%', background:'none', border:'none', outline:'none', color:'white', fontSize:28, fontWeight:800, textAlign:'center', resize:'none', height:200, fontFamily:'Poppins' }} />\n          </div>\n          <div style={{ display:'flex', gap:10, padding:'16px 20px 28px', overflowX:'auto', justifyContent:'center' }}>\n            {STORY_BG_COLORS.map((bg, i) => (\n              <button key={i} onClick={() => setTextStoryBg(bg)}\n                style={{ width:36, height:36, borderRadius:'50%', background:bg, border: textStoryBg===bg ? '3px solid white' : '2px solid rgba(255,255,255,.4)', cursor:'pointer', flexShrink:0 }} />\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Visionneuse de story (plein \u00e9cran) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {storyViewer && (() => {\n        const raw = storyViewer.group.items[storyViewer.index];\n        // Version \"fra\u00eeche\" (mivantana avy amin'ny snapshot) mba hita avy hatrany ny r\u00e9actions\n        const cur = storyGroups.find(g => g.uid === storyViewer.group.uid)?.items.find(i => i.id === raw.id) || raw;\n        const isMyStory = cur.uid === currentUser.uid;\n        const myStoryR = cur.reactions?.[currentUser.uid] || [];\n        const rCount = Object.keys(cur.reactions || {}).length;\n        const vCount = new Set([...(cur.viewers||[]), ...Object.keys(cur.reactions||{})]).size;\n        const allEmojis = Object.values(cur.reactions || {}).flat();\n        return (\n          <div style={{ position:'fixed', inset:0, background:'#000', zIndex:300, display:'flex', flexDirection:'column' }}>\n            {/* Barres de progression */}\n            <div style={{ display:'flex', gap:4, padding:'10px 10px 6px' }}>\n              {storyViewer.group.items.map((it, i) => (\n                <div key={it.id} style={{ flex:1, height:3, borderRadius:2, background: i <= storyViewer.index ? 'white' : 'rgba(255,255,255,.35)' }} />\n              ))}\n            </div>\n            {/* En-t\u00eate */}\n            <div style={{ display:'flex', alignItems:'center', gap:10, padding:'6px 12px' }}>\n              <img src={storyViewer.group.photo || `https://ui-avatars.com/api/?name=${encodeURIComponent(storyViewer.group.name||'U')}&background=1877F2&color=fff`}\n                alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover', border:'2px solid #1877F2' }} />\n              <p style={{ color:'white', fontWeight:700, fontSize:14, flex:1 }}>{storyViewer.group.name}</p>\n              {cur.uid === currentUser.uid && (\n                <button onClick={() => deleteStory(cur)} style={{ background:'none', border:'none', cursor:'pointer', color:'white', padding:6 }}><HiTrash size={20} /></button>\n              )}\n              <button onClick={() => setStoryViewer(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'white', fontSize:24, padding:'0 6px' }}>\u2715</button>\n            </div>\n            {/* M\u00e9dia + zones tactiles gauche/droite */}\n            <div style={{ flex:1, position:'relative', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden', background: cur.mediaType === 'text' ? (cur.bgColor || '#1877F2') : 'transparent' }}>\n              {cur.mediaType === 'video'\n                ? <video ref={storyVideoRef} key={cur.id} src={cur.mediaURL} autoPlay={!dataSaver} controls={dataSaver} playsInline muted={!!cur.music?.url} onEnded={nextStory} style={{ maxWidth:'100%', maxHeight:'100%', filter: cur.filter || 'none' }} />\n                : cur.mediaType === 'text'\n                ? <p style={{ color: cur.textColor || 'white', fontSize: cur.fontSize || 30, fontWeight:800, textAlign: cur.align || 'center', padding:'0 30px', wordBreak:'break-word', whiteSpace:'pre-wrap' }}>{cur.text}</p>\n                : <img key={cur.id} src={cur.mediaURL} alt=\"\" style={{ maxWidth:'100%', maxHeight:'100%', objectFit:'contain', filter: cur.filter || 'none' }} />}\n              {cur.caption && (cur.mediaType === 'video' || cur.mediaType === 'image') && (\n                <div style={ cur.captionPos ? { position:'absolute', left:(cur.captionPos.x*100)+'%', top:(cur.captionPos.y*100)+'%', transform:'translate(-50%,-50%)', maxWidth:'82%', textAlign:'center', color:'#fff', fontWeight:800, fontSize:22, textShadow:'0 2px 10px rgba(0,0,0,.7)', pointerEvents:'none', wordBreak:'break-word' } : { position:'absolute', left:24, right:24, bottom:24, textAlign:'center', color:'#fff', fontWeight:800, fontSize:22, textShadow:'0 2px 10px rgba(0,0,0,.7)', pointerEvents:'none', wordBreak:'break-word' }}>{cur.caption}</div>\n              )}\n              {cur.music?.url && <StoryMusicPlayer url={cur.music.url} start={cur.music.start} paused={storyPaused} />}\n              {cur.music?.title && (\n                <div style={{ position:'absolute', left:14, bottom:14, display:'flex', alignItems:'center', gap:7, background:'rgba(0,0,0,.5)', borderRadius:20, padding:'6px 12px', color:'#fff', fontSize:12.5, fontWeight:700, maxWidth:'70%', pointerEvents:'none' }}>\n                  <span style={{ color:'#FF7AB8' }}>\u266a</span>\n                  <span style={{ overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{cur.music.title}{cur.music.artist ? ' \u00b7 ' + cur.music.artist : ''}</span>\n                </div>\n              )}\n              {/* Zone gauche : appui long = pause, tap = pr\u00e9c\u00e9dent */}\n              <div\n                onPointerDown={() => startStoryPress()}\n                onPointerUp={() => endStoryPress(prevStory)}\n                onPointerLeave={() => endStoryPress(null)}\n                style={{ position:'absolute', left:0, top:0, bottom:0, width:'35%', touchAction:'none' }} />\n              {/* Zone droite : appui long = pause, tap = suivant */}\n              <div\n                onPointerDown={() => startStoryPress()}\n                onPointerUp={() => endStoryPress(nextStory)}\n                onPointerLeave={() => endStoryPress(null)}\n                style={{ position:'absolute', right:0, top:0, bottom:0, width:'65%', touchAction:'none' }} />\n            </div>\n\n            {/* \u2500\u2500 R\u00e9pondre (envoie un message direct au propri\u00e9taire) \u2500\u2500 */}\n            {!isMyStory && (\n              <div style={{ padding:'0 14px 8px', display:'flex', alignItems:'center', gap:8 }} onClick={e => e.stopPropagation()}>\n                <input value={storyReply} onChange={e => setStoryReply(e.target.value)}\n                  onKeyDown={e => { if (e.key === 'Enter') sendStoryReply(cur); }}\n                  placeholder=\"R\u00e9pondre...\" maxLength={500}\n                  style={{ flex:1, background:'rgba(255,255,255,.15)', border:'1.5px solid rgba(255,255,255,.35)', borderRadius:22, padding:'10px 16px', color:'white', fontSize:14, fontFamily:'Poppins', outline:'none' }} />\n                {storyReply.trim() && (\n                  <button onClick={() => sendStoryReply(cur)} disabled={sendingStoryReply}\n                    style={{ background:'#1877F2', border:'none', borderRadius:'50%', width:40, height:40, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\n                    <HiPaperAirplane size={18} />\n                  </button>\n                )}\n              </div>\n            )}\n\n            {/* \u2500\u2500 R\u00e9actions (format Facebook, plusieurs possibles) \u2500\u2500 */}\n            <div style={{ padding:'10px 14px 18px', display:'flex', alignItems:'center', justifyContent:'center', gap:10 }} onClick={e => e.stopPropagation()}>\n              {isMyStory ? (\n                <button onClick={() => openStoryReactors(cur)}\n                  style={{ background:'rgba(255,255,255,.14)', border:'1px solid rgba(255,255,255,.3)', borderRadius:22, padding:'9px 18px', cursor:'pointer', color:'white', fontFamily:'Poppins', fontSize:13, fontWeight:700, display:'flex', alignItems:'center', gap:8 }}>\n                  \ud83d\udc41 {vCount} vue{vCount>1?'s':''}{rCount > 0 ? ` \u00b7 ${[...new Set(allEmojis)].slice(0,3).join('')} ${rCount}` : ''} \u2014 voir\n                </button>\n              ) : (\n                REACTIONS.map(em => (\n                  <button key={em} onClick={e => reactToStory(cur, em, e)}\n                    style={{ background: myStoryR.includes(em) ? 'rgba(255,255,255,.32)' : 'rgba(255,255,255,.12)', border: myStoryR.includes(em) ? '1.5px solid white' : '1px solid rgba(255,255,255,.25)', borderRadius:'50%', width:44, height:44, cursor:'pointer', fontSize:22, display:'flex', alignItems:'center', justifyContent:'center', transform: myStoryR.includes(em) ? 'scale(1.15)' : 'none', transition:'all .15s' }}>\n                    {em}\n                  </button>\n                ))\n              )}\n            </div>\n\n            {/* Animation : emoji miakatra sy manjavona rehefa misy r\u00e9action (format story Facebook) */}\n            {flyingEmojis.map(f => (\n              <span key={f.id} className=\"story-emoji-fly\" style={{ left: f.x - 16 }}>{f.emoji}</span>\n            ))}\n\n            {/* Lisitry ny \"Vu\" + r\u00e9actions (tompony ihany) */}\n            {storyReactors !== null && (\n              <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,.6)', display:'flex', alignItems:'flex-end', justifyContent:'center', zIndex:10 }} onClick={() => setStoryReactors(null)}>\n                <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:18, width:'100%', maxWidth:480, maxHeight:'60vh', overflowY:'auto' }}>\n                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>\n                    <h3 style={{ fontWeight:800, color:'#1877F2', fontSize:16 }}>Vues et r\u00e9actions</h3>\n                    <button onClick={() => setStoryReactors(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:20 }}>\u2715</button>\n                  </div>\n                  {storyReactors.length === 0 && <p style={{ fontSize:13, color:'#65676B', textAlign:'center', padding:'14px 0' }}>Chargement...</p>}\n                  {storyReactors.map(r => (\n                    <div key={r.uid} onClick={() => { setStoryReactors(null); setStoryViewer(null); navigate(`/profile/${r.uid}`); }}\n                      style={{ display:'flex', alignItems:'center', gap:10, padding:'9px 2px', cursor:'pointer', borderBottom:'1px solid #F0F2F5' }}>\n                      <img src={r.photo || `https://ui-avatars.com/api/?name=${encodeURIComponent(r.name||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:38, height:38, borderRadius:'50%', objectFit:'cover' }} />\n                      <p style={{ flex:1, fontWeight:600, fontSize:14 }}>{r.name}</p>\n                      {r.emojis.length > 0\n                        ? <span style={{ fontSize:18 }}>{r.emojis.join(' ')}</span>\n                        : <span style={{ fontSize:11, color:'#65676B' }}>\ud83d\udc41 Vu</span>}\n                    </div>\n                  ))}\n                </div>\n              </div>\n            )}\n          </div>\n        );\n      })()}\n\n      {/* Create post \u2014 barre kely (ic\u00f4ne fotsiny, clic = page feno) */}\n      <div className=\"card post-card\" style={{ padding:12, marginBottom:8 }}>\n        <div style={{ display:'flex', gap:10, alignItems:'center' }}>\n          <img src={userProfile?.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:40, height:40, flexShrink:0 }}/>\n          <button onClick={() => setPublishFullOpen(true)}\n            style={{ flex:1, textAlign:'left', background:'#F0F2F5', border:'none', borderRadius:22, padding:'10px 16px', color:'#65676B', fontSize:14.5, fontFamily:'Poppins', cursor:'pointer' }}>\n            {t('whatsOnMind')}\n          </button>\n        </div>\n        <div style={{ display:'flex', alignItems:'center', marginTop:10, paddingTop:8, borderTop:'1px solid #E4E6EB' }}>\n          {/* Ic\u00f4nes fotsiny (tsy labelle) \u2014 Photo, Vid\u00e9o, Vente + \"Plus\" */}\n          <button onClick={() => { setPublishFullOpen(true); setTimeout(() => photoRef.current?.click(), 60); }} title=\"Photo\"\n            style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', gap:6, background:'none', border:'none', cursor:'pointer', padding:'6px 0' }}>\n            <HiPhotograph size={22} color=\"#45BD62\" />\n          </button>\n          <button onClick={() => { setPublishFullOpen(true); setTimeout(() => videoRef.current?.click(), 60); }} title=\"Vid\u00e9o\"\n            style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', gap:6, background:'none', border:'none', cursor:'pointer', padding:'6px 0', borderLeft:'1px solid #E4E6EB' }}>\n            <HiVideoCamera size={22} color=\"#F3425F\" />\n          </button>\n          <button onClick={() => { setPublishFullOpen(true); setIsSale(true); }} title=\"Vente\"\n            style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', gap:6, background:'none', border:'none', cursor:'pointer', padding:'6px 0', borderLeft:'1px solid #E4E6EB' }}>\n            <HiTag size={22} color=\"#F5C518\" />\n          </button>\n          <button onClick={() => setPublishFullOpen(true)} title=\"Plus\"\n            style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', gap:5, background:'none', border:'none', cursor:'pointer', padding:'6px 0', borderLeft:'1px solid #E4E6EB', color:'#1877F2', fontWeight:700, fontSize:13, fontFamily:'Poppins' }}>\n            <span style={{ fontSize:18 }}>\uff0b</span> Publi\u00e9\n          </button>\n        </div>\n      </div>\n\n      {/* \u2500\u2500 PAGE FENO : Cr\u00e9er une publication (accueil, format Facebook) \u2500\u2500 */}\n      {publishFullOpen && (\n      <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.35)', zIndex:350, display:'flex', alignItems:'flex-start', justifyContent:'center', overflowY:'auto' }}>\n      <div className=\"card post-card\" style={{ padding:16, marginBottom:8, width:'100%', maxWidth:600, minHeight:'100vh', borderRadius:0 }}>\n        {/* Header page */}\n        <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:14, paddingBottom:12, borderBottom:'1px solid #E4E6EB' }}>\n          <button onClick={() => setPublishFullOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', padding:4 }}><HiX size={24} color=\"#050505\"/></button>\n          <h3 style={{ fontWeight:800, fontSize:18, flex:1 }}>Cr\u00e9er une publication</h3>\n          <button className=\"btn-primary\" onClick={() => { createPost(); }} disabled={posting||(!content.trim()&&!mediaFile&&multiPhotos.length===0)||content.length>MAX_POST} style={{ padding:'7px 20px', fontSize:14 }}>\n            {posting?'...':t('publishPost')}\n          </button>\n        </div>        <div style={{ display:'flex', gap:10, alignItems:'flex-start' }}>\n          <img src={userProfile?.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:42, height:42, flexShrink:0 }}/>\n          <div style={{ flex:1 }}>\n            {textBg ? (\n              <div style={{ background:textBg, borderRadius:14, minHeight:180, display:'flex', alignItems:'center', justifyContent:'center', padding:'20px 16px', width:'100%' }} onClick={()=>document.getElementById('textbg-input')?.focus()}>\n                <textarea\n                  id=\"textbg-input\"\n                  placeholder=\"\u00c9crire quelque chose...\"\n                  value={content}\n                  onChange={e => setContent(e.target.value)}\n                  style={{ resize:'none', width:'100%', border:'none', fontSize:22, fontWeight:800, color:'white', textAlign:'center', background:'transparent', outline:'none', lineHeight:1.4, minHeight:80 }}\n                  maxLength={MAX_POST}\n                  autoFocus\n                />\n              </div>\n            ) : (\n              <textarea className=\"input\" placeholder={t('whatsOnMind')} value={content} onChange={e => setContent(e.target.value)} rows={3} style={{ resize:'none', width:'100%', border:'none', fontSize:17 }} maxLength={MAX_POST} autoFocus/>\n            )}\n            {content.length > 0 && <p style={{ fontSize:11, color:charColor, textAlign:'right', marginTop:2 }}>{rem} restants</p>}\n          {!mediaPreview && multiPhotos.length === 0 && (\n          <div style={{ display:'flex', gap:8, marginTop:10, alignItems:'center', justifyContent:'center', flexWrap:'wrap' }}>\n            {TEXT_BG_COLORS.map((bg, i) => (\n              <button key={i} onClick={() => setTextBg(bg)}\n                style={{ width: textBg===bg ? 32 : 28, height: textBg===bg ? 32 : 28, borderRadius:'50%', padding:0, cursor:'pointer', flexShrink:0,\n                  background: bg || '#ffffff',\n                  border: textBg===bg ? '3px solid #050505' : '2px solid #E4E6EB',\n                  transition:'all .15s',\n                  boxShadow: textBg===bg ? '0 0 0 2px white, 0 0 0 4px #050505' : 'none' }}/>\n            ))}\n          </div>\n          )}\n          </div>\n        </div>\n\n        {/* Audience \u2014 Public / Amis / Moi uniquement (ic\u00f4nes n\u00e9on, format Facebook) */}\n        <div style={{ display:'flex', justifyContent:'flex-end', marginTop:4, position:'relative' }} onClick={e => e.stopPropagation()}>\n          <button onClick={() => setAudienceMenuOpen(p => !p)}\n            style={{ display:'flex', alignItems:'center', gap:6, padding:'5px 12px', borderRadius:14, border:'1.5px solid #E4E6EB', background:'#F0F2F5', fontFamily:'Poppins', fontSize:12, fontWeight:700, color:'#65676B', cursor:'pointer' }}>\n            {audience==='public' && <><NeonGlobe size={14}/> Public</>}\n            {audience==='friends' && <><NeonPeople size={14}/> Amis</>}\n            {audience==='me' && <><NeonLock size={14}/> Moi uniquement</>}\n          </button>\n          {audienceMenuOpen && (\n            <div style={{ position:'absolute', top:'110%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.14)', minWidth:190, zIndex:20, overflow:'hidden' }}>\n              {[['public','Public',<NeonGlobe key=\"g\" size={15}/>],['friends','Amis',<NeonPeople key=\"p\" size={15}/>],['me','Moi uniquement',<NeonLock key=\"l\" size={15}/>]].map(([val,label,icon]) => (\n                <button key={val} onClick={() => { setAudience(val); setAudienceMenuOpen(false); }}\n                  style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 14px', background: audience===val ? '#E7F0FE' : 'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:13, fontWeight:600, color:'#050505' }}>\n                  {icon} {label}\n                </button>\n              ))}\n            </div>\n          )}\n        </div>\n\n        {/* Pastilles : lieu / humeur / amis identifi\u00e9s (format Facebook) */}\n        {(postLocation || postMood || Object.values(composerTagSel).some(Boolean)) && (\n          <div style={{ display:'flex', flexWrap:'wrap', gap:6, marginTop:8 }}>\n            {postLocation && (\n              <span style={{ display:'flex', alignItems:'center', gap:5, background:'#FFE9F2', color:'#FF2D8D', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>\n                \ud83d\udccd {postLocation} <span onClick={() => setPostLocation('')} style={{ cursor:'pointer' }}>\u2715</span>\n              </span>\n            )}\n            {postMood && (\n              <span style={{ display:'flex', alignItems:'center', gap:5, background:'#FFF6DB', color:'#B8860B', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>\n                {postMood} <span onClick={() => setPostMood('')} style={{ cursor:'pointer' }}>\u2715</span>\n              </span>\n            )}\n            {Object.values(composerTagSel).some(Boolean) && (\n              <span style={{ display:'flex', alignItems:'center', gap:5, background:'#E7F0FE', color:'#1877F2', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>\n                \ud83c\udff7\ufe0f avec {composerTagList.filter(f => composerTagSel[f.uid]).map(f => f.fullName).join(', ')} <span onClick={() => setComposerTagSel({})} style={{ cursor:'pointer' }}>\u2715</span>\n              </span>\n            )}\n          </div>\n        )}\n\n        {mediaPreview && (\n          <div style={{ position:'relative', marginTop:10 }}>\n            {mediaType==='image'\n              ? <img src={mediaPreview} alt=\"\" style={{ width:'100%', borderRadius:10, maxHeight:250, objectFit:'cover' }}/>\n              : <video src={mediaPreview} controls style={{ width:'100%', borderRadius:10, maxHeight:250 }}/>}\n            <button onClick={removeMedia} style={{ position:'absolute', top:6, right:6, background:'rgba(0,0,0,.5)', border:'none', borderRadius:'50%', width:28, height:28, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiX size={16}/></button>\n          </div>\n        )}\n\n        {multiPhotos.length > 0 && (\n          <div style={{ marginTop:10 }}>\n            <div style={{ display:'flex', gap:8, overflowX:'auto', paddingBottom:4 }}>\n              {multiPhotos.map((f, i) => (\n                <div key={i} style={{ position:'relative', flexShrink:0, width:84, height:84 }}>\n                  <img src={URL.createObjectURL(f)} alt=\"\" style={{ width:'100%', height:'100%', borderRadius:10, objectFit:'cover' }}/>\n                  <button onClick={() => removeOnePhoto(i)} style={{ position:'absolute', top:3, right:3, background:'rgba(0,0,0,.55)', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiX size={11}/></button>\n                </div>\n              ))}\n            </div>\n            <p style={{ fontSize:11, color:'#65676B', marginTop:4 }}>{multiPhotos.length}/10 photos</p>\n          </div>\n        )}\n\n        {isSale && (\n          <div style={{ marginTop:10, display:'flex', flexDirection:'column', gap:8 }}>\n            <div style={{ display:'flex', alignItems:'center', gap:8 }}>\n              <HiTag color=\"#1877F2\" size={18}/>\n              <select className=\"input\" value={saleCategory} onChange={e => setSaleCategory(e.target.value)} style={{ flex:1 }}>\n                {SALE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}\n              </select>\n            </div>\n            <div style={{ display:'flex', alignItems:'center', gap:8 }}>\n              <HiTag color=\"#1877F2\" size={18}/>\n              <input className=\"input\" type=\"number\" placeholder={`${t('price')} (Ar)`} value={price} onChange={e => setPrice(e.target.value)} style={{ flex:1 }} min=\"1\" max={MAX_PRICE}/>\n            </div>\n            <div style={{ display:'flex', alignItems:'center', gap:8 }}>\n              <HiPhone color=\"#1877F2\" size={18}/>\n              <input className=\"input\" type=\"tel\" placeholder=\"Num\u00e9ro de contact\" value={contact} onChange={e => setContact(e.target.value)} style={{ flex:1 }} maxLength={20}/>\n            </div>\n            <div style={{ display:'flex', alignItems:'center', gap:8 }}>\n              <HiLocationMarker color=\"#1877F2\" size={18}/>\n              <input className=\"input\" type=\"text\" placeholder=\"Lieu pr\u00e9cis de vente (point exact)\" value={lieu} onChange={e => setLieu(e.target.value)} style={{ flex:1 }} maxLength={100}/>\n            </div>\n          </div>\n        )}\n\n        {posting && uploadPct > 0 && (\n          <div style={{ marginTop:8 }}>\n            <div style={{ height:4, background:'#E4E6EB', borderRadius:2 }}>\n              <div style={{ height:'100%', width:`${uploadPct}%`, background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', borderRadius:2, transition:'width .3s' }}/>\n            </div>\n            <p style={{ fontSize:11, color:'#65676B', marginTop:3 }}>Upload en cours...</p>\n          </div>\n        )}\n\n        {/* Options importation \u2014 ic\u00f4ne + labelle (format Facebook, page feno) */}\n        <div style={{ marginTop:16, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden' }}>\n          <input ref={photoRef} type=\"file\" multiple accept=\"image/jpeg,image/png,image/gif,image/webp\" onChange={e => handleMedia(e,'image')} style={{ display:'none' }}/>\n          <input ref={videoRef} type=\"file\" accept=\"video/mp4,video/webm,video/quicktime\"       onChange={e => handleMedia(e,'video')} style={{ display:'none' }}/>\n          {[\n            { icon:<HiPhotograph size={22} color=\"#45BD62\"/>, label:'Photo / Vid\u00e9o', action:() => photoRef.current?.click() },\n            { icon:<HiVideoCamera size={22} color=\"#F3425F\"/>, label:'Vid\u00e9o',        action:() => videoRef.current?.click() },\n            { icon:<HiTag size={22} color=\"#F5C518\"/>,         label:'Vente',        action:() => setIsSale(p=>!p), active:isSale },\n            { icon:<HiUserAdd size={22} color=\"#1877F2\"/>,     label:'Identifier des personnes', action:() => openComposerTagModal() },\n            { icon:<NeonLocation size={22}/>,                  label: postLocation ? `Lieu : ${postLocation}` : 'Ajouter un lieu', action:() => setLocationPromptOpen(true) },\n            { icon:<span style={{ fontSize:22 }}>\ud83d\ude0a</span>,     label: postMood || 'Humeur / Activit\u00e9', action:() => setMoodPickerOpen(true) },\n            { icon:<HiPaperAirplane size={22} color=\"#1877F2\"/>, label: allowMessages ? 'Recevoir des messages : Activ\u00e9' : 'Recevoir des messages : D\u00e9sactiv\u00e9', action:() => setAllowMessages(p=>!p) },\n            { icon:<HiCalendar size={22} color=\"#3DD9C4\"/>,    label:'Cr\u00e9er un \u00e9v\u00e9nement', action:() => navigate('/events') },\n            { icon:<HiLightningBolt size={22} color=\"#FF7A00\"/>, label:'Lancer un d\u00e9cret', action:() => setIsDecree(p=>!p), active:isDecree },\n          ].map((opt, i) => (\n            <button key={i} onClick={opt.action}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'13px 16px', background: opt.active ? '#E7F0FE' : 'none', border:'none', borderTop: i>0?'1px solid #F0F2F5':'none', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:15, fontWeight:600, color:'#050505' }}>\n              {opt.icon} {opt.label}\n            </button>\n          ))}\n        </div>\n      </div>\n      </div>\n      )}\n\n      {/* Edit post modal */}\n      {/* \u2500\u2500 Menu : Copier le texte (appui long sur une publication) \u2500\u2500 */}\n      {textCopyMenu && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setTextCopyMenu(null)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', width:'100%', maxWidth:520, padding:'10px 0 22px' }}>\n            <div style={{ width:40, height:4, borderRadius:2, background:'#CED0D4', margin:'6px auto 12px' }} />\n            <button onClick={() => copyPostText(textCopyMenu.content)}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'15px 22px', background:'none', border:'none', cursor:'pointer', textAlign:'left', fontSize:15, fontWeight:600, color:'#050505', fontFamily:'Poppins' }}>\n              <HiClipboardCopy size={22} color=\"#1877F2\" /> Copier le texte\n            </button>\n            <button onClick={() => setTextCopyMenu(null)}\n              style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'15px 22px', background:'none', border:'none', cursor:'pointer', textAlign:'left', fontSize:15, fontWeight:600, color:'#65676B', fontFamily:'Poppins' }}>\n              <HiX size={22} color=\"#65676B\" /> Annuler\n            </button>\n          </div>\n        </div>\n      )}\n\n      {/* Toast : Texte copi\u00e9 */}\n      {copyToast && (\n        <div style={{ position:'fixed', bottom:104, left:'50%', transform:'translateX(-50%)', zIndex:450, background:'#050505', color:'white', padding:'10px 20px', borderRadius:22, fontSize:14, fontWeight:600, fontFamily:'Poppins', boxShadow:'0 6px 20px rgba(0,0,0,.3)' }}>\n          \u2713 Texte copi\u00e9\n        </div>\n      )}\n\n      {editPost && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:400, padding:20 }}>\n            <h3 style={{ marginBottom:12 }}>Modifier la publication</h3>\n            <textarea className=\"input\" rows={4} value={editContent} onChange={e => setEditContent(e.target.value)} style={{ resize:'none' }} maxLength={MAX_POST}/>\n            {!editPost.groupId && (\n              <div style={{ marginTop:12 }}>\n                <p style={{ fontSize:12.5, fontWeight:700, color:'#65676B', marginBottom:7 }}>Audience</p>\n                <div style={{ display:'flex', gap:8 }}>\n                  {[['public','Public',<NeonGlobe key=\"g\" size={14}/>],['friends','Amis',<NeonPeople key=\"p\" size={14}/>],['me','Moi',<NeonLock key=\"l\" size={14}/>]].map(([v,lb,ic]) => (\n                    <button key={v} onClick={() => setEditAudience(v)}\n                      style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:5, padding:'8px 0', borderRadius:12, cursor:'pointer', fontFamily:'Poppins', fontSize:12.5, fontWeight:600,\n                        border: editAudience===v ? '1.5px solid #1877F2' : '1.5px solid #E4E6EB',\n                        background: editAudience===v ? '#E7F0FE' : '#fff', color: editAudience===v ? '#1877F2' : '#050505' }}>\n                      {ic} {lb}\n                    </button>\n                  ))}\n                </div>\n              </div>\n            )}\n            <button onClick={() => { openTagModal(editPost); }} style={{ width:'100%', marginTop:10, display:'flex', alignItems:'center', justifyContent:'center', gap:7, padding:'9px 0', borderRadius:12, border:'1.5px solid #E4E6EB', background:'#fff', cursor:'pointer', fontFamily:'Poppins', fontSize:13, fontWeight:600, color:'#1877F2' }}>\n              <HiUserAdd size={16}/> Identifier des amis\n            </button>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditPost(null)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\"   onClick={saveEditPost}            style={{ flex:1 }}>{t('save')}</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Edit comment modal */}\n      {editCmt && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:400, padding:20 }}>\n            <h3 style={{ marginBottom:12 }}>Modifier le commentaire</h3>\n            <textarea className=\"input\" rows={3} value={editCmt.text} onChange={e => setEditCmt(p=>({...p,text:e.target.value}))} style={{ resize:'none' }} maxLength={MAX_COMMENT}/>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditCmt(null)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\" onClick={() => saveEditCmt(editCmt.postId, editCmt.cmt, editCmt.text)} style={{ flex:1 }}>{t('save')}</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Reaction users modal */}\n      {reactionModal && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:820, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:360, padding:20, maxHeight:'70vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ color:'#1877F2', fontWeight:700 }}>R\u00e9actions</h3>\n              <button onClick={() => setRM(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {Object.entries(reactionModal.reactions).map(([uid, emoji]) => {\n              const info = reactionModal.userData?.[uid]||{};\n              return (\n                <div key={uid} onClick={() => { setRM(null); navigate(`/profile/${uid}`); }}\n                  style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom:'1px solid #E4E6EB', cursor:'pointer' }}>\n                  <img src={info.photo||`https://ui-avatars.com/api/?name=${encodeURIComponent(info.name||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                  <p style={{ fontSize:14, fontWeight:600, flex:1 }}>{uid===currentUser.uid?'Vous':(info.name||uid)}</p>\n                  <span style={{ fontSize:20 }}>{emoji}</span>\n                </div>\n              );\n            })}\n          </div>\n        </div>\n      )}\n\n      {/* Feed */}\n      {posts.filter(p => !(p.mediaType === 'audio' && p.isMusic)).slice(0, visibleCount).map((post, pIdx) => {\n        const rc     = countReactions(post.reactions);\n        const myR    = post.reactions?.[currentUser.uid];\n        const total  = Object.keys(post.reactions||{}).length;\n        const isOwn  = post.uid === currentUser.uid;\n        const boosted = post.isBoosted && post.boostUntil && new Date(post.boostUntil)>new Date();\n        const isMyFriend = isFriend(post.uid);\n        const sentReq    = hasSentReq(post.uid);\n\n        return (\n          <div key={post.id}>\n          {pIdx > 0 && pIdx % 5 === 0 && (\n            <MusicRow\n              onVoirTout={() => navigate('/artists')}\n              tracks={posts.filter(p => p.mediaType === 'audio' && p.isMusic)}\n              playingId={playingTrackId}\n              onToggle={toggleMusic}\n              onArtist={aid => aid && navigate(`/artists/${aid}`)}\n              onShare={setShareModalPost}\n              onFollow={toggleFollowArtist}\n              onMessage={aid => aid && navigate(`/artists/${aid}/messages`)}\n              followedArtists={followedArtists}\n              onSave={toggleSave}\n              onBlock={toggleBlockAuthor}\n              savedIds={userProfile?.saved || []}\n              blockedIds={userProfile?.blocked || []}\n            />\n          )}\n          {feedAds.length > 0 && pIdx > 0 && pIdx % 4 === 0 && (\n            <SponsoredPost ad={feedAds[(Math.floor(pIdx / 4) - 1) % feedAds.length]} />\n          )}\n          <div className=\"card post-card animate-fade\" style={{ marginBottom:14, border:boosted?'1px solid #a855f755':undefined }}>\n            {boosted && (\n              <div style={{ background:'linear-gradient(135deg,#7c3aed18,#a855f718)', borderBottom:'1px solid #a855f733', padding:'5px 14px' }}>\n                <span style={{ fontSize:10, color:'#a855f7', fontWeight:600 }}>\u26a1 Sponsoris\u00e9</span>\n              </div>\n            )}\n\n            {/* Header */}\n            <div style={{ padding:'14px 16px 0', display:'flex', alignItems:'center', justifyContent:'space-between' }}>\n              {post.groupName ? (\n                /* Pub de groupe : photo + nom du groupe (\u2192 groupe), auteur dessous (\u2192 profil) */\n                <div style={{ display:'flex', alignItems:'center', gap:10, flex:1, minWidth:0 }}>\n                  <div style={{ position:'relative', flexShrink:0, width:44, height:44 }}>\n                    <div onClick={() => navigate(`/groups/${post.groupId}`)} style={{ width:44, height:44, borderRadius:10, background:'linear-gradient(135deg,#1B84FF,#1877F2)', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', overflow:'hidden', boxShadow:'0 2px 8px rgba(24,119,242,.3)' }}>\n                      {post.groupPhoto\n                        ? <img src={post.groupPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>\n                        : <HiUserGroup size={22} color=\"white\"/>}\n                    </div>\n                    {/* Avatar an'ilay olona superpos\u00e9 (format Facebook) */}\n                    <img onClick={() => navigate(`/profile/${post.uid}`)}\n                      src={post.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName||'U')}&background=1877F2&color=fff`}\n                      alt=\"\" style={{ position:'absolute', bottom:-4, right:-4, width:22, height:22, borderRadius:'50%', objectFit:'cover', border:'2.5px solid white', cursor:'pointer', boxShadow:'0 1px 4px rgba(0,0,0,.25)' }}/>\n                  </div>\n                  <div style={{ minWidth:0 }}>\n                    <p onClick={() => navigate(`/groups/${post.groupId}`)} style={{ fontWeight:700, fontSize:14, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', cursor:'pointer' }}>{post.groupName}</p>\n                    <p style={{ fontSize:12, color:'#65676B' }}>\n                      <span onClick={() => navigate(`/profile/${post.uid}`)} style={{ cursor:'pointer', fontWeight:600, color:'#050505' }}>{post.authorName}</span>\n                      {post.authorIsVip&&<VIPBadge/>} \u00b7 {post.createdAt?timeAgo(post.createdAt):\"\u00c0 l'instant\"}\n                    </p>\n                  </div>\n                </div>) : post.artistId ? (\n                /* Pub de canal Artiste : photo + nom, clic \u2192 page artiste */\n                <div onClick={() => navigate(`/artists/${post.artistId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n                  <div style={{ width:44, height:44, borderRadius:'50%', background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                    {post.artistPhoto ? <img src={post.artistPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <NeonMic size={20} color=\"white\"/>}\n                  </div>\n                  <div style={{ minWidth:0 }}>\n                    <p style={{ fontWeight:700, fontSize:14, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{post.artistName} <span style={{ fontSize:10, fontWeight:800, color:'#FF2D8D' }}>\ud83c\udfa4</span></p>\n                    <p style={{ fontSize:12, color:'#65676B' }}>{post.genre} \u00b7 {post.createdAt?timeAgo(post.createdAt):\"\u00c0 l'instant\"}</p>\n                  </div>\n                </div>\n              ) : post.shopId ? (\n                /* Pub de Boutique : photo + nom, clic \u2192 page boutique */\n                <div onClick={() => navigate(`/shop/${post.shopId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n                  <div style={{ width:44, height:44, borderRadius:10, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                    {post.shopPhoto ? <img src={post.shopPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <HiShoppingBag size={22} color=\"white\"/>}\n                  </div>\n                  <div style={{ minWidth:0 }}>\n                    <p style={{ fontWeight:700, fontSize:14, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{post.shopName} <span style={{ fontSize:10, fontWeight:800, color:'#FF2D8D' }}>\ud83c\udfea</span></p>\n                    <p style={{ fontSize:12, color:'#65676B' }}>Boutique \u00b7 {post.createdAt?timeAgo(post.createdAt):\"\u00c0 l'instant\"}</p>\n                  </div>\n                </div>\n              ) : (\n                <div style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }} onClick={() => navigate(`/profile/${post.uid}`)}>\n                  <StoryRing active={activeStoryUids.has(post.uid)}>\n                    <img src={post.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:40, height:40, flexShrink:0 }}/>\n                  </StoryRing>\n                  <div style={{ minWidth:0 }}>\n                    <p style={{ fontWeight:600, fontSize:14, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{post.authorName}{post.authorIsVip&&<VIPBadge/>}</p>\n                    <p style={{ fontSize:12, color:'#65676B' }}>@{post.authorUsername} \u00b7 {post.createdAt?timeAgo(post.createdAt):\"\u00c0 l'instant\"}</p>\n                    {post.taggedNames?.length > 0 && <p style={{ fontSize:12, color:'#65676B' }}>avec {post.taggedNames.join(', ')}</p>}\n                    {(post.mood || post.location) && (\n                      <p style={{ fontSize:12, color:'#65676B' }}>\n                        {post.mood && <>{post.mood}</>}{post.mood && post.location ? ' \u00e0 ' : ''}{post.location && <>\ud83d\udccd {post.location}</>}\n                      </p>\n                    )}\n                  </div>\n                </div>\n              )}\n\n              <div style={{ display:'flex', alignItems:'center', gap:6, flexShrink:0 }}>\n                {post.isSale && !post.shopId && <div style={{ textAlign:'right' }}><span className=\"sale-badge\">{t('sale')}</span><p className=\"price-tag\" style={{ marginTop:2, fontSize:13 }}>{post.price} Ar</p></div>}\n                {!isOwn && (\n                  <button onClick={() => toggleFollowAuthor(post.uid, post.authorName)}\n                    style={{ background: isFollowingUid(post.uid) ? '#F0F2F5' : 'linear-gradient(135deg,#FFE066,#F2B300)', border:'none', borderRadius:20, padding:'5px 12px', cursor:'pointer', color: isFollowingUid(post.uid) ? '#65676B' : '#4A3400', fontSize:12, fontWeight:700, display:'flex', alignItems:'center', gap:4 }}>\n                    {isFollowingUid(post.uid) ? <><HiCheck size={13}/> Suivi</> : <><NeonStar size={13} color=\"#4A3400\"/> Suivre</>}\n                  </button>\n                )}\n                {!isOwn && !isMyFriend && !sentReq && (\n                  <button onClick={() => sendFriendReq(post.uid, post.authorName)}\n                    style={{ background:'none', border:'1px solid #E4E6EB', borderRadius:20, padding:'5px 10px', cursor:'pointer', color:'#65676B', fontSize:12, display:'flex', alignItems:'center', gap:4 }}>\n                    <HiUserAdd size={13}/> Ajouter\n                  </button>\n                )}\n\n                {/* 3-dot menu */}\n                <div style={{ position:'relative' }} onClick={e => e.stopPropagation()}>\n                  <button onClick={() => setPostMenu(postMenu===post.id?null:post.id)}\n                    style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4, display:'flex', alignItems:'center' }}><HiDotsVertical size={18}/></button>\n                  {postMenu === post.id && (\n                    <div style={{ position:'absolute', top:'100%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:14, boxShadow:'0 6px 24px rgba(0,0,0,.16)', minWidth:220, zIndex:50, overflow:'hidden' }}>\n                      {isOwn && <>\n                        <button onClick={() => { setEditPost(post); setEditContent(post.content); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14.5, fontWeight:400, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}><HiPencil size={17} color=\"#1877F2\"/> Modifier</button>\n                        {!post.groupId && !post.sharedFrom && <button onClick={() => { setBoostTarget({ type:'post', id: post.id, ownerUid: post.uid, title: post.content?.slice(0,60) || 'Votre publication', thumbnailURL: post.mediaURL || '' }); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14.5, fontWeight:400, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}><HiLightningBolt size={17} color=\"#a855f7\"/> Booster</button>}\n                      </>}\n                      <button onClick={() => { toggleSave(post.id); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14.5, fontWeight:400, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}>\n                        <HiBookmark size={17} color=\"#F2B300\"/> {(userProfile?.saved||[]).includes(post.id) ? 'Retirer' : 'Enregistrer'}\n                      </button>\n                      {isOwn && (\n                        <button onClick={() => { openTagModal(post); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14.5, fontWeight:400, fontFamily:'Poppins' }}>\n                          <HiUserAdd size={17} color=\"#1877F2\"/> Identifier\n                        </button>\n                      )}\n                      {isOwn && (\n                        <button onClick={() => { deletePost(post.id); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#FF2D8D', fontSize:14.5, fontWeight:400, borderTop:'1px solid #F0F2F5', fontFamily:'Poppins' }}>\n                          <HiTrash size={17}/> Supprimer\n                        </button>\n                      )}\n                      {!isOwn && (\n                        <>\n                          <button onClick={() => { reportPost(post); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14.5, fontWeight:400, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}>\n                            <HiFlag size={17} color=\"#F2B300\"/> Signaler\n                          </button>\n                          <button onClick={() => { toggleBlockAuthor(post); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'13px 18px', background:'none', border:'none', cursor:'pointer', color:'#FF2D8D', fontSize:14.5, fontWeight:400, fontFamily:'Poppins' }}>\n                            <HiBan size={17}/> {(userProfile?.blocked||[]).includes(post.uid) ? 'D\u00e9bloquer' : 'Bloquer'}\n                          </button>\n                        </>\n                      )}\n                    </div>\n                  )}\n                </div>\n              </div>\n            </div>\n\n            {/* Content */}\n            <div style={{ padding: post.textBg ? 0 : '10px 16px', cursor:'pointer' }} onClick={() => navigate(`/post/${post.id}`)}>\n              {post.content && (\n                <p\n                  onClick={e => {\n                    // Raha nisy s\u00e9lection texte (copie), tsy mandeha amin'ny post\n                    if (window.getSelection && window.getSelection().toString().length > 0) { e.stopPropagation(); return; }\n                  }}\n                  onContextMenu={e => { e.stopPropagation(); }}\n                  onPointerDown={e => startTextPress(e, post)}\n                  onPointerUp={endTextPress}\n                  onPointerLeave={endTextPress}\n                  style={ post.textBg ? { background: post.textBg, minHeight:200, display:'flex', alignItems:'center', justifyContent:'center', textAlign:'center', color:'#fff', fontSize:26, fontWeight:800, padding:'28px 20px', lineHeight:1.4, wordBreak:'break-word', whiteSpace:'pre-wrap', margin:0 } : { fontSize:15, lineHeight:1.6, wordBreak:'break-word', whiteSpace:'pre-wrap', userSelect:'text', WebkitUserSelect:'text', cursor:'text',\n                    ...(expandedPosts[post.id] ? {} : { display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }) } }\n                >{post.content}</p>\n              )}\n              {post.content && post.content.length > 90 && (\n                <button onClick={e => { e.stopPropagation(); setExpandedPosts(p => ({ ...p, [post.id]: !p[post.id] })); }}\n                  style={{ background:'none', border:'none', padding:'2px 0 0', cursor:'pointer', color:'#65676B', fontSize:14, fontWeight:600, fontFamily:'Poppins' }}>\n                  {expandedPosts[post.id] ? 'Voir moins' : 'Voir plus'}\n                </button>\n              )}\n              {post.isSale && !post.shopId && (post.contact||post.lieu) && (\n                <div style={{ marginTop:8, display:'flex', flexWrap:'wrap', gap:8 }}>\n                  {post.contact && <a href={`tel:${post.contact}`} onClick={e=>e.stopPropagation()} style={{ display:'flex', alignItems:'center', gap:5, background:'#E4E6EB', borderRadius:20, padding:'5px 12px', color:'#1877F2', fontSize:13, fontWeight:600, textDecoration:'none' }}><HiPhone size={13}/>{post.contact}</a>}\n                  {post.lieu   && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#F0F2F5', borderRadius:20, padding:'5px 12px', color:'#65676B', fontSize:13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n                </div>\n              )}\n              {/* Publication partag\u00e9e (format Facebook) */}\n              {post.sharedFrom && (\n                <div onClick={e => { e.stopPropagation(); navigate(`/post/${post.sharedFrom.id}`); }}\n                  style={{ marginTop:8, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', cursor:'pointer' }}>\n                  <div style={{ display:'flex', alignItems:'center', gap:8, padding:'9px 12px' }}>\n                    <img src={post.sharedFrom.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.sharedFrom.authorName||'U')}&background=1877F2&color=fff`}\n                      alt=\"\" style={{ width:30, height:30, borderRadius:'50%', objectFit:'cover' }}/>\n                    <p style={{ fontWeight:700, fontSize:13 }}>{post.sharedFrom.groupName ? `${post.sharedFrom.groupName} \u00b7 ${post.sharedFrom.authorName}` : post.sharedFrom.authorName}</p>\n                  </div>\n                  {post.sharedFrom.content && <p style={{ padding:'0 12px 8px', fontSize:13, color:'#050505' }}>{post.sharedFrom.content}</p>}\n                  {post.sharedFrom.mediaURL && (\n                    post.sharedFrom.isMusic\n                      ? <div style={{ padding:'0 10px 10px' }}><MusicPostCard post={post.sharedFrom} height={115}/></div>\n                      : post.sharedFrom.mediaType === 'image'\n                        ? <img src={post.sharedFrom.mediaURL} alt=\"\" style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block' }}/>\n                        : <video src={post.sharedFrom.mediaURL} muted playsInline style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block', background:'#000' }}/>\n                  )}\n                </div>\n              )}\n              {post.eventFrom && (\n                <div onClick={e => { e.stopPropagation(); navigate('/events'); }}\n                  style={{ marginTop:8, border:'1.5px solid #12A48D', borderRadius:12, overflow:'hidden', cursor:'pointer' }}>\n                  {post.eventFrom.coverURL && <img src={post.eventFrom.coverURL} alt=\"\" style={{ width:'100%', height:140, objectFit:'cover', display:'block' }}/>}\n                  <div style={{ padding:'10px 12px', background:'#EAFBF8' }}>\n                    <p style={{ fontSize:11, fontWeight:800, color:'#12A48D', display:'flex', alignItems:'center', gap:5 }}>\ud83d\udcc5 \u00c9V\u00c9NEMENT</p>\n                    <p style={{ fontWeight:800, fontSize:15, marginTop:2 }}>{post.eventFrom.title}</p>\n                    <p style={{ fontSize:12, color:'#65676B', marginTop:2 }}>\n                      {new Date(post.eventFrom.date).toLocaleString('fr-FR', { weekday:'short', day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' })}\n                      {post.eventFrom.lieu ? ` \u00b7 ${post.eventFrom.lieu}` : ''}\n                    </p>\n                  </div>\n                </div>\n              )}\n              {post.mediaURLs?.length > 1 ? (\n                <div style={{ marginTop:8, marginLeft:-16, marginRight:-16 }}>\n                  <PhotoCarousel urls={post.mediaURLs} onOpen={() => navigate(`/post/${post.id}`)} />\n                </div>\n              ) : post.mediaURL && (\n                <div style={{ marginTop:8, marginLeft:-16, marginRight:-16 }}>\n                  {post.isMusic ? <MusicPostCard post={post} height={140}/> : post.mediaType==='image' ? <img src={post.mediaURL} alt=\"\" onClick={e=>{e.stopPropagation();navigate(`/post/${post.id}`);}} style={{ width:'100%', borderRadius:0, maxHeight:520, objectFit:'cover', display:'block', cursor:'zoom-in' }}/> : <FeedVideo src={post.mediaURL} poster={post.thumbURL} dataSaver={dataSaver} onOpenReels={()=>navigate('/reels',{state:{startId:post.id}})} style={{ width:'100%', borderRadius:0, maxHeight:520, objectFit:'cover', display:'block', background:'#000' }} />}\n                </div>\n              )}\n              {/* \u2500\u2500 Article boutique : informations ambanin'ny sary (sary 3) \u2500\u2500 */}\n              {post.shopId && post.isSale && (\n                <div onClick={e => e.stopPropagation()} style={{ marginTop:10 }}>\n                  <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10 }}>\n                    <span style={{ fontWeight:800, fontSize:20, color:'#FF2D8D' }}>{post.price ? `${Number(post.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                    <button onClick={() => navigate(`/shop/${post.shopId}/messages`)}\n                      style={{ display:'flex', alignItems:'center', gap:5, background:'#fff', border:'1.5px solid #FF2D8D', borderRadius:20, padding:'7px 16px', fontSize:13, fontWeight:700, color:'#FF2D8D', cursor:'pointer', flexShrink:0 }}>\n                      <NeonPlane size={15}/> Message\n                    </button>\n                  </div>\n                  {(post.lieu || post.contact) && (\n                    <div style={{ display:'flex', alignItems:'center', flexWrap:'wrap', gap:8, marginTop:8, paddingTop:8, borderTop:'1px solid #F0F2F5' }}>\n                      {post.lieu && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#F0F2F5', borderRadius:20, padding:'5px 12px', color:'#65676B', fontSize:13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n                      {post.contact && <a href={`tel:${String(post.contact).split(/[\\/,;|]/)[0].trim()}`} style={{ display:'flex', alignItems:'center', gap:5, background:'#E4E6EB', borderRadius:20, padding:'5px 12px', color:'#1877F2', fontSize:13, fontWeight:600, textDecoration:'none' }}><HiPhone size={13}/>{post.contact}</a>}\n                    </div>\n                  )}\n                  <button onClick={() => { const ok = addToCart(post); alert(ok ? 'Article ajout\u00e9 au panier \ud83d\uded2' : 'Cet article est d\u00e9j\u00e0 dans votre panier'); }}\n                    style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:7, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'none', borderRadius:20, padding:'10px 0', marginTop:10, fontSize:14, fontWeight:800, color:'#fff', cursor:'pointer', fontFamily:'Poppins' }}>\n                    <HiShoppingCart size={17}/> Ajouter au panier\n                  </button>\n                </div>\n              )}\n            </div>\n\n            {/* R\u00e9sum\u00e9 r\u00e9actions \u00b7 commentaires (format Facebook) */}\n            {(total > 0 || post.comments?.length > 0 || (post.views||0) > 0) && (\n              <div style={{ padding:'8px 16px 6px', display:'flex', alignItems:'center', justifyContent:'space-between', gap:8 }}>\n                <div onClick={() => openReactionModal(post)} style={{ display:'flex', alignItems:'center', gap:4, cursor:'pointer', minHeight:18, minWidth:0, flex:1 }}>\n                  {total > 0 && (() => {\n                    const rUids = Object.keys(post.reactions||{});\n                    const meIn = rUids.includes(currentUser?.uid);\n                    const otherUid = rUids.find(u => u !== currentUser?.uid);\n                    const firstName = meIn ? 'Vous' : (reactorNames[otherUid] || '');\n                    const rest = total - 1;\n                    const sortedEmojis = Object.entries(rc).sort((a,b) => b[1]-a[1]).slice(0,3).map(([e]) => e);\n                    return <>\n                      <div style={{ display:'flex', gap:3, flexShrink:0 }}>\n                        {sortedEmojis.map(e =>\n                          <span key={e} style={{ fontSize:14, background:'white', borderRadius:'50%', boxShadow:'0 0 0 1.5px white', lineHeight:1 }}>{e}</span>)}\n                      </div>\n                      <span style={{ fontSize:12.5, color:'#65676B', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>\n                        {firstName\n                          ? (rest > 0 ? `${firstName} et ${rest} autre${rest>1?'s':''} personne${rest>1?'s':''} ont r\u00e9agi \u00e0 la publication` : `${firstName} a r\u00e9agi \u00e0 la publication`)\n                          : `${total} r\u00e9action${total>1?'s':''}`}\n                      </span>\n                    </>;\n                  })()}\n                </div>\n                <div style={{ display:'flex', alignItems:'center', gap:10, flexShrink:0 }}>\n                  {(post.views||0) > 0 && (\n                    <span style={{ fontSize:12.5, color:'#8A8D91', display:'flex', alignItems:'center', gap:4 }}>\n                      <NeonEye size={14}/> {post.views > 999 ? (post.views/1000).toFixed(1)+' k' : post.views}\n                    </span>\n                  )}\n                  {post.comments?.length > 0 && (\n                    <span onClick={(e) => { e.stopPropagation(); navigate('/post/' + post.id); }} style={{ fontSize:12.5, color:'#65676B', cursor:'pointer' }}>\n                      {post.comments.length} commentaire{post.comments.length>1?'s':''}\n                    </span>\n                  )}\n                </div>\n              </div>\n            )}\n\n            {/* Actions : J'aime \u00b7 Commenter \u00b7 Partager (format Facebook) */}\n            <div className='post-actions-row'>\n              <div style={{ position:'relative', flex:1, display:'flex' }}>\n                <button\n                  onClick={() => quickLike(post)}\n                  onTouchStart={() => startLongPress(post.id)} onTouchEnd={endLongPress}\n                  onMouseDown={() => startLongPress(post.id)} onMouseUp={endLongPress} onMouseLeave={endLongPress}\n                  className={'post-action-btn'+(myR?' active':'')}\n                  style={myR ? { color:'#FF2D8D', fontWeight:700 } : {}}>\n                  {myR\n                    ? <span style={{ fontSize:18, lineHeight:1 }}>{myR}</span>\n                    : <NeonLike size={19} color={'#65676B'}/>}\n                  {' '}{myR ? (FB_REACTIONS.find(r => r.emoji === myR)?.label || \"J'aime\") : \"J'aime\"}\n                </button>\n                {showReact[post.id] && (\n                  <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', bottom:'calc(100% + 8px)', left:0, background:'white', borderRadius:20, padding:'10px 8px 6px', display:'flex', gap:4, boxShadow:'0 4px 24px rgba(0,0,0,.18)', zIndex:50, border:'1px solid #E4E6EB', whiteSpace:'nowrap' }}>\n                    {FB_REACTIONS.map(r => (\n                      <button key={r.emoji}\n                        onClick={() => { reactToPost(post.id, r.emoji); setShowReact(p=>({...p,[post.id]:false})); }}\n                        style={{ background:'none', border:'none', cursor:'pointer', display:'flex', flexDirection:'column', alignItems:'center', gap:3, padding:'0 4px', minWidth:44 }}>\n                        <span style={{ fontSize:28, lineHeight:1, transition:'transform .15s', display:'block' }}\n                          onMouseEnter={ev=>ev.currentTarget.style.transform='scale(1.35) translateY(-4px)'}\n                          onMouseLeave={ev=>ev.currentTarget.style.transform='scale(1)'}\n                          onTouchStart={ev=>ev.currentTarget.style.transform='scale(1.35) translateY(-4px)'}\n                          onTouchEnd={ev=>ev.currentTarget.style.transform='scale(1)'}\n                        >{r.emoji}</span>\n                        <span style={{ fontSize:10, color:'#65676B', fontWeight:600, fontFamily:'Poppins' }}>{r.label}</span>\n                      </button>\n                    ))}\n                  </div>\n                )}\n              </div>\n              <button onClick={() => navigate('/post/' + post.id)} className='post-action-btn'>\n                <NeonComment size={18}/> Commenter\n              </button>\n              <button onClick={() => sharePost(post)} className='post-action-btn'>\n                <NeonShare size={18}/> Partager\n              </button>\n            </div>\n\n            {post.uid === currentUser.uid && !post.isBoosted && (\n              <div style={{ padding:'0 14px 12px' }}>\n                <button\n                  onClick={() => setBoostTarget({ type:'post', id: post.id, ownerUid: post.uid, title: post.content?.slice(0,60) || 'Votre publication', thumbnailURL: post.mediaURL || '' })}\n                  style={{ width:'100%', padding:'9px 0', borderRadius:20, border:'none', background:'linear-gradient(135deg,#1B84FF,#1877F2)', color:'white', fontWeight:700, fontSize:13, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:6, fontFamily:'Poppins' }}>\n                  <HiTrendingUp size={16}/> Booster la publication\n                </button>\n              </div>\n            )}\n\n            {/* Comments */}\n            {openCmt[post.id] && (\n              <div style={{ padding:'0 16px 14px', borderTop:'1px solid #E4E6EB' }}>\n                {post.comments?.map(c => {\n                  const myCR = c.reactions?.[currentUser.uid];\n                  const crCount = Object.keys(c.reactions||{}).length;\n                  return (\n                  <div key={c.id} style={{ display:'flex', gap:8, marginTop:10 }}>\n                    <img src={c.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(c.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:32, height:32, flexShrink:0, cursor:'pointer' }} onClick={() => navigate(`/profile/${c.uid}`)}/>\n                    <div style={{ flex:1, minWidth:0 }}>\n                      {/* Bulle (format Facebook) */}\n                      <div style={{ position:'relative', display:'inline-block', maxWidth:'100%', background:'#F0F2F5', borderRadius:16, padding:'8px 12px' }}>\n                        <p style={{ fontWeight:700, fontSize:13 }}>{c.authorName}{c.authorIsVip&&<VIPBadge/>}</p>\n                        {c.text&&<p style={{ fontSize:14, wordBreak:'break-word' }}>{c.text}</p>}\n                        {c.mediaURL&&<div style={{ marginTop:4 }}>{c.mediaType==='image'?<img src={c.mediaURL} alt=\"\" style={{ maxWidth:200, borderRadius:8 }}/>:<video src={c.mediaURL} controls style={{ maxWidth:200, borderRadius:8 }}/>}</div>}\n                        {crCount > 0 && (\n                          <span style={{ position:'absolute', bottom:-10, right:4, background:'white', borderRadius:12, padding:'1px 6px', fontSize:12, boxShadow:'0 1px 4px rgba(0,0,0,.25)', display:'flex', alignItems:'center', gap:2 }}>\n                            {[...new Set(Object.values(c.reactions))].slice(0,3).join('')}\n                            {crCount > 1 && <span style={{ fontSize:10, color:'#65676B' }}>{crCount}</span>}\n                          </span>\n                        )}\n                      </div>\n                      {/* Liens sous la bulle (format Facebook) */}\n                      <div style={{ display:'flex', gap:14, padding:'4px 12px 0', fontSize:12, fontWeight:700, color:'#65676B', position:'relative', alignItems:'center' }}>\n                        <span onClick={() => reactToCmt(post.id, c.id, '\u2764\ufe0f')}\n                          style={{ cursor:'pointer', color: myCR ? '#FF2D8D' : '#65676B', fontWeight: myCR ? 700 : 400 }}>\n                          {myCR && myCR !== '\u2764\ufe0f' ? myCR + ' ' : ''}J'aime\n                        </span>\n                        <span onClick={() => setCmtReactionPicker(p => p===c.id?null:c.id)} style={{ cursor:'pointer' }}>\ud83d\ude0a</span>\n                        <span onClick={() => setReplyTo(p=>({...p,[post.id]:c.authorName}))} style={{ cursor:'pointer' }}>R\u00e9pondre</span>\n                        {c.uid===currentUser.uid && (\n                          <span onClick={() => setEditCmt({ postId:post.id, cmt:c, text:c.text })} style={{ cursor:'pointer' }}>Modifier</span>\n                        )}\n                        {(c.uid===currentUser.uid||post.uid===currentUser.uid) && (\n                          <span onClick={() => deleteCmt(post.id,c)} style={{ cursor:'pointer', color:'#FF2D8D' }}>Supprimer</span>\n                        )}\n                        {cmtReactionPicker===c.id && (\n                          <div style={{ display:'flex', gap:6, background:'white', borderRadius:20, padding:'6px 10px', boxShadow:'0 2px 12px rgba(0,0,0,.2)', position:'absolute', bottom:'110%', left:0, zIndex:10, border:'1px solid #E4E6EB' }}>\n                            {REACTIONS.map(em=><span key={em} onClick={()=>reactToCmt(post.id,c.id,em)} style={{ fontSize:20, cursor:'pointer' }}>{em}</span>)}\n                          </div>\n                        )}\n                      </div>\n                    </div>\n                  </div>\n                  );\n                })}\n\n                {replyTo[post.id] && (\n                  <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:8, background:'#F0F2F5', padding:'6px 10px', borderRadius:10 }}>\n                    <HiReply size={14} color=\"#1877F2\"/>\n                    <span style={{ fontSize:12, color:'#65676B' }}>R\u00e9pondre \u00e0 <strong>{replyTo[post.id]}</strong></span>\n                    <button onClick={() => setReplyTo(p=>({...p,[post.id]:null}))} style={{ marginLeft:'auto', background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={14}/></button>\n                  </div>\n                )}\n\n                {cmtMedia[post.id] && (\n                  <div style={{ position:'relative', marginTop:8, display:'inline-block' }}>\n                    {cmtMedia[post.id].type==='image'?<img src={cmtMedia[post.id].preview} alt=\"\" style={{ maxWidth:150, borderRadius:8 }}/>:<video src={cmtMedia[post.id].preview} style={{ maxWidth:150, borderRadius:8 }}/>}\n                    <button onClick={() => setCmtMedia(p=>({...p,[post.id]:null}))} style={{ position:'absolute', top:2, right:2, background:'rgba(0,0,0,.5)', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', color:'white', fontSize:10 }}>\u2715</button>\n                  </div>\n                )}\n\n                <div style={{ display:'flex', gap:6, marginTop:10, alignItems:'center' }}>\n                  <img src={userProfile?.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:30, height:30, flexShrink:0 }}/>\n                  <input ref={el=>cPhotoRef.current[post.id]=el} type=\"file\" accept=\"image/jpeg,image/png,image/gif,image/webp\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia(p=>({...p,[post.id]:{file:f,type:'image',preview:URL.createObjectURL(f)}}));}}/>\n                  <input ref={el=>cVideoRef.current[post.id]=el} type=\"file\" accept=\"video/mp4,video/webm,video/quicktime\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia(p=>({...p,[post.id]:{file:f,type:'video',preview:URL.createObjectURL(f)}}));}}/>\n                  <div style={{ flex:1, position:'relative', minWidth:0 }}>\n                    <input className=\"input\" placeholder={replyTo[post.id]?`R\u00e9pondre \u00e0 ${replyTo[post.id]}...`:t('writeComment')} value={cmtText[post.id]||''}\n                      onChange={e=>{\n                        const v = e.target.value;\n                        setCmtText(p=>({...p,[post.id]:v}));\n                        const mAt = v.match(/@([\\p{L}0-9_-]*)$/u);\n                        if (mAt) { loadMentionFriends(); setMentionQuery({ postId: post.id, q: mAt[1].toLowerCase() }); }\n                        else setMentionQuery(null);\n                      }}\n                      onKeyDown={e=>e.key==='Enter'&&!mentionQuery&&addComment(post.id)} style={{ width:'100%', padding:'7px 12px', fontSize:13 }} maxLength={MAX_COMMENT}/>\n                    {mentionQuery?.postId === post.id && (() => {\n                      const opts = mentionFriends.filter(f => f.fullName.toLowerCase().includes(mentionQuery.q)).slice(0,5);\n                      if (!opts.length) return null;\n                      return (\n                        <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', bottom:'110%', left:0, right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 6px 20px rgba(0,0,0,.15)', zIndex:60, overflow:'hidden' }}>\n                          {opts.map(f => (\n                            <button key={f.uid} onClick={() => {\n                                setCmtText(prev => ({ ...prev, [post.id]: (prev[post.id]||'').replace(/@([\\p{L}0-9_-]*)$/u, '@'+f.fullName.split(' ')[0]+' ') }));\n                                setMentionQuery(null);\n                              }}\n                              style={{ width:'100%', display:'flex', alignItems:'center', gap:8, padding:'9px 12px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:13, color:'#050505', borderBottom:'1px solid #F0F2F5', textAlign:'left' }}>\n                              <HiAtSymbol size={14} color=\"#1877F2\"/> {f.fullName}\n                            </button>\n                          ))}\n                        </div>\n                      );\n                    })()}\n                  </div>\n                  <button onClick={() => cPhotoRef.current[post.id]?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiPhotograph size={18}/></button>\n                  <button onClick={() => cVideoRef.current[post.id]?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiVideoCamera size={18}/></button>\n                  <button onClick={() => addComment(post.id)} style={{ background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:'50%', width:32, height:32, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\u27a4</button>\n                </div>\n              </div>\n            )}\n          </div>\n\n          {/* Suggestions boutique toutes les 8 publications */}\n          {(pIdx + 1) % 8 === 0 && shopSuggestions.length > 0 && (() => {\n            const shopOff = (Math.floor((pIdx + 1) / 8) - 1) * 4 % shopSuggestions.length;\n            const shopChunk = [...shopSuggestions.slice(shopOff), ...shopSuggestions.slice(0, shopOff)].slice(0, 4);\n            return (\n              <div className=\"card post-card\" style={{ marginBottom:14, padding:'12px 0' }}>\n                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 16px 10px' }}>\n                  <p style={{ fontWeight:700, fontSize:15, margin:0 }}>Boutiques \u00e0 d\u00e9couvrir</p>\n                  <button onClick={() => navigate('/shop')} style={{ background:'none', border:'none', color:'#1877F2', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>Voir tout</button>\n                </div>\n                <div style={{ display:'flex', gap:10, overflowX:'auto', padding:'0 16px 4px', scrollbarWidth:'none' }}>\n                  {shopChunk.map(sh => (\n                    <div key={sh.id} onClick={() => navigate(`/shop/${sh.id}`)} style={{ flexShrink:0, width:140, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', background:'white', cursor:'pointer' }}>\n                      <div style={{ width:'100%', height:80, background:'linear-gradient(135deg,#FF2D8D,#FF6BB5)', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>\n                        {sh.photoURL\n                          ? <img src={sh.photoURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>\n                          : <HiShoppingBag size={28} color=\"white\"/>}\n                      </div>\n                      <div style={{ padding:'8px 8px 10px' }}>\n                        <p style={{ fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{sh.name}</p>\n                        <p style={{ fontSize:11, color:'#65676B' }}>{sh.category || 'Boutique'}</p>\n                        <button className=\"btn-blue\" style={{ width:'100%', marginTop:6, padding:'6px 0', fontSize:12, borderRadius:8 }}>Voir la boutique</button>\n                      </div>\n                    </div>\n                  ))}\n                </div>\n              </div>\n            );\n          })()}\n\n          {/* Suggestions en rotation toutes les 10 publications : amis \u2192 groupes \u2192 stories */}\n          {(pIdx + 1) % 10 === 0 && (() => {\n            const slot = Math.floor((pIdx + 1) / 10) - 1;\n            const grpSugg = pageGroups.filter(g => !g.members?.includes(currentUser.uid));\n            let kind = ['amis', 'groupes', 'stories'][slot % 3];\n            if (kind === 'groupes' && grpSugg.length === 0) kind = 'amis';\n            if (kind === 'stories' && storyGroups.length === 0) kind = 'amis';\n            if (kind === 'amis' && suggestions.length === 0) return null;\n\n            if (kind === 'groupes') {\n              return (\n                <div className=\"card post-card\" style={{ marginBottom:14, padding:'12px 0' }}>\n                  <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 16px 10px' }}>\n                    <p style={{ fontWeight:700, fontSize:15, margin:0 }}>Groupes que vous pourriez rejoindre</p>\n                    <button onClick={() => navigate('/groups')} style={{ background:'none', border:'none', color:'#1877F2', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>Voir tout</button>\n                  </div>\n                  <div style={{ display:'flex', gap:10, overflowX:'auto', padding:'0 16px 4px', scrollbarWidth:'none' }}>\n                    {grpSugg.slice(0, 8).map(g => (\n                      <div key={g.id} onClick={() => navigate(`/groups/${g.id}`)} style={{ flexShrink:0, width:150, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', background:'white', cursor:'pointer' }}>\n                        <div style={{ width:'100%', height:82, background:'linear-gradient(135deg,#1B84FF,#1877F2)', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>\n                          {g.photoURL\n                            ? <img src={g.photoURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>\n                            : <HiUserGroup size={30} color=\"white\"/>}\n                        </div>\n                        <div style={{ padding:'8px 8px 10px' }}>\n                          <p style={{ fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{g.name}</p>\n                          <p style={{ fontSize:11, color:'#65676B' }}>{g.members?.length || 0} membre{(g.members?.length||0)>1?'s':''}</p>\n                          <button className=\"btn-blue\" style={{ width:'100%', marginTop:6, padding:'7px 0', fontSize:12, borderRadius:8 }}>Voir le groupe</button>\n                        </div>\n                      </div>\n                    ))}\n                  </div>\n                </div>\n              );\n            }\n\n            if (kind === 'stories') {\n              return (\n                <div className=\"card post-card\" style={{ marginBottom:14, padding:'12px 0' }}>\n                  <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 16px 10px' }}>\n                    <p style={{ fontWeight:700, fontSize:15, margin:0 }}>Stories</p>\n                    <button onClick={() => navigate('/', { state: { scrollToStories: true } })} style={{ background:'none', border:'none', color:'#1877F2', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>Voir tout</button>\n                  </div>\n                  <div style={{ display:'flex', gap:8, overflowX:'auto', padding:'0 16px 4px', scrollbarWidth:'none' }}>\n                    {storyGroups.slice(0, 10).map(g => {\n                      const last = g.items[g.items.length - 1];\n                      return (\n                        <div key={g.uid} className=\"story-card\" onClick={() => openStories(g)} style={{ width:92, height:150 }}>\n                          {last.mediaType === 'video'\n                            ? <video src={last.mediaURL} muted playsInline preload=\"metadata\" />\n                            : <img src={last.mediaURL} alt=\"\" />}\n                          <div className=\"story-gradient\" />\n                          <img className=\"story-avatar\" src={g.photo || `https://ui-avatars.com/api/?name=${encodeURIComponent(g.name||'U')}&background=1877F2&color=fff`} alt=\"\" />\n                          <span className=\"story-name\">{g.uid === currentUser.uid ? 'Votre story' : g.name?.split(' ')[0]}</span>\n                        </div>\n                      );\n                    })}\n                  </div>\n                </div>\n              );\n            }\n\n            const off = (slot * 6) % suggestions.length;\n            const chunk = [...suggestions.slice(off), ...suggestions.slice(0, off)].slice(0, 8);\n            return (\n              <div className=\"card post-card\" style={{ marginBottom:14, padding:'12px 0' }}>\n                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 16px 10px' }}>\n                  <p style={{ fontWeight:700, fontSize:15, margin:0 }}>Personnes que vous connaissez peut-\u00eatre</p>\n                  <button onClick={() => navigate('/friends')} style={{ background:'none', border:'none', color:'#1877F2', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins' }}>Voir tout</button>\n                </div>\n                <div style={{ display:'flex', gap:10, overflowX:'auto', padding:'0 16px 4px', scrollbarWidth:'none' }}>\n                  {chunk.map(u => (\n                    <div key={u.uid} style={{ flexShrink:0, width:136, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', background:'white' }}>\n                      <img src={u.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(u.fullName)}&background=1877F2&color=fff`}\n                        alt=\"\" onClick={() => navigate(`/profile/${u.uid}`)}\n                        style={{ width:'100%', height:110, objectFit:'cover', cursor:'pointer', display:'block' }} />\n                      <div style={{ padding:'8px 8px 10px' }}>\n                        <p onClick={() => navigate(`/profile/${u.uid}`)} style={{ fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', cursor:'pointer' }}>{u.fullName}</p>\n                        {hasSentReq(u.uid)\n                          ? <button onClick={() => cancelFriendReq(u.uid)} className=\"btn-secondary\" style={{ width:'100%', marginTop:6, padding:'7px 0', fontSize:12, borderRadius:8 }}>Annul\u00e9</button>\n                          : <button onClick={() => sendFriendReq(u.uid, u.fullName)} className=\"btn-blue\" style={{ width:'100%', marginTop:6, padding:'7px 0', fontSize:12, borderRadius:8, display:'flex', alignItems:'center', justifyContent:'center', gap:5 }}>\n                              <HiUserAdd size={14}/> Ajouter\n                            </button>}\n                      </div>\n                    </div>\n                  ))}\n                </div>\n              </div>\n            );\n          })()}\n          </div>\n        );\n      })}\n\n      {audienceEditPost && (\n        <div onClick={() => setAudienceEditPost(null)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:320, display:'flex', alignItems:'flex-end', justifyContent:'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'#fff', borderRadius:'18px 18px 0 0', width:'100%', maxWidth:480, overflow:'hidden', fontFamily:'Poppins' }}>\n            <p style={{ fontWeight:800, fontSize:16, padding:'16px 20px 8px' }}>Qui peut voir cette publication ?</p>\n            {[['public','\ud83c\udf0d Public'],['friends','\ud83d\udc65 Amis'],['me','\ud83d\udd12 Moi uniquement']].map(([v,l]) => (\n              <button key={v} onClick={async () => { try { await updateDoc(doc(db,'posts',audienceEditPost.id), { audience: v }); } catch(e) { alert('Erreur : '+(e?.message||e)); } setAudienceEditPost(null); }}\n                style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderTop:'1px solid #F0F2F5', fontFamily:'Poppins' }}>\n                <span>{l}</span>\n                {(audienceEditPost.audience || 'public') === v && <span style={{ color:'#1877F2', fontWeight:800 }}>\u2713</span>}\n              </button>\n            ))}\n          </div>\n        </div>\n      )}\n\n\n      {posts.filter(p => !(p.mediaType === 'audio' && p.isMusic)).length > visibleCount && (\n        <div ref={el => {\n          if (!el) return;\n          const io = new IntersectionObserver(es => { if (es[0].isIntersecting) setVisibleCount(c => c + 10); }, { rootMargin: '400px' });\n          io.observe(el);\n        }} style={{ padding: 18, textAlign: 'center', color: '#65676B', fontSize: 13 }}>\n          Chargement\u2026\n        </div>\n      )}\n\n      {shareModalPost && <ShareModal post={shareModalPost} onClose={() => setShareModalPost(null)} />}\n\n      {/* \u2500\u2500 Bottom sheet : Plus d'options (format \"Cr\u00e9er une publication\" Facebook) \u2500\u2500 */}\n      {composerMoreOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setComposerMoreOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:'8px 0 20px', width:'100%', maxWidth:480 }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'10px 20px 14px' }}>\n              <h3 style={{ fontWeight:800, fontSize:16 }}>Plus d'options</h3>\n              <button onClick={() => setComposerMoreOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {[\n              { icon:<HiUserAdd size={20} color=\"#1877F2\"/>, label:'Identifier des personnes', action:() => { setComposerMoreOpen(false); openComposerTagModal(); } },\n              { icon:<NeonLocation size={20}/>, label: postLocation ? `Lieu : ${postLocation}` : 'Ajouter un lieu', action:() => { setComposerMoreOpen(false); setLocationPromptOpen(true); } },\n              { icon:<span style={{ fontSize:20 }}>\ud83d\ude0a</span>, label: postMood || 'Humeur / Activit\u00e9', action:() => { setComposerMoreOpen(false); setMoodPickerOpen(true); } },\n              { icon:<HiPaperAirplane size={20} color=\"#1877F2\"/>, label: allowMessages ? 'Recevoir des messages : Activ\u00e9' : 'Recevoir des messages : D\u00e9sactiv\u00e9', action:() => setAllowMessages(p => !p) },\n              { icon:<span className=\"icon-badge-3d\" style={{ width:26, height:26, borderRadius:8, background:'linear-gradient(145deg,#3DD9C4,#12A48D)', display:'inline-flex' }}><HiCalendar size={14} color=\"white\"/></span>, label:'Cr\u00e9er un \u00e9v\u00e9nement', action:() => { setComposerMoreOpen(false); navigate('/events'); } },\n              { icon:<span className=\"icon-badge-3d\" style={{ width:26, height:26, borderRadius:8, background:'linear-gradient(145deg,#FF6B6B,#E0242D)', display:'inline-flex' }}><HiVideoCamera size={14} color=\"white\"/></span>, label:'Lancer un direct', action:() => { setComposerMoreOpen(false); alert(\"Le Live arrive bient\u00f4t sur Trengo \u2014 une infrastructure vid\u00e9o d\u00e9di\u00e9e est en pr\u00e9paration. En attendant, essayez une Story ou un Reel !\"); } },\n            ].map((item, i) => (\n              <button key={i} onClick={item.action} style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'13px 20px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:15, fontWeight:600, color:'#050505', textAlign:'left' }}>\n                {item.icon} {item.label}\n              </button>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Prompt : Ajouter un lieu \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {locationPromptOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:410, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }} onClick={() => setLocationPromptOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:18, padding:20, width:'100%', maxWidth:360 }}>\n            <h3 style={{ fontWeight:800, fontSize:15, marginBottom:12 }}>\ud83d\udccd Ajouter un lieu</h3>\n            <input className=\"input\" autoFocus placeholder=\"O\u00f9 \u00eates-vous ?\" value={postLocation} onChange={e => setPostLocation(e.target.value)} maxLength={100} style={{ marginBottom:14 }}/>\n            <button onClick={() => setLocationPromptOpen(false)} className=\"btn-primary\" style={{ width:'100%', padding:'10px 0', fontSize:14 }}>OK</button>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 S\u00e9lecteur : Humeur / Activit\u00e9 \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {moodPickerOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:410, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setMoodPickerOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480 }}>\n            <h3 style={{ fontWeight:800, fontSize:15, marginBottom:12 }}>Comment vous sentez-vous ?</h3>\n            {MOODS.map(m => (\n              <button key={m} onClick={() => { setPostMood(m); setMoodPickerOpen(false); }}\n                style={{ width:'100%', textAlign:'left', padding:'11px 6px', background:'none', border:'none', borderBottom:'1px solid #F0F2F5', cursor:'pointer', fontSize:15, fontFamily:'Poppins' }}>\n                {m}\n              </button>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Identifier des amis (avant publication) \u2500\u2500\u2500\u2500 */}\n      {composerTagOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:410, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setComposerTagOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480, maxHeight:'75vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ fontWeight:800, fontSize:16 }}>Identifier des amis</h3>\n              <button onClick={() => setComposerTagOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {composerTagList.length === 0 && <p style={{ fontSize:13, color:'#65676B', textAlign:'center', padding:'16px 0' }}>Vous n'avez pas encore d'amis \u00e0 identifier.</p>}\n            {composerTagList.map(f => (\n              <label key={f.uid} style={{ display:'flex', alignItems:'center', gap:10, padding:'9px 4px', cursor:'pointer', borderBottom:'1px solid #F0F2F5' }}>\n                <input type=\"checkbox\" checked={!!composerTagSel[f.uid]} onChange={e => setComposerTagSel(p => ({ ...p, [f.uid]: e.target.checked }))} style={{ width:18, height:18, accentColor:'#1877F2' }}/>\n                <img src={f.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(f.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                <p style={{ fontWeight:600, fontSize:14 }}>{f.fullName}</p>\n              </label>\n            ))}\n            <button onClick={() => setComposerTagOpen(false)} className=\"btn-primary\" style={{ width:'100%', marginTop:14, padding:'11px 0', fontSize:14 }}>OK</button>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Identifier des amis \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {tagModalPost && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setTagModalPost(null)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480, maxHeight:'75vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ fontWeight:800, fontSize:16 }}>Identifier des amis</h3>\n              <button onClick={() => setTagModalPost(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {tagFriendsList.length === 0 && <p style={{ fontSize:13, color:'#65676B', textAlign:'center', padding:'16px 0' }}>Vous n'avez pas encore d'amis \u00e0 identifier.</p>}\n            {tagFriendsList.map(f => (\n              <label key={f.uid} style={{ display:'flex', alignItems:'center', gap:10, padding:'9px 4px', cursor:'pointer', borderBottom:'1px solid #F0F2F5' }}>\n                <input type=\"checkbox\" checked={!!tagSelected[f.uid]} onChange={e => setTagSelected(p => ({ ...p, [f.uid]: e.target.checked }))} style={{ width:18, height:18, accentColor:'#1877F2' }}/>\n                <img src={f.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(f.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                <p style={{ fontWeight:600, fontSize:14 }}>{f.fullName}</p>\n              </label>\n            ))}\n            <button onClick={saveTags} className=\"btn-primary\" style={{ width:'100%', marginTop:14, padding:'11px 0', fontSize:14 }}>Enregistrer</button>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}";
const ARTIST_SRC="// src/pages/ArtistDetail.jsx \u2014 Page Artiste (format Spotify/Sera)\nimport { useState, useEffect, useRef } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport {\n  doc, onSnapshot, updateDoc, deleteDoc, collection, query, where, getDocs,\n  addDoc, serverTimestamp, arrayUnion, arrayRemove, writeBatch\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { captureVideoThumb } from '../utils/videoThumb';\nimport { timeAgo } from '../utils/timeAgo';\nimport { NeonMic, NeonGlobe, NeonPhone, NeonLocation, NeonChart, NeonEye, NeonPeople, NeonLike, NeonComment } from '../components/NeonIcons';\nimport FollowListModal from '../components/FollowListModal';\nimport ShareModal from '../components/ShareModal';\nimport { SkeletonChannelPage } from '../components/Skeleton';\nimport ReportModal from '../components/ReportModal';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport { downloadMedia } from '../utils/download';\nimport { parseAppLink } from '../utils/appLink';\nimport {\n  HiCamera, HiArrowLeft, HiPencil, HiX, HiTrash, HiDotsVertical, HiPaperAirplane,\n  HiMusicNote, HiVideoCamera, HiPhotograph, HiCog, HiBan, HiFlag,\n  HiInformationCircle, HiDownload, HiLightningBolt, HiSearch, HiLink, HiShare\n} from 'react-icons/hi';\n\nconst GENRES = ['Salegy', 'Tsapiky', 'Kawitry', 'Pop', 'Hip-Hop', 'Gospel', 'Reggae', 'Rock', 'Autre'];\nconst GENRE_COLORS = {\n  Salegy:'#FF7A00', Tsapiky:'#12A48D', Kawitry:'#8F6BFF', Pop:'#FF2D8D',\n  'Hip-Hop':'#1877F2', Gospel:'#F2B300', Reggae:'#2E9E4B', Rock:'#E0242D', Autre:'#65676B',\n};\n\nexport default function ArtistDetail() {\n  const { artistId } = useParams();\n  const { currentUser, userProfile } = useAuth();\n  const navigate = useNavigate();\n\n  const [artist, setArtist] = useState(null);\n  const [notFound, setNotFound] = useState(false);\n  const [tracks, setTracks] = useState([]);\n  const [menuOpen, setMenuOpen] = useState(false);\n  const [editOpen, setEditOpen] = useState(false);\n  const [editForm, setEditForm] = useState({ name:'', bio:'', label:'', manager:'', address:'', contact:'', website:'' });\n  const [followersOpen, setFollowersOpen] = useState(false);\n  const [statsOpen, setStatsOpen] = useState(false);\n\n  const [content, setContent] = useState('');\n  const [genre, setGenre] = useState(GENRES[0]);\n  const [mediaFile, setMediaFile] = useState(null);\n  const [mediaType, setMediaType] = useState('');\n  const [thumbFile, setThumbFile] = useState(null);\n  const [thumbPreview, setThumbPreview] = useState(null);\n  const [posting, setPosting] = useState(false);\n  // Champs hira (R\u00e9saka artiste)\n  const [songFullOpen, setSongFullOpen] = useState(false);\n  const [songTitle, setSongTitle]   = useState('');\n  const [songAC, setSongAC]         = useState('');   // Auteur / Compositeur\n  const [songLabel, setSongLabel]   = useState('');\n  const [songStudio, setSongStudio] = useState('');\n  const [songTeam, setSongTeam]     = useState('');   // \u00e9quipe\n  const [songArt, setSongArt]       = useState('');   // direction artistique\n  const [publishTarget, setPublishTarget] = useState('page');  // 'page' | 'groups'\n  const [myGroups, setMyGroups]     = useState([]);\n  const [songGroupSel, setSongGroupSel] = useState({});\n  const [groupQ, setGroupQ] = useState('');   // recherche de groupe\n  // Lecteur (Spotify-style)\n  const [currentTrack, setCurrentTrack] = useState(null);\n  const [playing, setPlaying] = useState(false);\n  const [trackInfo, setTrackInfo] = useState(null);\n  const [trackMenu, setTrackMenu] = useState(null);\n  const [trackQ, setTrackQ] = useState('');\n  const [sharePost, setSharePost] = useState(null);   // recherche de chansons dans la page   // piste dont le menu est ouvert\n  const [boostTarget, setBoostTarget] = useState(null);\n  const [reportTarget, setReportTarget] = useState(null); // 'artist' | { track }\n  const [curTime, setCurTime] = useState(0);\n  const [duration, setDuration] = useState(0);\n  const playerRef = useRef(null);\n  const audioRef = useRef(); const videoRef = useRef(); const thumbRef = useRef();\n  const coverRef = useRef(); const photoRef = useRef();\n\n  const isAdmin = !!artist?.admins?.includes(currentUser?.uid);\n  const isFollowing = !!artist?.followers?.includes(currentUser?.uid);\n\n  useEffect(() => {\n    const unsub = onSnapshot(doc(db, 'artists', artistId), snap => {\n      if (!snap.exists()) { setNotFound(true); return; }\n      setArtist({ id: snap.id, ...snap.data() });\n    }, err => console.error('Artist:', err?.message || err));\n    return () => unsub();\n  }, [artistId]);\n\n  useEffect(() => {\n    const q = query(collection(db, 'posts'), where('artistId', '==', artistId));\n    const unsub = onSnapshot(q, snap => {\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n      list.sort((a,b) => (b.createdAt?.seconds||0) - (a.createdAt?.seconds||0));\n      setTracks(list);\n    }, err => console.error('Artist tracks:', err?.message || err));\n    return () => unsub();\n  }, [artistId]);\n\n  useEffect(() => { const fn = () => setMenuOpen(false); document.addEventListener('click', fn); return () => document.removeEventListener('click', fn); }, []);\n\n  // Lecteur : d\u00e9marrage auto quand le titre change\n  useEffect(() => {\n    if (!currentTrack || !playerRef.current) return;\n    const p = playerRef.current;\n    p.load();\n    if (playing) p.play().catch(() => {});\n  }, [currentTrack]);\n\n  async function changeImage(e, field) {\n    const file = e.target.files[0]; if (!file) return;\n    try { const r = await uploadToTelegram(file); await updateDoc(doc(db, 'artists', artistId), { [field]: r.url }); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    e.target.value = '';\n  }\n\n  async function toggleFollowArtist() {\n    try { await updateDoc(doc(db, 'artists', artistId), { followers: isFollowing ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) }); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function openEdit() {\n    setEditForm({ name: artist.name||'', bio: artist.bio||'', label: artist.label||'', manager: artist.manager||'', address: artist.address||'', contact: artist.contact||'', website: artist.website||'' });\n    setEditOpen(true);\n  }\n  async function saveEdit() {\n    if (!editForm.name.trim()) return;\n    try { await updateDoc(doc(db, 'artists', artistId), { ...editForm, name: editForm.name.trim() }); setEditOpen(false); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n  function copyPageLink() {\n    setMenuOpen(false);\n    const url = `${window.location.origin}/artists/${artistId}`;\n    if (navigator.clipboard?.writeText) navigator.clipboard.writeText(url).then(() => alert('Lien copi\u00e9 !'), () => alert(url));\n    else { const el = document.createElement('textarea'); el.value = url; document.body.appendChild(el); el.select(); document.execCommand('copy'); el.remove(); alert('Lien copi\u00e9 !'); }\n  }\n\n  async function reportArtist() {\n    setMenuOpen(false);\n    setReportTarget('artist');\n  }\n\n  async function blockArtist() {\n    setMenuOpen(false);\n    if (!window.confirm(`Bloquer la page \"${artist.name}\" ?`)) return;\n    try { await updateDoc(doc(db, 'users', currentUser.uid), { blocked: arrayUnion(artistId) }); alert('Page bloqu\u00e9e.'); navigate('/artists'); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function reportTrack(t) {\n    setTrackMenu(null);\n    setReportTarget({ track: t });\n  }\n  async function submitReport(motif, detail) {\n    const t = reportTarget;\n    try {\n      if (t === 'artist') {\n        await addDoc(collection(db, 'reports'), {\n          type: 'artist', targetId: artistId, targetUid: artist.createdBy || '', targetAuthor: artist.name,\n          reportedBy: currentUser.uid, reportedByName: userProfile?.fullName || '',\n          motif, detail: detail || '', createdAt: serverTimestamp(), status: 'pending',\n        });\n      } else {\n        await addDoc(collection(db, 'reports'), {\n          type: 'post', targetId: t.track.id, targetUid: t.track.uid || '', targetAuthor: artist.name,\n          reportedBy: currentUser.uid, reportedByName: userProfile?.fullName || '',\n          motif, detail: detail || '', createdAt: serverTimestamp(), status: 'pending',\n        });\n      }\n      setReportTarget(null);\n      alert('Signalement envoy\u00e9. Merci.');\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function deleteTrack(t) {\n    setTrackMenu(null);\n    if (!window.confirm(`Supprimer \"${t.songTitle || 'ce titre'}\" ?`)) return;\n    try { await deleteDoc(doc(db, 'posts', t.id)); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function deleteArtist() {\n    if (!window.confirm(`Supprimer d\u00e9finitivement le canal \"${artist.name}\" ?`)) return;\n    try { await deleteDoc(doc(db, 'artists', artistId)); navigate('/artists'); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function pickAudio(e) { const f = e.target.files[0]; if (!f) return; setMediaFile(f); setMediaType('audio'); }\n  function pickVideo(e) { const f = e.target.files[0]; if (!f) return; setMediaFile(f); setMediaType('video'); }\n  function pickThumb(e) { const f = e.target.files[0]; if (!f) return; setThumbFile(f); setThumbPreview(URL.createObjectURL(f)); }\n\n  async function loadMyGroups() {\n    try {\n      const snap = await getDocs(query(collection(db, 'groups'), where('members', 'array-contains', currentUser.uid)));\n      setMyGroups(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch (e) { console.warn('loadMyGroups:', e?.message); }\n  }\n  function chooseTarget(target) {\n    setPublishTarget(target);\n    if (target === 'groups' && myGroups.length === 0) loadMyGroups();\n  }\n\n  function playTrack(t) {\n    if (currentTrack?.id === t.id) { togglePlay(); return; }\n    setCurrentTrack(t);\n    setPlaying(true);\n    setCurTime(0);\n    // La lecture d\u00e9marre via useEffect (quand la source est pr\u00eate)\n  }\n  function togglePlay() {\n    const p = playerRef.current;\n    if (!p) return;\n    if (p.paused) { p.play().catch(()=>{}); setPlaying(true); }\n    else { p.pause(); setPlaying(false); }\n  }\n  function playAdjacent(dir) {\n    if (!currentTrack) return;\n    const idx = tracks.findIndex(x => x.id === currentTrack.id);\n    const ni = idx + dir;\n    if (ni >= 0 && ni < tracks.length) playTrack(tracks[ni]);\n  }\n  function fmtTime(s) {\n    if (!s || isNaN(s)) return '0:00';\n    const m = Math.floor(s / 60), sec = Math.floor(s % 60);\n    return `${m}:${sec < 10 ? '0' : ''}${sec}`;\n  }\n\n  async function publishTrack() {\n    if (!mediaFile) { alert('Ajoutez un audio ou une vid\u00e9o'); return; }\n    if (!songTitle.trim()) { alert('Ajoutez un titre'); return; }\n    setPosting(true);\n    try {\n      const r = await uploadToTelegram(mediaFile);\n      let thumbURL = '';\n      if (mediaType === 'video' && !thumbFile) {\n        try { const auto = await captureVideoThumb(mediaFile); if (auto) { const tr = await uploadToTelegram(auto); thumbURL = tr.url || ''; } } catch {}\n      } else if (thumbFile) {\n        try { const tr = await uploadToTelegram(thumbFile); thumbURL = tr.url || ''; } catch {}\n      }\n      // Groupes cibles (si \"publier dans groupes\") \u2014 sinon page artiste\n      const targetGroups = publishTarget === 'groups' ? Object.keys(songGroupSel).filter(k => songGroupSel[k]) : [];\n\n      const baseData = {\n        uid: currentUser.uid, authorName: artist.name, authorUsername: '', authorPhoto: artist.photoURL || '',\n        content: content.trim().slice(0, 500), mediaURL: r.url, mediaType: mediaType === 'audio' ? 'audio' : 'video', thumbURL,\n        isSale: false, price: '', contact: '', lieu: '',\n        artistId: artist.id, artistName: artist.name, artistPhoto: artist.photoURL || '', genre,\n        isMusic: true,\n        songTitle: songTitle.trim().slice(0, 120),\n        songAuthorComposer: songAC.trim().slice(0, 160),   // A/C (auteur/compositeur)\n        songLabel: songLabel.trim().slice(0, 120),\n        songStudio: songStudio.trim().slice(0, 120),\n        songTeam: songTeam.trim().slice(0, 250),           // \u00e9quipe\n        songArt: songArt.trim().slice(0, 160),             // art / direction artistique\n        reactions: {}, comments: [], createdAt: serverTimestamp(),\n      };\n\n      if (targetGroups.length > 0) {\n        // Publier dans chaque groupe (la page artiste publie directement dedans)\n        const batch = writeBatch(db);\n        targetGroups.forEach(gid => {\n          const g = myGroups.find(x => x.id === gid);\n          const ref = doc(collection(db, 'posts'));\n          batch.set(ref, { ...baseData, groupId: gid, groupName: g?.name || '', postedByArtist: true });\n        });\n        await batch.commit();\n      } else {\n        // Publier sur la page artiste (+ fil d'actualit\u00e9s, canal audio)\n        await addDoc(collection(db, 'posts'), baseData);\n      }\n\n      // \u2705 Le titre est publi\u00e9 \u2014 une notification qui \u00e9choue ne doit JAMAIS\n      // d\u00e9clencher un faux message \"Erreur\"\n      try {\n        const targets = artist.followers || [];\n        if (targets.length > 0) {\n          const batch = writeBatch(db);\n          targets.forEach(fUid => batch.set(doc(collection(db,'notifications')), {\n            toUid: fUid, fromUid: currentUser.uid, fromName: artist.name, fromPhoto: artist.photoURL || '',\n            type: 'post', message: `${artist.name} a publi\u00e9 un nouveau son : ${songTitle.trim().slice(0,40)}`,\n            read: false, createdAt: serverTimestamp(),\n          }));\n          await batch.commit();\n        }\n      } catch (notifErr) { console.warn('Notification abonn\u00e9s \u00e9chou\u00e9e (titre d\u00e9j\u00e0 publi\u00e9) :', notifErr?.message || notifErr); }\n      setContent(''); setMediaFile(null); setMediaType(''); setThumbFile(null); setThumbPreview(null);\n      setSongTitle(''); setSongAC(''); setSongLabel(''); setSongStudio(''); setSongTeam(''); setSongArt('');\n      setPublishTarget('page'); setSongGroupSel({}); setSongFullOpen(false);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setPosting(false);\n  }\n\n  if (notFound) return (\n    <div style={{ padding:40, textAlign:'center' }}>\n      <p style={{ fontWeight:700, marginBottom:10 }}>Ce canal n'existe plus.</p>\n      <button className=\"btn-primary\" onClick={() => navigate('/artists')} style={{ padding:'10px 20px', borderRadius:20 }}>Voir les artistes</button>\n    </div>\n  );\n  if (!artist) return <SkeletonChannelPage />;\n\n  return (\n    <div style={{ paddingBottom:20 }}>\n      <div style={{ position:'relative', height:170, background: artist.coverURL ? '#000' : 'linear-gradient(135deg,#FF2D8D,#8F6BFF,#050505)' }}>\n        {artist.coverURL && <img src={artist.coverURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}\n        <button onClick={() => navigate('/artists')} style={{ position:'absolute', top:10, left:10, width:36, height:36, borderRadius:'50%', background:'rgba(0,0,0,.45)', border:'none', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiArrowLeft size={20}/></button>\n        {isAdmin && (<>\n          <input ref={coverRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e => changeImage(e,'coverURL')} />\n          <button onClick={() => coverRef.current?.click()} style={{ position:'absolute', bottom:10, right:10, background:'rgba(255,255,255,.92)', border:'none', borderRadius:18, padding:'7px 12px', cursor:'pointer', fontSize:12, fontWeight:700, display:'flex', alignItems:'center', gap:5 }}><HiCamera size={15}/> Couverture</button>\n        </>)}\n        <div style={{ position:'absolute', bottom:-32, left:16 }}>\n          <div style={{ position:'relative' }}>\n            <div style={{ width:74, height:74, borderRadius:'50%', background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'4px solid white', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>\n              {artist.photoURL ? <img src={artist.photoURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : <NeonMic size={30} color=\"white\"/>}\n            </div>\n            {isAdmin && (<>\n              <input ref={photoRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e => changeImage(e,'photoURL')} />\n              <button onClick={() => photoRef.current?.click()} style={{ position:'absolute', bottom:-4, right:-4, width:26, height:26, borderRadius:'50%', background:'#FF2D8D', border:'2.5px solid white', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiCamera size={12}/></button>\n            </>)}\n          </div>\n        </div>\n      </div>\n\n      <div style={{ padding:'40px 16px 0' }}>\n        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>\n          <div style={{ minWidth:0 }}>\n            <h2 style={{ fontWeight:800, fontSize:19, display:'flex', alignItems:'center', gap:6 }}>\n              {artist.name}\n              <span style={{ display:'inline-flex', alignItems:'center', gap:3, background:'linear-gradient(135deg,#FF6FA5,#FF2D8D)', color:'white', fontSize:10, fontWeight:800, borderRadius:8, padding:'2px 8px' }}><NeonMic size={10} color=\"white\"/> ARTISTE</span>\n            </h2>\n            <p style={{ fontSize:12, color:'#65676B' }}>\n              <span onClick={() => (artist.followers||[]).length>0 && setFollowersOpen(true)} style={{ cursor:(artist.followers||[]).length>0?'pointer':'default', textDecoration:(artist.followers||[]).length>0?'underline':'none' }}><b style={{ fontWeight:800 }}>{(artist.followers||[]).length}</b> abonn\u00e9s</span>\n            </p>\n          </div>\n          <div style={{ position:'relative' }} onClick={e => e.stopPropagation()}>\n            <span style={{ display:'flex', alignItems:'center', gap:8 }}>\n              {isAdmin && (\n                <button onClick={() => setStatsOpen(true)} title=\"Statistiques\" style={{ background:'linear-gradient(145deg,#3DD9C4,#12A48D)', border:'none', borderRadius:12, width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', boxShadow:'0 4px 10px rgba(18,164,141,.35)' }}><NeonChart size={20} color=\"#fff\"/></button>\n              )}\n              <button onClick={() => navigate(`/artists/${artistId}/messages`)} title=\"Messages\" style={{ background:'linear-gradient(150deg,#FFD84D,#D69A00)', border:'none', borderRadius:12, width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', boxShadow:'0 4px 10px rgba(214,154,0,.4)' }}><HiPaperAirplane size={22} style={{ transform:'rotate(90deg)' }}/></button>\n              <button onClick={() => setMenuOpen(p=>!p)} title={isAdmin ? 'Param\u00e8tres' : 'Options'} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#050505' }}>{isAdmin ? <HiCog size={21}/> : <HiDotsVertical size={20}/>}</button>\n            </span>\n            {menuOpen && (\n              <div style={{ position:'absolute', top:'100%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.14)', minWidth:180, zIndex:50, overflow:'hidden' }}>\n                {isAdmin ? (<>\n                  <button onClick={() => { setMenuOpen(false); openEdit(); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiPencil size={18} color=\"#1877F2\"/> Modifier la page</button>\n                  <button onClick={() => { setMenuOpen(false); deleteArtist(); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#FF2D8D' }}><HiTrash size={18}/> Supprimer la page</button>\n                  <button onClick={() => { setMenuOpen(false); setBoostTarget({ type:'artist', id: artistId, ownerUid: currentUser.uid, title: artist.name || 'Mon artiste', thumbnailURL: artist.photoURL || '' }); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderTop:'1px solid #F0F2F5' }}><HiLightningBolt size={18} color=\"#a855f7\"/> Booster mon artiste</button>\n                  <button onClick={copyPageLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderTop:'1px solid #F0F2F5' }}><HiLink size={18} color=\"#12A48D\"/> Copier le lien</button>\n                </>) : (<>\n                  <button onClick={copyPageLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiLink size={18} color=\"#12A48D\"/> Copier le lien</button>\n                  <button onClick={reportArtist} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiFlag size={18} color=\"#F2B300\"/> Signaler aux admins</button>\n                  <button onClick={blockArtist} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#FF2D8D' }}><HiBan size={18}/> Bloquer cette page</button>\n                </>)}\n              </div>\n            )}\n          </div>\n        </div>\n\n        {artist.bio && <p style={{ fontSize:14, marginTop:8 }}>{artist.bio}</p>}\n        <div style={{ display:'flex', flexDirection:'column', gap:7, marginTop:10 }}>\n          {artist.label && <p style={{ fontSize:13, color:'#65676B' }}>\ud83d\udcbf Label/Studio : {artist.label}</p>}\n          {artist.manager && <p style={{ fontSize:13, color:'#65676B' }}>\ud83d\udc64 Manager : {artist.manager}</p>}\n          {artist.address && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:8 }}><NeonLocation size={15}/> {artist.address}</p>}\n          {artist.contact && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:8 }}><NeonPhone size={15}/> {artist.contact}</p>}\n          {artist.website && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:8 }}><NeonGlobe size={15}/> <a href={artist.website.startsWith('http')?artist.website:`https://${artist.website}`} target=\"_blank\" rel=\"noreferrer\" style={{ color:'#1877F2' }}>{artist.website}</a></p>}\n        </div>\n\n        {!isAdmin && (\n          <button onClick={toggleFollowArtist} className={isFollowing ? 'btn-secondary' : 'btn-gold'} style={{ width:'100%', marginTop:12, padding:'10px 0', fontSize:14, borderRadius:10 }}>\n            {isFollowing ? '\u2713 Abonn\u00e9' : '\u2b50 Suivre cet artiste'}\n          </button>\n        )}\n      </div>\n\n      {isAdmin && (\n        <div className=\"card post-card\" style={{ padding:12, marginTop:14, marginBottom:8 }}>\n          <button onClick={() => setSongFullOpen(true)}\n            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'none', borderRadius:22, padding:'12px', color:'white', fontWeight:800, fontSize:15, fontFamily:'Poppins', cursor:'pointer' }}>\n            <HiMusicNote size={20}/> Publier un nouveau son / vid\u00e9o\n          </button>\n        </div>\n      )}\n\n      {/* \u2500\u2500 PAGE FENO : Publier un titre (artiste) \u2500\u2500 */}\n      {songFullOpen && (\n      <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.35)', zIndex:350, display:'flex', alignItems:'flex-start', justifyContent:'center', overflowY:'auto' }}>\n      <div className=\"card post-card\" style={{ padding:16, width:'100%', maxWidth:600, minHeight:'100vh', borderRadius:0 }}>\n        <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:14, paddingBottom:12, borderBottom:'1px solid #E4E6EB' }}>\n          <button onClick={() => setSongFullOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', padding:4 }}><HiX size={24} color=\"#050505\"/></button>\n          <h3 style={{ fontWeight:800, fontSize:18, flex:1 }}>Publier un titre</h3>\n          <button onClick={publishTrack} disabled={posting || !mediaFile || !songTitle.trim()} className=\"btn-gold\" style={{ padding:'7px 20px', fontSize:14 }}>{posting ? '...' : 'Publier'}</button>\n        </div>\n\n        <input ref={audioRef} type=\"file\" accept=\"audio/*\" style={{ display:'none' }} onChange={pickAudio} />\n        <input ref={videoRef} type=\"file\" accept=\"video/mp4,video/webm,video/quicktime\" style={{ display:'none' }} onChange={pickVideo} />\n        <input ref={thumbRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={pickThumb} />\n\n        {/* M\u00e9dia : Audio / Vid\u00e9o + Vignette (art) */}\n        <div style={{ display:'flex', gap:8, marginBottom:12 }}>\n          <button onClick={() => audioRef.current.click()} className=\"btn-primary\" style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:6, padding:'12px', fontSize:13, borderRadius:12 }}><HiMusicNote size={18}/> Audio</button>\n          <button onClick={() => videoRef.current.click()} className=\"btn-blue\" style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:6, padding:'12px', fontSize:13, borderRadius:12 }}><HiVideoCamera size={18}/> Vid\u00e9o</button>\n          <button onClick={() => thumbRef.current.click()} className=\"btn-secondary\" style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:6, padding:'12px', fontSize:13, borderRadius:12 }}><HiPhotograph size={18}/> Art</button>\n        </div>\n        {mediaFile && (\n          <div style={{ display:'flex', alignItems:'center', gap:8, background:'#F0F2F5', borderRadius:10, padding:'8px 12px', marginBottom:8 }}>\n            {mediaType === 'audio' ? <HiMusicNote color=\"#FF2D8D\" /> : <HiVideoCamera color=\"#FF2D8D\" />}\n            <p style={{ fontSize:13, flex:1, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{mediaFile.name}</p>\n            <button onClick={() => { setMediaFile(null); setMediaType(''); }} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={16}/></button>\n          </div>\n        )}\n        {thumbPreview && <img src={thumbPreview} alt=\"\" style={{ width:80, height:80, borderRadius:10, objectFit:'cover', marginBottom:10 }} />}\n\n        {/* Champs du titre */}\n        <input className=\"input\" placeholder=\"Titre du morceau *\" value={songTitle} onChange={e => setSongTitle(e.target.value)} style={{ marginBottom:8 }} maxLength={120} />\n        <select value={genre} onChange={e => setGenre(e.target.value)} className=\"input\" style={{ marginBottom:8 }}>\n          {GENRES.map(g => <option key={g} value={g}>{g}</option>)}\n        </select>\n        <input className=\"input\" placeholder=\"A/C \u2014 Auteur / Compositeur\" value={songAC} onChange={e => setSongAC(e.target.value)} style={{ marginBottom:8 }} maxLength={160} />\n        <input className=\"input\" placeholder=\"Label\" value={songLabel} onChange={e => setSongLabel(e.target.value)} style={{ marginBottom:8 }} maxLength={120} />\n        <input className=\"input\" placeholder=\"Studio\" value={songStudio} onChange={e => setSongStudio(e.target.value)} style={{ marginBottom:8 }} maxLength={120} />\n        <input className=\"input\" placeholder=\"\u00c9quipe (musiciens, r\u00e9alisateur\u2026)\" value={songTeam} onChange={e => setSongTeam(e.target.value)} style={{ marginBottom:8 }} maxLength={250} />\n        <input className=\"input\" placeholder=\"Direction artistique / Art\" value={songArt} onChange={e => setSongArt(e.target.value)} style={{ marginBottom:8 }} maxLength={160} />\n        <textarea className=\"input\" placeholder=\"Description...\" value={content} onChange={e => setContent(e.target.value)} rows={3} style={{ resize:'none', marginBottom:12 }} maxLength={500} />\n\n        {/* Choix : publier dans ma page artiste OU dans des groupes */}\n        <div style={{ border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', marginBottom:8 }}>\n          <button onClick={() => chooseTarget('page')}\n            style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'13px 16px', background: publishTarget==='page' ? '#E7F0FE' : 'none', border:'none', borderBottom:'1px solid #F0F2F5', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, fontWeight:700, color:'#050505' }}>\n            <span style={{ width:18, height:18, borderRadius:'50%', border:'2px solid #1877F2', display:'inline-flex', alignItems:'center', justifyContent:'center' }}>{publishTarget==='page' && <span style={{ width:9, height:9, borderRadius:'50%', background:'#1877F2' }}/>}</span>\n            Publier dans ma page artiste\n          </button>\n          <button onClick={() => chooseTarget('groups')}\n            style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'13px 16px', background: publishTarget==='groups' ? '#E7F0FE' : 'none', border:'none', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, fontWeight:700, color:'#050505' }}>\n            <span style={{ width:18, height:18, borderRadius:'50%', border:'2px solid #1877F2', display:'inline-flex', alignItems:'center', justifyContent:'center' }}>{publishTarget==='groups' && <span style={{ width:9, height:9, borderRadius:'50%', background:'#1877F2' }}/>}</span>\n            Publier dans des groupes\n          </button>\n        </div>\n\n        {/* Liste des groupes (si \"dans groupes\") \u2014 avec recherche */}\n        {publishTarget === 'groups' && (() => {\n          const lowG = groupQ.trim().toLowerCase();\n          const shown = myGroups.filter(g => !lowG || (g.name || '').toLowerCase().includes(lowG));\n          const nSel = Object.values(songGroupSel).filter(Boolean).length;\n          return (\n          <div style={{ border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', marginBottom:8 }}>\n            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 14px 6px', background:'#FAFBFC' }}>\n              <span style={{ fontSize:12, fontWeight:800, color:'#65676B' }}>Groupes ({myGroups.length})</span>\n              {nSel > 0 && <span style={{ fontSize:11, fontWeight:700, color:'#fff', background:'#1877F2', borderRadius:10, padding:'2px 8px' }}>{nSel} s\u00e9lectionn\u00e9{nSel > 1 ? 's' : ''}</span>}\n            </div>\n\n            <div style={{ padding:'0 12px 10px', background:'#FAFBFC' }}>\n              <div style={{ display:'flex', alignItems:'center', gap:8, background:'#fff', border:'1px solid #E4E6EB', borderRadius:18, padding:'7px 12px' }}>\n                <HiSearch size={15} color=\"#65676B\"/>\n                <input value={groupQ} onChange={e => setGroupQ(e.target.value)} placeholder=\"Rechercher un groupe\u2026\"\n                  style={{ flex:1, border:'none', outline:'none', fontSize:13, background:'transparent', color:'#050505', minWidth:0, fontFamily:'Poppins' }} />\n                {groupQ && <button onClick={() => setGroupQ('')} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#65676B', flexShrink:0 }}><HiX size={11}/></button>}\n              </div>\n            </div>\n\n            <div style={{ maxHeight:230, overflowY:'auto' }}>\n              {myGroups.length === 0 && <p style={{ padding:16, textAlign:'center', fontSize:13, color:'#65676B' }}>Aucun groupe accessible.</p>}\n              {myGroups.length > 0 && shown.length === 0 && <p style={{ padding:16, textAlign:'center', fontSize:13, color:'#65676B' }}>Aucun groupe trouv\u00e9.</p>}\n              {shown.map(g => (\n                <button key={g.id} onClick={() => setSongGroupSel(p => ({ ...p, [g.id]: !p[g.id] }))}\n                  style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background: songGroupSel[g.id] ? 'rgba(24,119,242,.06)' : 'none', border:'none', borderTop:'1px solid #F0F2F5', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, color:'#050505' }}>\n                  <span style={{ width:20, height:20, borderRadius:5, border:'2px solid #1877F2', background: songGroupSel[g.id] ? '#1877F2' : 'transparent', display:'inline-flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:13, flexShrink:0 }}>{songGroupSel[g.id] && '\u2713'}</span>\n                  <span style={{ flex:1, minWidth:0, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{g.name}</span>\n                  {typeof g.members !== 'undefined' && <span style={{ fontSize:11, color:'#8A8D91', flexShrink:0 }}>{(g.members || []).length} membres</span>}\n                </button>\n              ))}\n            </div>\n          </div>\n          );\n        })()}\n      </div>\n      </div>\n      )}\n\n      {tracks.length === 0 && <p style={{ padding:30, textAlign:'center', color:'#65676B', fontSize:14 }}>Aucun titre publi\u00e9 pour le moment.</p>}\n\n      {/* \u2500\u2500 Titres : 2 colonnes (audio | clips) + recherche \u2500\u2500\u2500 */}\n      {tracks.length > 0 && (() => {\n        const lowQ = trackQ.trim().toLowerCase();\n        const match = t => !lowQ || (t.songTitle || '').toLowerCase().includes(lowQ) || (t.content || '').toLowerCase().includes(lowQ) || (t.genre || '').toLowerCase().includes(lowQ) || (t.songAuthorComposer || '').toLowerCase().includes(lowQ);\n        const audios = tracks.filter(t => t.mediaType !== 'video' && match(t));\n        const videos = tracks.filter(t => t.mediaType === 'video' && match(t));\n\n        const Row = (t, i) => {\n          const isCur = currentTrack?.id === t.id;\n          return (\n            <div key={t.id} onClick={() => playTrack(t)}\n              style={{ display:'flex', alignItems:'center', gap:9, padding:'8px 10px', cursor:'pointer', background: isCur ? 'rgba(255,45,141,.08)' : 'transparent', borderTop: i>0?'1px solid #F0F2F5':'none' }}>\n              <div style={{ width:38, height:38, borderRadius:8, background: t.thumbURL ? `url(${t.thumbURL}) center/cover` : `linear-gradient(145deg, ${GENRE_COLORS[t.genre]||'#FF2D8D'}, #050505)`, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', position:'relative' }}>\n                {!t.thumbURL && (t.mediaType === 'video' ? <HiVideoCamera color=\"white\" size={15}/> : <NeonMic color=\"white\" size={14}/>)}\n                {isCur && playing && <span style={{ position:'absolute', inset:0, background:'rgba(0,0,0,.45)', borderRadius:8, display:'flex', alignItems:'center', justifyContent:'center', color:'#FF2D8D', fontSize:13 }}>\u25b6</span>}\n              </div>\n              <div style={{ flex:1, minWidth:0 }}>\n                <p style={{ fontWeight:600, fontSize:13, color: isCur ? '#FF2D8D' : '#050505', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{t.songTitle || t.content || 'Sans titre'}</p>\n                <p style={{ fontSize:11, color:'#65676B', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>\n                  <span style={{ color: GENRE_COLORS[t.genre]||'#FF2D8D' }}>{t.genre}</span>\n                </p>\n              </div>\n              <button onClick={e => { e.stopPropagation(); setTrackMenu(t); }} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', flexShrink:0, padding:2 }}><HiDotsVertical size={17}/></button>\n            </div>\n          );\n        };\n\n        return (\n        <div className=\"card\" style={{ marginTop:12, overflow:'hidden' }}>\n          <div style={{ display:'flex', alignItems:'center', gap:10, padding:'14px 16px 8px' }}>\n            <NeonMic color=\"#FF2D8D\" size={20}/>\n            <h3 style={{ fontWeight:800, fontSize:16 }}>Titres</h3>\n            <span style={{ fontSize:12, color:'#65676B' }}>{audios.length + videos.length}</span>\n          </div>\n\n          <div style={{ padding:'0 12px 10px' }}>\n            <div style={{ display:'flex', alignItems:'center', gap:8, background:'#F0F2F5', borderRadius:20, padding:'8px 13px' }}>\n              <HiSearch size={16} color=\"#65676B\"/>\n              <input value={trackQ} onChange={e => { const l = parseAppLink(e.target.value); if (l) { setTrackQ(''); navigate(l); return; } setTrackQ(e.target.value); }} placeholder=\"Rechercher une chanson\u2026 ou coller un lien\"\n                style={{ flex:1, border:'none', outline:'none', fontSize:13.5, background:'transparent', color:'#050505', minWidth:0 }} />\n              {trackQ && <button onClick={() => setTrackQ('')} style={{ background:'#fff', border:'none', borderRadius:'50%', width:21, height:21, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#65676B', flexShrink:0 }}><HiX size={12}/></button>}\n            </div>\n          </div>\n\n          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:0 }}>\n            <div style={{ borderRight:'1px solid #F0F2F5' }}>\n              <div style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 12px', background:'#FAFBFC' }}>\n                <HiMusicNote size={14} color=\"#FF2D8D\"/>\n                <span style={{ fontSize:12, fontWeight:800, color:'#65676B' }}>Audio</span>\n                <span style={{ fontSize:11, color:'#8A8D91' }}>{audios.length}</span>\n              </div>\n              {audios.length === 0\n                ? <p style={{ fontSize:12, color:'#8A8D91', textAlign:'center', padding:'18px 8px' }}>Aucun audio</p>\n                : audios.map((t, i) => Row(t, i))}\n            </div>\n            <div>\n              <div style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 12px', background:'#FAFBFC' }}>\n                <HiVideoCamera size={14} color=\"#1877F2\"/>\n                <span style={{ fontSize:12, fontWeight:800, color:'#65676B' }}>Clips</span>\n                <span style={{ fontSize:11, color:'#8A8D91' }}>{videos.length}</span>\n              </div>\n              {videos.length === 0\n                ? <p style={{ fontSize:12, color:'#8A8D91', textAlign:'center', padding:'18px 8px' }}>Aucun clip</p>\n                : videos.map((t, i) => Row(t, i))}\n            </div>\n          </div>\n        </div>\n        );\n      })()}\n\n      {false && tracks.map((t, i) => {\n            const isCur = currentTrack?.id === t.id;\n            return (\n              <div key={t.id} onClick={() => playTrack(t)}\n                style={{ display:'flex', alignItems:'center', gap:12, padding:'9px 16px', cursor:'pointer', background: isCur ? 'rgba(255,45,141,.08)' : 'transparent', borderTop: i>0?'1px solid #F0F2F5':'none' }}>\n                {/* Num\u00e9ro / indicateur lecture */}\n                <div style={{ width:24, textAlign:'center', flexShrink:0 }}>\n                  {isCur && playing\n                    ? <span style={{ color:'#FF2D8D', fontSize:15 }}>\u25b6</span>\n                    : <span style={{ color:'#65676B', fontSize:14, fontWeight:600 }}>{i+1}</span>}\n                </div>\n                {/* Pochette */}\n                <div style={{ width:44, height:44, borderRadius:8, background: t.thumbURL ? `url(${t.thumbURL}) center/cover` : `linear-gradient(145deg, ${GENRE_COLORS[t.genre]||'#FF2D8D'}, #050505)`, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', position:'relative' }}>\n                  {!t.thumbURL && <NeonMic color=\"white\" size={16}/>}\n                  {t.mediaType === 'video' && <span style={{ position:'absolute', bottom:2, right:2, fontSize:10 }}>\ud83c\udfac</span>}\n                </div>\n                {/* Infos */}\n                <div style={{ flex:1, minWidth:0 }}>\n                  <p style={{ fontWeight:600, fontSize:14, color: isCur ? '#FF2D8D' : '#050505', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{t.songTitle || t.content || 'Sans titre'}</p>\n                  <p style={{ fontSize:12, color:'#65676B', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>\n                    {[artist.name, t.songAuthorComposer].filter(Boolean).join(' \u00b7 ')} <span style={{ color: GENRE_COLORS[t.genre]||'#FF2D8D' }}>\u00b7 {t.genre}</span>\n                  </p>\n                </div>\n                {/* Menu / d\u00e9tails */}\n                <button onClick={e => { e.stopPropagation(); setTrackMenu(t); }} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', flexShrink:0 }}><HiDotsVertical size={18}/></button>\n              </div>\n            );\n          })}\n\n      {/* \u2500\u2500 Fiche titre (d\u00e9tails : \u00e9quipe, art, studio\u2026) \u2500\u2500 */}\n      {sharePost && <ShareModal post={sharePost} asPage={artist} onClose={() => setSharePost(null)} />}\n      {boostTarget && <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />}\n      {reportTarget && <ReportModal title=\"Signaler\" onConfirm={submitReport} onClose={() => setReportTarget(null)} />}\n\n      {trackMenu && (\n        <div onClick={() => setTrackMenu(null)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:300, display:'flex', alignItems:'flex-end', justifyContent:'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'#fff', borderRadius:'18px 18px 0 0', width:'100%', maxWidth:480, overflow:'hidden' }}>\n            {isAdmin ? (<>\n              <button onClick={() => { const t = trackMenu; setTrackMenu(null); setTrackInfo(t); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiPencil size={19} color=\"#1877F2\"/> Modifier</button>\n              <button onClick={() => { downloadMedia(trackMenu.mediaURL, trackMenu.mediaType || 'audio', trackMenu.songTitle || 'titre'); setTrackMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiDownload size={19} color=\"#12A48D\"/> T\u00e9l\u00e9charger</button>\n              <button onClick={() => { const tr = trackMenu; setTrackMenu(null); setBoostTarget({ type:'post', id: tr.id, ownerUid: tr.uid, title: tr.songTitle || artist.name, thumbnailURL: tr.mediaURL || '' }); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiLightningBolt size={19} color=\"#a855f7\"/> Booster</button>\n              <button onClick={() => { const t = trackMenu; setTrackMenu(null); setSharePost(t); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiShare size={19} color=\"#7A2DFF\"/> Partager</button>\n              <button onClick={() => deleteTrack(trackMenu)} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#FF2D8D' }}><HiTrash size={19}/> Supprimer</button>\n            </>) : (<>\n              <button onClick={() => { const t = trackMenu; setTrackMenu(null); setTrackInfo(t); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiInformationCircle size={19} color=\"#1877F2\"/> Informations</button>\n              <button onClick={() => { downloadMedia(trackMenu.mediaURL, trackMenu.mediaType || 'audio', trackMenu.songTitle || 'titre'); setTrackMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiDownload size={19} color=\"#12A48D\"/> T\u00e9l\u00e9charger</button>\n              <button onClick={() => { const t = trackMenu; setTrackMenu(null); setSharePost(t); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiShare size={19} color=\"#7A2DFF\"/> Partager</button>\n              <button onClick={() => reportTrack(trackMenu)} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#FF2D8D' }}><HiFlag size={19}/> Signaler aux admins</button>\n            </>)}\n          </div>\n        </div>\n      )}\n\n      {trackInfo && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setTrackInfo(null)}>\n          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:'10px 0 22px', width:'100%', maxWidth:480, maxHeight:'80vh', overflowY:'auto' }}>\n            <div style={{ width:40, height:4, borderRadius:2, background:'#CED0D4', margin:'6px auto 14px' }} />\n            <div style={{ display:'flex', gap:14, padding:'0 20px 14px' }}>\n              <div style={{ width:80, height:80, borderRadius:12, background: trackInfo.thumbURL ? `url(${trackInfo.thumbURL}) center/cover` : `linear-gradient(145deg, ${GENRE_COLORS[trackInfo.genre]||'#FF2D8D'}, #050505)`, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>\n                {!trackInfo.thumbURL && <NeonMic color=\"white\" size={28}/>}\n              </div>\n              <div style={{ flex:1, minWidth:0 }}>\n                <p style={{ fontWeight:800, fontSize:17 }}>{trackInfo.songTitle || 'Sans titre'}</p>\n                <p style={{ fontSize:13, color:'#65676B' }}>{artist.name} \u00b7 {trackInfo.genre}</p>\n                {trackInfo.createdAt && <p style={{ fontSize:12, color:'#8A8D91', marginTop:2 }}>{timeAgo(trackInfo.createdAt)}</p>}\n              </div>\n            </div>\n            {trackInfo.content && <p style={{ fontSize:14, padding:'0 20px 10px', lineHeight:1.5 }}>{trackInfo.content}</p>}\n            <div style={{ padding:'0 20px' }}>\n              {trackInfo.songAuthorComposer && <InfoRow label=\"A/C (Auteur / Compositeur)\" value={trackInfo.songAuthorComposer} />}\n              {trackInfo.songLabel  && <InfoRow label=\"Label\"  value={trackInfo.songLabel} />}\n              {trackInfo.songStudio && <InfoRow label=\"Studio\" value={trackInfo.songStudio} />}\n              {trackInfo.songTeam   && <InfoRow label=\"\u00c9quipe\" value={trackInfo.songTeam} />}\n              {trackInfo.songArt    && <InfoRow label=\"Direction artistique\" value={trackInfo.songArt} />}\n            </div>\n            <div style={{ padding:'14px 20px 0' }}>\n              <button onClick={() => { playTrack(trackInfo); setTrackInfo(null); }} className=\"btn-gold\" style={{ width:'100%', padding:'12px', fontSize:15 }}>\u25b6 Lire</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {editOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setEditOpen(false)}>\n          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480, maxHeight:'80vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ fontWeight:800, color:'#FF2D8D' }}>Modifier le canal</h3>\n              <button onClick={() => setEditOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            <input className=\"input\" value={editForm.name} onChange={e=>setEditForm(p=>({...p,name:e.target.value}))} placeholder=\"Nom d'artiste\" style={{ marginBottom:10 }}/>\n            <textarea className=\"input\" value={editForm.bio} onChange={e=>setEditForm(p=>({...p,bio:e.target.value}))} placeholder=\"Biographie\" rows={3} style={{ resize:'none', marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.label} onChange={e=>setEditForm(p=>({...p,label:e.target.value}))} placeholder=\"Label / studio\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.manager} onChange={e=>setEditForm(p=>({...p,manager:e.target.value}))} placeholder=\"Manager\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.address} onChange={e=>setEditForm(p=>({...p,address:e.target.value}))} placeholder=\"Adresse (point exact)\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.contact} onChange={e=>setEditForm(p=>({...p,contact:e.target.value}))} placeholder=\"Contact\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.website} onChange={e=>setEditForm(p=>({...p,website:e.target.value}))} placeholder=\"Site web\" style={{ marginBottom:14 }}/>\n            <button onClick={saveEdit} className=\"btn-primary\" style={{ width:'100%', padding:'11px 0', fontSize:14 }}>Enregistrer</button>\n          </div>\n        </div>\n      )}\n\n      {followersOpen && <FollowListModal uids={artist.followers||[]} title=\"Abonn\u00e9s\" onClose={() => setFollowersOpen(false)} />}\n\n      {/* \u2500\u2500 Statistiques plein \u00e9cran artiste : SVG NeonIcons + donut + bar \u2500\u2500 */}\n      {statsOpen && (() => {\n        let reactions = 0, views = 0, comments = 0;\n        tracks.forEach(t => { reactions += Object.keys(t.reactions||{}).length; views += t.views||0; comments += (t.comments||[]).length; });\n        const abonnes = (artist.followers||[]).length;\n        const statsData = [\n          { label:'Abonn\u00e9s',   value:abonnes,      color:'#1877F2', icon:<NeonPeople  size={18} color=\"#fff\"/> },\n          { label:'Titres',    value:tracks.length, color:'#FF2D8D', icon:<NeonMic     size={18} color=\"#fff\"/> },\n          { label:'R\u00e9actions', value:reactions,     color:'#FF7A00', icon:<NeonLike    size={18} color=\"#fff\"/> },\n          { label:'\u00c9coutes',   value:views,         color:'#5E4BDB', icon:<NeonEye     size={18} color=\"#fff\"/> },\n          { label:'Comments',  value:comments,      color:'#12A48D', icon:<NeonComment size={18} color=\"#fff\"/> },\n        ];\n        const total = statsData.reduce((s,d)=>s+d.value,0)||1;\n        const maxV  = Math.max(...statsData.map(d=>d.value),1);\n        let cumPct = 0;\n        const R=48, CX=60, CY=60, CIRC=2*Math.PI*R;\n        const donutSegs = statsData.filter(d=>d.value>0).map((d,i)=>{\n          const pct = d.value/total;\n          const dash= pct*CIRC;\n          const off = -cumPct*CIRC + CIRC/4;\n          cumPct += pct;\n          return <circle key={i} cx={CX} cy={CY} r={R} fill=\"none\" stroke={d.color} strokeWidth={20}\n            strokeDasharray={dash + \" \" + (CIRC-dash)} strokeDashoffset={off}\n            style={{ transition:'stroke-dasharray .4s' }}/>;\n        });\n        return (\n          <div onClick={() => setStatsOpen(false)} style={{ position:'fixed', inset:0, background:'white', zIndex:400, overflowY:'auto', display:'flex', flexDirection:'column' }}>\n            <div style={{ position:'sticky', top:0, background:'white', zIndex:10, padding:'12px 16px', display:'flex', alignItems:'center', gap:10, borderBottom:'1px solid #E4E6EB', boxShadow:'0 1px 4px rgba(0,0,0,.06)' }}\n              onClick={e=>e.stopPropagation()}>\n              <button onClick={() => setStatsOpen(false)} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:36, height:36, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\u2190</button>\n              <NeonChart size={20}/>\n              <div>\n                <p style={{ fontWeight:800, fontSize:16 }}>Statistiques \u2014 {artist.name}</p>\n                <p style={{ fontSize:11, color:'#65676B' }}>Canal artiste \u00b7 abonn\u00e9s, titres, interactions</p>\n              </div>\n            </div>\n            <div onClick={e=>e.stopPropagation()} style={{ padding:'16px 14px 40px', maxWidth:520, margin:'0 auto', width:'100%' }}>\n              <div style={{ background:'#F8F9FA', borderRadius:16, padding:'16px', marginBottom:14, display:'flex', alignItems:'center', gap:16 }}>\n                <svg width={120} height={120} viewBox=\"0 0 120 120\" style={{ flexShrink:0 }}>\n                  <circle cx={CX} cy={CY} r={R} fill=\"none\" stroke=\"#F0F2F5\" strokeWidth={20}/>\n                  {donutSegs}\n                  <text x={CX} y={CY-5} textAnchor=\"middle\" fontSize={11} fill=\"#65676B\">Total</text>\n                  <text x={CX} y={CY+10} textAnchor=\"middle\" fontSize={16} fontWeight={800} fill=\"#050505\">{total}</text>\n                </svg>\n                <div style={{ flex:1 }}>\n                  {statsData.filter(d=>d.value>0).map((d,i)=>(\n                    <div key={i} style={{ display:'flex', alignItems:'center', gap:6, marginBottom:5 }}>\n                      <div style={{ width:10, height:10, borderRadius:'50%', background:d.color, flexShrink:0 }}/>\n                      <span style={{ fontSize:12, color:'#65676B', flex:1 }}>{d.label}</span>\n                      <span style={{ fontSize:12, fontWeight:700 }}>{d.value.toLocaleString()}</span>\n                    </div>\n                  ))}\n                </div>\n              </div>\n              <div style={{ background:'#F8F9FA', borderRadius:16, padding:'14px', marginBottom:14 }}>\n                <p style={{ fontWeight:700, fontSize:13, marginBottom:10, color:'#050505' }}>Distribution</p>\n                <div style={{ display:'flex', alignItems:'flex-end', gap:8, height:80 }}>\n                  {statsData.map((d,i)=>{\n                    const h = Math.max((d.value/maxV)*64,2);\n                    return (\n                      <div key={i} style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>\n                        <span style={{ fontSize:9, fontWeight:700, color:d.color }}>{d.value}</span>\n                        <div style={{ width:'100%', height:h, background:d.color, borderRadius:'6px 6px 2px 2px', opacity:0.85 }}/>\n                        <span style={{ fontSize:8, color:'#65676B', textAlign:'center', lineHeight:1.2 }}>{d.label}</span>\n                      </div>\n                    );\n                  })}\n                </div>\n              </div>\n              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>\n                {statsData.map((d,i)=>(\n                  <div key={i} style={{ background:'white', borderRadius:14, padding:'12px', border:'1px solid #E4E6EB', display:'flex', alignItems:'center', gap:10 }}>\n                    <span style={{ width:40, height:40, borderRadius:12, background:`linear-gradient(145deg,${d.color}99,${d.color})`, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{d.icon}</span>\n                    <div>\n                      <p style={{ fontWeight:800, fontSize:20, lineHeight:1 }}>{d.value.toLocaleString()}</p>\n                      <p style={{ fontSize:11, color:'#65676B', marginTop:2 }}>{d.label}</p>\n                    </div>\n                  </div>\n                ))}\n              </div>\n            </div>\n          </div>\n        );\n      })()}\n\n      {/* \u2500\u2500 LECTEUR (mini-player Spotify) \u2500\u2500 */}\n      {currentTrack && (\n        <>\n          {/* \u00c9l\u00e9ment m\u00e9dia (audio ou vid\u00e9o) */}\n          {currentTrack.mediaType === 'video' ? (\n            <video ref={playerRef} src={currentTrack.mediaURL} playsInline\n              onTimeUpdate={e => setCurTime(e.target.currentTime)}\n              onLoadedMetadata={e => setDuration(e.target.duration)}\n              onEnded={() => playAdjacent(1)}\n              onPlay={() => setPlaying(true)} onPause={() => setPlaying(false)}\n              style={{ position:'fixed', bottom:150, right:12, width:150, borderRadius:12, zIndex:250, background:'#000', boxShadow:'0 6px 20px rgba(0,0,0,.4)' }} />\n          ) : (\n            <audio ref={playerRef} src={currentTrack.mediaURL}\n              onTimeUpdate={e => setCurTime(e.target.currentTime)}\n              onLoadedMetadata={e => setDuration(e.target.duration)}\n              onEnded={() => playAdjacent(1)}\n              onPlay={() => setPlaying(true)} onPause={() => setPlaying(false)} />\n          )}\n\n          <div style={{ position:'fixed', bottom:92, left:0, right:0, zIndex:260, display:'flex', justifyContent:'center', padding:'0 8px', pointerEvents:'none' }}>\n            <div style={{ pointerEvents:'auto', width:'100%', maxWidth:600, background:'linear-gradient(135deg,#2A0A1B,#4A0E2E)', borderRadius:14, padding:'8px 12px', boxShadow:'0 6px 24px rgba(0,0,0,.4)', display:'flex', alignItems:'center', gap:12 }}>\n              <div style={{ width:44, height:44, borderRadius:8, background: currentTrack.thumbURL ? `url(${currentTrack.thumbURL}) center/cover` : `linear-gradient(145deg, ${GENRE_COLORS[currentTrack.genre]||'#FF2D8D'}, #050505)`, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>\n                {!currentTrack.thumbURL && <NeonMic color=\"white\" size={16}/>}\n              </div>\n              <div style={{ flex:1, minWidth:0 }}>\n                <p style={{ fontWeight:700, fontSize:13, color:'white', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{currentTrack.songTitle || 'Sans titre'}</p>\n                <p style={{ fontSize:11, color:'rgba(255,255,255,.7)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{artist.name}</p>\n                {/* Barre de progression */}\n                <div style={{ marginTop:4, height:3, background:'rgba(255,255,255,.25)', borderRadius:2, cursor:'pointer' }}\n                  onClick={e => { const r = e.currentTarget.getBoundingClientRect(); const pct = (e.clientX - r.left) / r.width; if (playerRef.current && duration) { playerRef.current.currentTime = pct * duration; } }}>\n                  <div style={{ width: duration ? `${(curTime/duration)*100}%` : '0%', height:'100%', background:'#FF2D8D', borderRadius:2 }} />\n                </div>\n              </div>\n              <button onClick={() => playAdjacent(-1)} style={{ background:'none', border:'none', cursor:'pointer', color:'white', flexShrink:0 }}>\u23ee</button>\n              <button onClick={togglePlay} style={{ background:'white', border:'none', borderRadius:'50%', width:36, height:36, cursor:'pointer', color:'#4A0E2E', fontSize:15, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>{playing ? '\u275a\u275a' : '\u25b6'}</button>\n              <button onClick={() => playAdjacent(1)} style={{ background:'none', border:'none', cursor:'pointer', color:'white', flexShrink:0 }}>\u23ed</button>\n              <button onClick={() => { setCurrentTrack(null); setPlaying(false); }} style={{ background:'none', border:'none', cursor:'pointer', color:'rgba(255,255,255,.6)', flexShrink:0 }}><HiX size={16}/></button>\n            </div>\n          </div>\n        </>\n      )}\n    </div>\n  );\n}\n\nfunction InfoRow({ label, value }) {\n  return (\n    <div style={{ display:'flex', justifyContent:'space-between', gap:12, padding:'8px 0', borderBottom:'1px solid #F0F2F5' }}>\n      <span style={{ fontSize:13, color:'#65676B', flexShrink:0 }}>{label}</span>\n      <span style={{ fontSize:13, fontWeight:600, textAlign:'right' }}>{value}</span>\n    </div>\n  );\n}\n";
const SHOP_SRC="// src/pages/ShopDetail.jsx \u2014 Page Boutique (firafitra mitovy amin'ny page Artiste)\n// Real-time (onSnapshot), messagerie d\u00e9di\u00e9e, menu \u22ee (admin/visiteur), publication\n// page/groupes misy recherche, cards misy prix/vues/clics/r\u00e9actions (sary 2).\nimport { useState, useEffect, useRef } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport {\n  doc, onSnapshot, updateDoc, deleteDoc, collection, query, where, getDocs,\n  addDoc, serverTimestamp, arrayUnion, arrayRemove, writeBatch, increment, deleteField\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { timeAgo } from '../utils/timeAgo';\nimport { NeonPhone, NeonLocation, NeonPlaneWhite, NeonChart, NeonEye, NeonPeople, NeonLike, NeonComment } from '../components/NeonIcons';\nimport FollowListModal from '../components/FollowListModal';\nimport ShareModal from '../components/ShareModal';\nimport { SkeletonChannelPage } from '../components/Skeleton';\nimport ReportModal from '../components/ReportModal';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport { downloadMedia } from '../utils/download';\nimport { parseAppLink } from '../utils/appLink';\nimport { addToCart } from '../utils/cart';\nimport {\n  HiCamera, HiArrowLeft, HiPencil, HiX, HiTrash, HiDotsVertical, HiPaperAirplane,\n  HiShoppingBag, HiPhotograph, HiTag, HiCog, HiBan, HiFlag, HiShoppingCart,\n  HiInformationCircle, HiDownload, HiLightningBolt, HiSearch, HiLink, HiShare,\n  HiEye, HiCursorClick, HiHeart, HiOutlineHeart, HiChat\n} from 'react-icons/hi';\n\nconst CATEGORIES = ['V\u00eatements', 'Robes', 'Hauts', 'Pantalons', 'Chaussures', 'Accessoires', '\u00c9lectronique', 'D\u00e9co & Maison', 'V\u00e9hicules', 'Alimentation', 'Beaut\u00e9', 'Autre'];\n\n// Vues : isaina indray mandeha isaky ny session (tsy mitombo tsy misy antony)\nconst viewedThisSession = new Set();\n\nexport default function ShopDetail() {\n  const { shopId } = useParams();\n  const { currentUser, userProfile } = useAuth();\n  const navigate = useNavigate();\n\n  const [shop, setShop] = useState(null);\n  const [notFound, setNotFound] = useState(false);\n  const [items, setItems] = useState([]);\n  const [menuOpen, setMenuOpen] = useState(false);\n  const [editOpen, setEditOpen] = useState(false);\n  const [editForm, setEditForm] = useState({ name:'', description:'', address:'', team:'', contact:'', category:CATEGORIES[0] });\n  const [followersOpen, setFollowersOpen] = useState(false);\n  const [statsOpen, setStatsOpen] = useState(false);\n\n  // \u2500\u2500 Ajouter un article \u2500\u2500\n  const [content, setContent] = useState('');\n  const [price, setPrice] = useState('');\n  const [itemOldPrice, setItemOldPrice] = useState('');\n  const [itemCategory, setItemCategory] = useState(CATEGORIES[0]);\n  const [mediaFile, setMediaFile] = useState(null);\n  const [mediaPreview, setMediaPreview] = useState(null);\n  const [posting, setPosting] = useState(false);\n  const [itemFullOpen, setItemFullOpen] = useState(false);\n  const [publishTarget, setPublishTarget] = useState('page');   // 'page' | 'groups'\n  const [myGroups, setMyGroups] = useState([]);\n  const [itemGroupSel, setItemGroupSel] = useState({});\n  const [groupQ, setGroupQ] = useState('');\n\n  // \u2500\u2500 Lisitra articles \u2500\u2500\n  const [shopFilter, setShopFilter] = useState('Tout');\n  const [itemQ, setItemQ] = useState('');\n  const [sortBy, setSortBy] = useState('recent');   // recent | priceAsc | priceDesc | views\n  const [itemMenu, setItemMenu] = useState(null);   // article misokatra menu\n  const [itemInfo, setItemInfo] = useState(null);   // fiche article\n  const [sharePost, setSharePost] = useState(null);\n  const [boostTarget, setBoostTarget] = useState(null);\n  const [reportTarget, setReportTarget] = useState(null); // 'shop' | { item }\n\n  const photoInputRef = useRef(); const coverRef = useRef(); const logoRef = useRef();\n\n  const isAdmin = !!shop?.admins?.includes(currentUser?.uid);\n  const isFollowing = !!shop?.followers?.includes(currentUser?.uid);\n\n  useEffect(() => {\n    const unsub = onSnapshot(doc(db, 'shops', shopId), snap => {\n      if (!snap.exists()) { setNotFound(true); return; }\n      setShop({ id: snap.id, ...snap.data() });\n    }, err => console.error('Shop:', err?.message || err));\n    return () => unsub();\n  }, [shopId]);\n\n  useEffect(() => {\n    const q = query(collection(db, 'posts'), where('shopId', '==', shopId));\n    const unsub = onSnapshot(q, snap => {\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() })).filter(p => !p.groupId);\n      list.sort((a,b) => (b.createdAt?.seconds||0) - (a.createdAt?.seconds||0));\n      setItems(list);\n    }, err => console.error('Shop items:', err?.message || err));\n    return () => unsub();\n  }, [shopId]);\n\n  // \u2500\u2500 Compteur \"vues\" : mitombo indray mandeha isaky ny session ho an'ny article miseho \u2500\u2500\n  useEffect(() => {\n    if (!items.length || !currentUser) return;\n    const fresh = items.filter(p => !viewedThisSession.has(p.id));\n    if (!fresh.length) return;\n    fresh.forEach(p => viewedThisSession.add(p.id));\n    const batch = writeBatch(db);\n    fresh.forEach(p => batch.update(doc(db, 'posts', p.id), { views: increment(1) }));\n    batch.commit().catch(() => {});\n  }, [items.length]); // eslint-disable-line\n\n  useEffect(() => { const fn = () => setMenuOpen(false); document.addEventListener('click', fn); return () => document.removeEventListener('click', fn); }, []);\n\n  async function changeImage(e, field) {\n    const file = e.target.files[0]; if (!file) return;\n    try { const r = await uploadToTelegram(file); await updateDoc(doc(db, 'shops', shopId), { [field]: r.url }); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    e.target.value = '';\n  }\n\n  async function toggleFollowShop() {\n    try { await updateDoc(doc(db, 'shops', shopId), { followers: isFollowing ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) }); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function openEdit() {\n    setEditForm({ name: shop.name||'', description: shop.description||'', address: shop.address||'', team: shop.team||'', contact: shop.contact||'', category: shop.category||CATEGORIES[0] });\n    setEditOpen(true);\n  }\n  async function saveEdit() {\n    if (!editForm.name.trim()) return;\n    try { await updateDoc(doc(db, 'shops', shopId), { ...editForm, name: editForm.name.trim() }); setEditOpen(false); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n  function copyPageLink() {\n    setMenuOpen(false);\n    const url = `${window.location.origin}/shop/${shopId}`;\n    if (navigator.clipboard?.writeText) navigator.clipboard.writeText(url).then(() => alert('Lien copi\u00e9 !'), () => alert(url));\n    else { const el = document.createElement('textarea'); el.value = url; document.body.appendChild(el); el.select(); document.execCommand('copy'); el.remove(); alert('Lien copi\u00e9 !'); }\n  }\n\n  async function reportShop() {\n    setMenuOpen(false);\n    setReportTarget('shop');\n  }\n\n  async function blockShop() {\n    setMenuOpen(false);\n    if (!window.confirm(`Bloquer la boutique \"${shop.name}\" ?`)) return;\n    try { await updateDoc(doc(db, 'users', currentUser.uid), { blocked: arrayUnion(shopId) }); alert('Boutique bloqu\u00e9e.'); navigate('/shop'); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function reportItem(p) {\n    setItemMenu(null);\n    setReportTarget({ item: p });\n  }\n  async function submitReport(motif, detail) {\n    const t = reportTarget;\n    try {\n      if (t === 'shop') {\n        await addDoc(collection(db, 'reports'), {\n          type: 'shop', targetId: shopId, targetUid: shop.createdBy || '', targetAuthor: shop.name,\n          reportedBy: currentUser.uid, reportedByName: userProfile?.fullName || '',\n          motif, detail: detail || '', createdAt: serverTimestamp(), status: 'pending',\n        });\n      } else {\n        await addDoc(collection(db, 'reports'), {\n          type: 'post', targetId: t.item.id, targetUid: t.item.uid || '', targetAuthor: shop.name,\n          reportedBy: currentUser.uid, reportedByName: userProfile?.fullName || '',\n          motif, detail: detail || '', createdAt: serverTimestamp(), status: 'pending',\n        });\n      }\n      setReportTarget(null);\n      alert('Signalement envoy\u00e9. Merci.');\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function deleteItem(p) {\n    setItemMenu(null);\n    if (!window.confirm(`Supprimer \"${(p.content||'cet article').slice(0,40)}\" ?`)) return;\n    try { await deleteDoc(doc(db, 'posts', p.id)); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function deleteShop() {\n    if (!window.confirm(`Supprimer d\u00e9finitivement la boutique \"${shop.name}\" ?`)) return;\n    try { await deleteDoc(doc(db, 'shops', shopId)); navigate('/shop'); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  // \u2500\u2500 \u2764\ufe0f r\u00e9action haingana amin'ny card \u2500\u2500\n  async function toggleHeart(e, p) {\n    e.stopPropagation();\n    const mine = p.reactions?.[currentUser.uid];\n    try {\n      if (mine) await updateDoc(doc(db, 'posts', p.id), { [`reactions.${currentUser.uid}`]: deleteField() });\n      else await updateDoc(doc(db, 'posts', p.id), { [`reactions.${currentUser.uid}`]: '\u2764\ufe0f' });\n    } catch (err) { console.warn('heart:', err?.message); }\n  }\n\n  // \u2500\u2500 Clic amin'ny card \u2192 compteur + detail \u2500\u2500\n  function openItem(p) {\n    updateDoc(doc(db, 'posts', p.id), { clicks: increment(1) }).catch(() => {});\n    navigate(`/post/${p.id}`);\n  }\n\n  function pickPhoto(e) { const f = e.target.files[0]; if (!f) return; setMediaFile(f); setMediaPreview(URL.createObjectURL(f)); }\n\n  async function loadMyGroups() {\n    try {\n      const snap = await getDocs(query(collection(db, 'groups'), where('members', 'array-contains', currentUser.uid)));\n      setMyGroups(snap.docs.map(d => ({ id: d.id, ...d.data() })));\n    } catch (e) { console.warn('loadMyGroups:', e?.message); }\n  }\n  function chooseTarget(target) {\n    setPublishTarget(target);\n    if (target === 'groups' && myGroups.length === 0) loadMyGroups();\n  }\n\n  async function publishItem() {\n    if (!mediaFile) { alert(\"Ajoutez une photo de l'article\"); return; }\n    if (!content.trim()) { alert(\"Ajoutez le nom / la description de l'article\"); return; }\n    setPosting(true);\n    try {\n      const r = await uploadToTelegram(mediaFile);\n      const targetGroups = publishTarget === 'groups' ? Object.keys(itemGroupSel).filter(k => itemGroupSel[k]) : [];\n\n      const baseData = {\n        uid: currentUser.uid, authorName: shop.name, authorUsername: '', authorPhoto: shop.photoURL || '',\n        content: content.trim().slice(0, 500), mediaURL: r.url, mediaType: 'image', thumbURL: '',\n        isSale: true, price: parseFloat(price) || 0, oldPrice: parseFloat(itemOldPrice) || 0,\n        contact: shop.contact || '', lieu: shop.address || '',\n        saleCategory: itemCategory || shop.category || '',\n        shopId: shop.id, shopName: shop.name, shopPhoto: shop.photoURL || '',\n        views: 0, clicks: 0,\n        reactions: {}, comments: [], createdAt: serverTimestamp(),\n      };\n\n      if (targetGroups.length > 0) {\n        // Publier dans chaque groupe (la boutique publie directement dedans)\n        const batch = writeBatch(db);\n        targetGroups.forEach(gid => {\n          const g = myGroups.find(x => x.id === gid);\n          const ref = doc(collection(db, 'posts'));\n          batch.set(ref, { ...baseData, groupId: gid, groupName: g?.name || '', postedByShop: true });\n        });\n        await batch.commit();\n      } else {\n        // Publier sur la page boutique (+ fil d'actualit\u00e9s)\n        await addDoc(collection(db, 'posts'), baseData);\n      }\n\n      // \u2705 L'article est publi\u00e9 \u2014 une notification qui \u00e9choue ne doit JAMAIS\n      // d\u00e9clencher un faux message \"Erreur\"\n      try {\n        const targets = targetGroups.length === 0 ? (shop.followers || []) : [];\n        if (targets.length > 0) {\n          const batch = writeBatch(db);\n          targets.forEach(fUid => batch.set(doc(collection(db,'notifications')), {\n            toUid: fUid, fromUid: currentUser.uid, fromName: shop.name, fromPhoto: shop.photoURL || '',\n            type: 'post', message: `${shop.name} a ajout\u00e9 un nouvel article : ${content.trim().slice(0,40)}`,\n            read: false, createdAt: serverTimestamp(),\n          }));\n          await batch.commit();\n        }\n      } catch (notifErr) { console.warn('Notification abonn\u00e9s \u00e9chou\u00e9e (article d\u00e9j\u00e0 publi\u00e9) :', notifErr?.message || notifErr); }\n\n      setContent(''); setPrice(''); setItemOldPrice(''); setItemCategory(CATEGORIES[0]);\n      setMediaFile(null); setMediaPreview(null);\n      setPublishTarget('page'); setItemGroupSel({}); setGroupQ(''); setItemFullOpen(false);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setPosting(false);\n  }\n\n  if (notFound) return (\n    <div style={{ padding:40, textAlign:'center' }}>\n      <p style={{ fontWeight:700, marginBottom:10 }}>Cette boutique n'existe plus.</p>\n      <button className=\"btn-primary\" onClick={() => navigate('/shop')} style={{ padding:'10px 20px', borderRadius:20 }}>Voir les boutiques</button>\n    </div>\n  );\n  if (!shop) return <SkeletonChannelPage />;\n\n  return (\n    <div style={{ paddingBottom:20 }}>\n      {/* \u2500\u2500 Couverture + logo (mitovy amin'ny artiste) \u2500\u2500 */}\n      <div style={{ position:'relative', height:170, background: shop.coverURL ? '#000' : 'linear-gradient(135deg,#FF2D8D,#FF9A5A,#F2B300)' }}>\n        {shop.coverURL && <img src={shop.coverURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}\n        <button onClick={() => navigate('/shop')} style={{ position:'absolute', top:10, left:10, width:36, height:36, borderRadius:'50%', background:'rgba(0,0,0,.45)', border:'none', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiArrowLeft size={20}/></button>\n        {isAdmin && (<>\n          <input ref={coverRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e => changeImage(e,'coverURL')} />\n          <button onClick={() => coverRef.current?.click()} style={{ position:'absolute', bottom:10, right:10, background:'rgba(255,255,255,.92)', border:'none', borderRadius:18, padding:'7px 12px', cursor:'pointer', fontSize:12, fontWeight:700, display:'flex', alignItems:'center', gap:5 }}><HiCamera size={15}/> Couverture</button>\n        </>)}\n        <div style={{ position:'absolute', bottom:-32, left:16 }}>\n          <div style={{ position:'relative' }}>\n            <div style={{ width:74, height:74, borderRadius:'50%', background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'4px solid white', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>\n              {shop.photoURL ? <img src={shop.photoURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : <HiShoppingBag size={30} color=\"white\"/>}\n            </div>\n            {isAdmin && (<>\n              <input ref={logoRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e => changeImage(e,'photoURL')} />\n              <button onClick={() => logoRef.current?.click()} style={{ position:'absolute', bottom:-4, right:-4, width:26, height:26, borderRadius:'50%', background:'#FF2D8D', border:'2.5px solid white', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiCamera size={12}/></button>\n            </>)}\n          </div>\n        </div>\n      </div>\n\n      {/* \u2500\u2500 Anarana, badge, abonn\u00e9s, menu \u22ee (mitovi-drafitra amin'ny artiste) \u2500\u2500 */}\n      <div style={{ padding:'40px 16px 0' }}>\n        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>\n          <div style={{ minWidth:0 }}>\n            <h2 style={{ fontWeight:800, fontSize:19, display:'flex', alignItems:'center', gap:6, flexWrap:'wrap' }}>\n              {shop.name}\n              {isAdmin && <span style={{ fontSize:10, fontWeight:800, color:'#F2B300', background:'#FFF6DB', borderRadius:8, padding:'2px 8px' }}>ADMIN</span>}\n            </h2>\n            <p style={{ fontSize:12, color:'#65676B' }}>\n              \ud83c\udfea {shop.category} \u00b7 <span onClick={() => (shop.followers||[]).length>0 && setFollowersOpen(true)} style={{ cursor:(shop.followers||[]).length>0?'pointer':'default', textDecoration:(shop.followers||[]).length>0?'underline':'none' }}><b style={{ fontWeight:800 }}>{(shop.followers||[]).length}</b> abonn\u00e9s</span>\n            </p>\n          </div>\n          <div style={{ position:'relative' }} onClick={e => e.stopPropagation()}>\n            <span style={{ display:'flex', alignItems:'center', gap:8 }}>\n              {isAdmin && (\n                <button onClick={() => setStatsOpen(true)} title=\"Statistiques\" style={{ background:'linear-gradient(145deg,#3DD9C4,#12A48D)', border:'none', borderRadius:12, width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', boxShadow:'0 4px 10px rgba(18,164,141,.35)' }}><NeonChart size={20} color=\"#fff\"/></button>\n              )}\n              <button onClick={() => navigate(`/shop/${shopId}/messages`)} title=\"Messages\" style={{ background:'linear-gradient(150deg,#FFD84D,#D69A00)', border:'none', borderRadius:12, width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', boxShadow:'0 4px 10px rgba(214,154,0,.4)' }}><HiPaperAirplane size={22} style={{ transform:'rotate(90deg)' }}/></button>\n              <button onClick={() => setMenuOpen(p=>!p)} title={isAdmin ? 'Param\u00e8tres' : 'Options'} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:42, height:42, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#050505' }}>{isAdmin ? <HiCog size={21}/> : <HiDotsVertical size={20}/>}</button>\n            </span>\n            {menuOpen && (\n              <div style={{ position:'absolute', top:'100%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.14)', minWidth:180, zIndex:50, overflow:'hidden' }}>\n                {isAdmin ? (<>\n                  <button onClick={() => { setMenuOpen(false); openEdit(); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiPencil size={18} color=\"#1877F2\"/> Modifier la boutique</button>\n                  <button onClick={() => { setMenuOpen(false); deleteShop(); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#FF2D8D' }}><HiTrash size={18}/> Supprimer la boutique</button>\n                  <button onClick={() => { setMenuOpen(false); setBoostTarget({ type:'shop', id: shopId, ownerUid: currentUser.uid, title: shop.name || 'Ma boutique', thumbnailURL: shop.photoURL || '' }); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderTop:'1px solid #F0F2F5' }}><HiLightningBolt size={18} color=\"#a855f7\"/> Booster ma boutique</button>\n                  <button onClick={copyPageLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderTop:'1px solid #F0F2F5' }}><HiLink size={18} color=\"#12A48D\"/> Copier le lien</button>\n                </>) : (<>\n                  <button onClick={copyPageLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiLink size={18} color=\"#12A48D\"/> Copier le lien</button>\n                  <button onClick={reportShop} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiFlag size={18} color=\"#F2B300\"/> Signaler aux admins</button>\n                  <button onClick={blockShop} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding:'14px 18px', background:'none', border:'none', cursor:'pointer', fontSize:14.5, fontWeight:600, color:'#FF2D8D' }}><HiBan size={18}/> Bloquer cette boutique</button>\n                </>)}\n              </div>\n            )}\n          </div>\n        </div>\n\n        {shop.description && <p style={{ fontSize:14, marginTop:8 }}>{shop.description}</p>}\n        <div style={{ display:'flex', flexDirection:'column', gap:7, marginTop:10 }}>\n          {shop.address && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:8 }}><NeonLocation size={15}/> {shop.address}</p>}\n          {shop.contact && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:8 }}><NeonPhone size={15}/> {shop.contact}</p>}\n          {shop.team && <p style={{ fontSize:13, color:'#65676B' }}>\ud83d\udc65 \u00c9quipe : {shop.team}</p>}\n        </div>\n\n        {!isAdmin && (\n          <button onClick={toggleFollowShop} className={isFollowing ? 'btn-secondary' : 'btn-gold'} style={{ width:'100%', marginTop:12, padding:'10px 0', fontSize:14, borderRadius:10 }}>\n            {isFollowing ? '\u2713 Abonn\u00e9' : '\u2b50 Suivre cette boutique'}\n          </button>\n        )}\n      </div>\n\n      {isAdmin && (\n        <div className=\"card post-card\" style={{ padding:12, marginTop:14, marginBottom:8 }}>\n          <button onClick={() => setItemFullOpen(true)}\n            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'none', borderRadius:22, padding:'12px', color:'white', fontWeight:800, fontSize:15, fontFamily:'Poppins', cursor:'pointer' }}>\n            <HiShoppingBag size={20}/> Ajouter un article\n          </button>\n        </div>\n      )}\n\n      {/* \u2500\u2500 PAGE FENO : Ajouter un article (mitovy flow amin'ny artiste) \u2500\u2500 */}\n      {itemFullOpen && (\n      <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.35)', zIndex:350, display:'flex', alignItems:'flex-start', justifyContent:'center', overflowY:'auto' }}>\n      <div className=\"card post-card\" style={{ padding:16, width:'100%', maxWidth:600, minHeight:'100vh', borderRadius:0 }}>\n        <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:14, paddingBottom:12, borderBottom:'1px solid #E4E6EB' }}>\n          <button onClick={() => setItemFullOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', padding:4 }}><HiX size={24} color=\"#050505\"/></button>\n          <h3 style={{ fontWeight:800, fontSize:18, flex:1 }}>Ajouter un article</h3>\n          <button onClick={publishItem} disabled={posting || !mediaFile || !content.trim()} className=\"btn-gold\" style={{ padding:'7px 20px', fontSize:14 }}>{posting ? '...' : 'Publier'}</button>\n        </div>\n\n        <input ref={photoInputRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={pickPhoto} />\n\n        {/* Photo */}\n        {mediaPreview ? (\n          <div style={{ position:'relative', marginBottom:10 }}>\n            <img src={mediaPreview} alt=\"\" style={{ width:'100%', borderRadius:12, maxHeight:260, objectFit:'cover' }} />\n            <button onClick={() => { setMediaFile(null); setMediaPreview(null); }} style={{ position:'absolute', top:6, right:6, background:'rgba(0,0,0,.55)', border:'none', borderRadius:'50%', width:28, height:28, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}><HiX size={15}/></button>\n          </div>\n        ) : (\n          <button onClick={() => photoInputRef.current?.click()} className=\"btn-blue\" style={{ display:'flex', alignItems:'center', gap:6, padding:'12px', fontSize:14, borderRadius:12, width:'100%', justifyContent:'center', marginBottom:10 }}><HiPhotograph size={18}/> Photo de l'article *</button>\n        )}\n\n        {/* Champs mifanaraka amin'izay miseho amin'ny card */}\n        <textarea className=\"input\" placeholder=\"Nom / description de l'article *\" value={content} onChange={e => setContent(e.target.value)} rows={3} style={{ resize:'none', marginBottom:8 }} maxLength={500} />\n        <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}>\n          <HiTag color=\"#FF2D8D\" size={18}/>\n          <input className=\"input\" type=\"number\" placeholder=\"Prix (Ar) *\" value={price} onChange={e => setPrice(e.target.value)} style={{ flex:1 }} />\n        </div>\n        <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}>\n          <span style={{ fontSize:13, color:'#8A8D91', width:22, textAlign:'center' }}>\u2248</span>\n          <input className=\"input\" type=\"number\" placeholder=\"Ancien prix (optionnel \u2014 pour afficher -%)\" value={itemOldPrice} onChange={e => setItemOldPrice(e.target.value)} style={{ flex:1 }} />\n        </div>\n        <select value={itemCategory} onChange={e => setItemCategory(e.target.value)} className=\"input\" style={{ marginBottom:12 }}>\n          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}\n        </select>\n\n        {/* Choix : publier dans ma boutique OU dans des groupes */}\n        <div style={{ border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', marginBottom:8 }}>\n          <button onClick={() => chooseTarget('page')}\n            style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'13px 16px', background: publishTarget==='page' ? '#E7F0FE' : 'none', border:'none', borderBottom:'1px solid #F0F2F5', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, fontWeight:700, color:'#050505' }}>\n            <span style={{ width:18, height:18, borderRadius:'50%', border:'2px solid #1877F2', display:'inline-flex', alignItems:'center', justifyContent:'center' }}>{publishTarget==='page' && <span style={{ width:9, height:9, borderRadius:'50%', background:'#1877F2' }}/>}</span>\n            Publier dans ma boutique\n          </button>\n          <button onClick={() => chooseTarget('groups')}\n            style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'13px 16px', background: publishTarget==='groups' ? '#E7F0FE' : 'none', border:'none', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, fontWeight:700, color:'#050505' }}>\n            <span style={{ width:18, height:18, borderRadius:'50%', border:'2px solid #1877F2', display:'inline-flex', alignItems:'center', justifyContent:'center' }}>{publishTarget==='groups' && <span style={{ width:9, height:9, borderRadius:'50%', background:'#1877F2' }}/>}</span>\n            Publier dans des groupes\n          </button>\n        </div>\n\n        {/* Liste des groupes \u2014 avec recherche (mitovy amin'ny artiste) */}\n        {publishTarget === 'groups' && (() => {\n          const lowG = groupQ.trim().toLowerCase();\n          const shown = myGroups.filter(g => !lowG || (g.name || '').toLowerCase().includes(lowG));\n          const nSel = Object.values(itemGroupSel).filter(Boolean).length;\n          return (\n          <div style={{ border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', marginBottom:8 }}>\n            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 14px 6px', background:'#FAFBFC' }}>\n              <span style={{ fontSize:12, fontWeight:800, color:'#65676B' }}>Groupes ({myGroups.length})</span>\n              {nSel > 0 && <span style={{ fontSize:11, fontWeight:700, color:'#fff', background:'#1877F2', borderRadius:10, padding:'2px 8px' }}>{nSel} s\u00e9lectionn\u00e9{nSel > 1 ? 's' : ''}</span>}\n            </div>\n\n            <div style={{ padding:'0 12px 10px', background:'#FAFBFC' }}>\n              <div style={{ display:'flex', alignItems:'center', gap:8, background:'#fff', border:'1px solid #E4E6EB', borderRadius:18, padding:'7px 12px' }}>\n                <HiSearch size={15} color=\"#65676B\"/>\n                <input value={groupQ} onChange={e => setGroupQ(e.target.value)} placeholder=\"Rechercher un groupe\u2026\"\n                  style={{ flex:1, border:'none', outline:'none', fontSize:13, background:'transparent', color:'#050505', minWidth:0, fontFamily:'Poppins' }} />\n                {groupQ && <button onClick={() => setGroupQ('')} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#65676B', flexShrink:0 }}><HiX size={11}/></button>}\n              </div>\n            </div>\n\n            <div style={{ maxHeight:230, overflowY:'auto' }}>\n              {myGroups.length === 0 && <p style={{ padding:16, textAlign:'center', fontSize:13, color:'#65676B' }}>Aucun groupe accessible.</p>}\n              {myGroups.length > 0 && shown.length === 0 && <p style={{ padding:16, textAlign:'center', fontSize:13, color:'#65676B' }}>Aucun groupe trouv\u00e9.</p>}\n              {shown.map(g => (\n                <button key={g.id} onClick={() => setItemGroupSel(p => ({ ...p, [g.id]: !p[g.id] }))}\n                  style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background: itemGroupSel[g.id] ? 'rgba(24,119,242,.06)' : 'none', border:'none', borderTop:'1px solid #F0F2F5', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:14, color:'#050505' }}>\n                  <span style={{ width:20, height:20, borderRadius:5, border:'2px solid #1877F2', background: itemGroupSel[g.id] ? '#1877F2' : 'transparent', display:'inline-flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:13, flexShrink:0 }}>{itemGroupSel[g.id] && '\u2713'}</span>\n                  <span style={{ flex:1, minWidth:0, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{g.name}</span>\n                  {typeof g.members !== 'undefined' && <span style={{ fontSize:11, color:'#8A8D91', flexShrink:0 }}>{(g.members || []).length} membres</span>}\n                </button>\n              ))}\n            </div>\n          </div>\n          );\n        })()}\n      </div>\n      </div>\n      )}\n\n      {items.length === 0 && <p style={{ padding:30, textAlign:'center', color:'#65676B', fontSize:14 }}>Aucun article publi\u00e9 pour le moment.</p>}\n\n      {/* \u2500\u2500 Articles : filtres cat\u00e9gorie + recherche + tri (sary 2) \u2500\u2500 */}\n      {items.length > 0 && (() => {\n        const lowQ = itemQ.trim().toLowerCase();\n        const match = p => !lowQ || (p.content || '').toLowerCase().includes(lowQ) || (p.saleCategory || '').toLowerCase().includes(lowQ);\n        let shown = items.filter(p => (shopFilter==='Tout' || p.saleCategory===shopFilter) && match(p));\n        if (sortBy === 'priceAsc')  shown = [...shown].sort((a,b) => (Number(a.price)||0) - (Number(b.price)||0));\n        if (sortBy === 'priceDesc') shown = [...shown].sort((a,b) => (Number(b.price)||0) - (Number(a.price)||0));\n        if (sortBy === 'views')     shown = [...shown].sort((a,b) => (b.views||0) - (a.views||0));\n\n        return (\n        <>\n          {/* Chips cat\u00e9gorie */}\n          <div style={{ display:'flex', gap:8, overflowX:'auto', padding:'4px 12px 8px', scrollbarWidth:'none' }}>\n            {['Tout', ...Array.from(new Set(items.map(p => p.saleCategory).filter(Boolean)))].map(cat => (\n              <button key={cat} onClick={() => setShopFilter(cat)}\n                style={{ flex:'0 0 auto', padding:'7px 16px', borderRadius:18, border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:13, fontWeight:700,\n                  background: shopFilter===cat ? 'linear-gradient(145deg,#FF6FA5,#FF2D8D)' : '#F0F2F5',\n                  color: shopFilter===cat ? 'white' : '#65676B', whiteSpace:'nowrap' }}>\n                {cat}\n              </button>\n            ))}\n          </div>\n\n          {/* Recherche article */}\n          <div style={{ padding:'0 12px 8px' }}>\n            <div style={{ display:'flex', alignItems:'center', gap:8, background:'#F0F2F5', borderRadius:20, padding:'8px 13px' }}>\n              <HiSearch size={16} color=\"#65676B\"/>\n              <input value={itemQ} onChange={e => { const l = parseAppLink(e.target.value); if (l) { setItemQ(''); navigate(l); return; } setItemQ(e.target.value); }} placeholder=\"Rechercher un article\u2026 ou coller un lien\"\n                style={{ flex:1, border:'none', outline:'none', fontSize:13.5, background:'transparent', color:'#050505', minWidth:0 }} />\n              {itemQ && <button onClick={() => setItemQ('')} style={{ background:'#fff', border:'none', borderRadius:'50%', width:21, height:21, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:'#65676B', flexShrink:0 }}><HiX size={12}/></button>}\n            </div>\n          </div>\n\n          {/* En-t\u00eate \"Articles\" + Trier par (sary 2) */}\n          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'2px 12px 8px' }}>\n            <span style={{ fontWeight:800, fontSize:16 }}>Articles <span style={{ fontSize:12, color:'#65676B', fontWeight:600 }}>{shown.length} article{shown.length>1?'s':''}</span></span>\n            <span style={{ display:'flex', alignItems:'center', gap:6, fontSize:12.5, color:'#65676B' }}>\n              Trier par :\n              <select value={sortBy} onChange={e => setSortBy(e.target.value)} style={{ border:'1px solid #E4E6EB', borderRadius:10, padding:'4px 8px', fontSize:12.5, fontFamily:'Poppins', background:'#fff', color:'#050505', outline:'none', cursor:'pointer' }}>\n                <option value=\"recent\">Plus r\u00e9cents</option>\n                <option value=\"priceAsc\">Prix croissant</option>\n                <option value=\"priceDesc\">Prix d\u00e9croissant</option>\n                <option value=\"views\">Plus vus</option>\n              </select>\n            </span>\n          </div>\n\n          {shown.length === 0 && <p style={{ padding:24, textAlign:'center', color:'#65676B', fontSize:13 }}>Aucun article trouv\u00e9.</p>}\n\n          {/* Grille articles (sary 2) : -%, \u2764\ufe0f, prix/ancien prix, \u2b50 r\u00e9actions, vues, clics, Message */}\n          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, padding:'0 12px 12px' }}>\n            {shown.map(p => {\n              const oldPrice = Number(p.oldPrice) || 0;\n              const discount = p.price && oldPrice > Number(p.price) ? Math.round((1 - Number(p.price)/oldPrice) * 100) : 0;\n              const nReact = Object.keys(p.reactions || {}).length;\n              const myHeart = !!p.reactions?.[currentUser?.uid];\n              const stars = Math.max(1, Math.min(5, Math.round(nReact > 0 ? 4 + Math.min(1, nReact / 20) : 4)));\n              return (\n                <div key={p.id} onClick={() => openItem(p)} className=\"card\" style={{ overflow:'hidden', cursor:'pointer', borderRadius:12, boxShadow:'0 1px 4px rgba(0,0,0,.08)' }}>\n                  <div style={{ position:'relative' }}>\n                    {p.mediaURL\n                      ? <img src={p.mediaURL} alt=\"\" style={{ width:'100%', aspectRatio:'1', objectFit:'cover', display:'block' }} />\n                      : <div style={{ width:'100%', aspectRatio:'1', background:'#F0F2F5', display:'flex', alignItems:'center', justifyContent:'center' }}><HiShoppingBag size={34} color=\"#CED0D4\"/></div>}\n                    {discount > 0 && <span style={{ position:'absolute', top:6, left:6, background:'#FF1744', color:'white', fontSize:11, fontWeight:800, padding:'2px 7px', borderRadius:6 }}>-{discount}%</span>}\n                    <button onClick={e => toggleHeart(e, p)} style={{ position:'absolute', top:6, right:6, width:30, height:30, borderRadius:'50%', background:'rgba(255,255,255,.95)', border:'none', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', boxShadow:'0 1px 4px rgba(0,0,0,.15)' }}>\n                      {myHeart ? <HiHeart size={17} color=\"#FF2D8D\"/> : <HiOutlineHeart size={17} color=\"#050505\"/>}\n                    </button>\n                  </div>\n                  <div style={{ padding:'8px 9px 10px' }}>\n                    <p style={{ fontSize:12.5, fontWeight:700, lineHeight:1.35, overflow:'hidden', textOverflow:'ellipsis', display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', minHeight:34 }}>{p.content}</p>\n                    <div style={{ display:'flex', alignItems:'baseline', gap:6, marginTop:5, flexWrap:'wrap' }}>\n                      <span style={{ fontWeight:800, fontSize:15.5, color:'#FF2D8D' }}>{p.price ? `${Number(p.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                      {discount > 0 && <span style={{ fontSize:11, color:'#8A8D91', textDecoration:'line-through' }}>{oldPrice.toLocaleString()} Ar</span>}\n                    </div>\n                    <div style={{ display:'flex', alignItems:'center', gap:4, marginTop:4 }}>\n                      <span style={{ fontSize:10, color:'#FF9500', letterSpacing:1 }}>{'\u2605'.repeat(stars)}{'\u2606'.repeat(5-stars)}</span>\n                      <span style={{ fontSize:10.5, color:'#8A8D91' }}>\u00b7 {nReact} r\u00e9action{nReact>1?'s':''}</span>\n                    </div>\n                    <div style={{ display:'flex', alignItems:'center', gap:8, marginTop:6 }}>\n                      <span style={{ display:'flex', alignItems:'center', gap:3, fontSize:10.5, color:'#65676B' }}><HiEye size={12}/> {(p.views||0).toLocaleString()} vues</span>\n                      <span style={{ display:'flex', alignItems:'center', gap:3, fontSize:10.5, color:'#65676B' }}><HiCursorClick size={12}/> {(p.clicks||0).toLocaleString()} clics</span>\n                    </div>\n                    <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:8 }}>\n                      <button onClick={e => { e.stopPropagation(); navigate(`/shop/${shopId}/messages`); }}\n                        style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:4, background:'#fff', border:'1.5px solid #FF2D8D', borderRadius:16, padding:'6px 0', fontSize:11.5, fontWeight:700, color:'#FF2D8D', cursor:'pointer' }}>\n                        <NeonPlaneWhite size={13}/> Message\n                      </button>\n                      <button onClick={e => { e.stopPropagation(); const ok = addToCart(p); alert(ok ? 'Article ajout\u00e9 au panier \ud83d\uded2' : 'Cet article est d\u00e9j\u00e0 dans votre panier'); }}\n                        title=\"Ajouter au panier\"\n                        style={{ width:32, height:30, display:'flex', alignItems:'center', justifyContent:'center', background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'none', borderRadius:16, cursor:'pointer', color:'#fff', flexShrink:0 }}>\n                        <HiShoppingCart size={15}/>\n                      </button>\n                      <button onClick={e => { e.stopPropagation(); setItemMenu(p); }} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:2, flexShrink:0 }}><HiDotsVertical size={16}/></button>\n                    </div>\n                  </div>\n                </div>\n              );\n            })}\n          </div>\n        </>\n        );\n      })()}\n\n      {/* \u2500\u2500 Partager (mitovy amin'ny artiste) \u2500\u2500 */}\n      {sharePost && <ShareModal post={sharePost} asPage={shop} onClose={() => setSharePost(null)} />}\n      {boostTarget && <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />}\n      {reportTarget && <ReportModal title=\"Signaler\" onConfirm={submitReport} onClose={() => setReportTarget(null)} />}\n\n      {/* \u2500\u2500 Menu article (\u22ee) \u2014 flow mitovy amin'ny artiste \u2500\u2500 */}\n      {itemMenu && (\n        <div onClick={() => setItemMenu(null)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:300, display:'flex', alignItems:'flex-end', justifyContent:'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'#fff', borderRadius:'18px 18px 0 0', width:'100%', maxWidth:480, overflow:'hidden' }}>\n            {isAdmin ? (<>\n              <button onClick={() => { const p = itemMenu; setItemMenu(null); setItemInfo(p); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiInformationCircle size={19} color=\"#1877F2\"/> Informations</button>\n              <button onClick={() => { downloadMedia(itemMenu.mediaURL, itemMenu.mediaType || 'image', (itemMenu.content||'article').slice(0,30)); setItemMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiDownload size={19} color=\"#12A48D\"/> T\u00e9l\u00e9charger</button>\n              <button onClick={() => { const it = itemMenu; setItemMenu(null); setBoostTarget({ type:'post', id: it.id, ownerUid: it.uid, title: (it.content||'').slice(0,60) || shop.name, thumbnailURL: it.mediaURL || '' }); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiLightningBolt size={19} color=\"#a855f7\"/> Booster</button>\n              <button onClick={() => { const p = itemMenu; setItemMenu(null); setSharePost(p); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiShare size={19} color=\"#7A2DFF\"/> Partager</button>\n              <button onClick={() => deleteItem(itemMenu)} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#FF2D8D' }}><HiTrash size={19}/> Supprimer</button>\n            </>) : (<>\n              <button onClick={() => { const p = itemMenu; setItemMenu(null); setItemInfo(p); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiInformationCircle size={19} color=\"#1877F2\"/> Informations</button>\n              <button onClick={() => { downloadMedia(itemMenu.mediaURL, itemMenu.mediaType || 'image', (itemMenu.content||'article').slice(0,30)); setItemMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiDownload size={19} color=\"#12A48D\"/> T\u00e9l\u00e9charger</button>\n              <button onClick={() => { const p = itemMenu; setItemMenu(null); setSharePost(p); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiShare size={19} color=\"#7A2DFF\"/> Partager</button>\n              <button onClick={() => reportItem(itemMenu)} style={{ width:'100%', display:'flex', alignItems:'center', gap:13, padding:'15px 20px', background:'none', border:'none', cursor:'pointer', fontSize:15, fontWeight:600, color:'#FF2D8D' }}><HiFlag size={19}/> Signaler aux admins</button>\n            </>)}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Fiche article (Informations \u2014 mitovy amin'ny trackInfo artiste) \u2500\u2500 */}\n      {itemInfo && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setItemInfo(null)}>\n          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:'10px 0 22px', width:'100%', maxWidth:480, maxHeight:'80vh', overflowY:'auto' }}>\n            <div style={{ width:40, height:4, borderRadius:2, background:'#CED0D4', margin:'6px auto 14px' }} />\n            <div style={{ display:'flex', gap:14, padding:'0 20px 14px' }}>\n              <div style={{ width:80, height:80, borderRadius:12, background: itemInfo.mediaURL ? `url(${itemInfo.mediaURL}) center/cover` : 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>\n                {!itemInfo.mediaURL && <HiShoppingBag color=\"white\" size={28}/>}\n              </div>\n              <div style={{ flex:1, minWidth:0 }}>\n                <p style={{ fontWeight:800, fontSize:16, lineHeight:1.3 }}>{(itemInfo.content||'Article').slice(0,80)}</p>\n                <p style={{ fontSize:14, fontWeight:800, color:'#FF2D8D', marginTop:2 }}>{itemInfo.price ? `${Number(itemInfo.price).toLocaleString()} Ar` : '\u00c0 discuter'}</p>\n                {itemInfo.createdAt && <p style={{ fontSize:12, color:'#8A8D91', marginTop:2 }}>{timeAgo(itemInfo.createdAt)}</p>}\n              </div>\n            </div>\n            <div style={{ padding:'0 20px' }}>\n              {itemInfo.saleCategory && <InfoRow label=\"Cat\u00e9gorie\" value={itemInfo.saleCategory} />}\n              {Number(itemInfo.oldPrice) > 0 && <InfoRow label=\"Ancien prix\" value={`${Number(itemInfo.oldPrice).toLocaleString()} Ar`} />}\n              <InfoRow label=\"Vues\" value={String(itemInfo.views || 0)} />\n              <InfoRow label=\"Clics\" value={String(itemInfo.clicks || 0)} />\n              <InfoRow label=\"R\u00e9actions\" value={String(Object.keys(itemInfo.reactions||{}).length)} />\n              {itemInfo.lieu && <InfoRow label=\"Lieu\" value={itemInfo.lieu} />}\n              {itemInfo.contact && <InfoRow label=\"Contact\" value={itemInfo.contact} />}\n            </div>\n            <div style={{ padding:'14px 20px 0' }}>\n              <button onClick={() => { const p = itemInfo; setItemInfo(null); openItem(p); }} className=\"btn-gold\" style={{ width:'100%', padding:'12px', fontSize:15 }}>Voir la publication</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modifier la boutique \u2500\u2500 */}\n      {editOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setEditOpen(false)}>\n          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480, maxHeight:'80vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ fontWeight:800, color:'#FF2D8D' }}>Modifier la boutique</h3>\n              <button onClick={() => setEditOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            <input className=\"input\" value={editForm.name} onChange={e=>setEditForm(p=>({...p,name:e.target.value}))} placeholder=\"Nom de la boutique\" style={{ marginBottom:10 }}/>\n            <select value={editForm.category} onChange={e=>setEditForm(p=>({...p,category:e.target.value}))} className=\"input\" style={{ marginBottom:10 }}>\n              {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}\n            </select>\n            <textarea className=\"input\" value={editForm.description} onChange={e=>setEditForm(p=>({...p,description:e.target.value}))} placeholder=\"Description\" rows={3} style={{ resize:'none', marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.address} onChange={e=>setEditForm(p=>({...p,address:e.target.value}))} placeholder=\"Adresse exacte\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.contact} onChange={e=>setEditForm(p=>({...p,contact:e.target.value}))} placeholder=\"Contact (t\u00e9l\u00e9phone)\" style={{ marginBottom:10 }}/>\n            <input className=\"input\" value={editForm.team} onChange={e=>setEditForm(p=>({...p,team:e.target.value}))} placeholder=\"\u00c9quipe (personnes qui g\u00e8rent la boutique)\" style={{ marginBottom:14 }}/>\n            <button onClick={saveEdit} className=\"btn-primary\" style={{ width:'100%', padding:'11px 0', fontSize:14 }}>Enregistrer</button>\n          </div>\n        </div>\n      )}\n\n      {followersOpen && <FollowListModal uids={shop.followers||[]} title=\"Abonn\u00e9s\" onClose={() => setFollowersOpen(false)} />}\n\n      {/* \u2500\u2500 Statistiques plein \u00e9cran : SVG NeonIcons + donut + bar chart \u2500\u2500 */}\n      {statsOpen && (() => {\n        let reactions = 0, views = 0, clicks = 0, comments = 0;\n        items.forEach(it => { reactions += Object.keys(it.reactions||{}).length; views += it.views||0; clicks += it.clicks||0; comments += (it.comments||[]).length; });\n        const abonnes = (shop.followers||[]).length;\n        const statsData = [\n          { label:'Abonn\u00e9s',   value:abonnes,    color:'#1877F2', icon:<NeonPeople  size={18} color=\"#fff\"/> },\n          { label:'Articles',  value:items.length,color:'#FF2D8D',icon:<NeonChart   size={18} color=\"#fff\"/> },\n          { label:'R\u00e9actions', value:reactions,  color:'#FF7A00', icon:<NeonLike    size={18} color=\"#fff\"/> },\n          { label:'Vues',      value:views,      color:'#5E4BDB', icon:<NeonEye     size={18} color=\"#fff\"/> },\n          { label:'Clics',     value:clicks,     color:'#F2B300', icon:<NeonChart   size={16} color=\"#fff\"/> },\n          { label:'Comments',  value:comments,   color:'#12A48D', icon:<NeonComment size={18} color=\"#fff\"/> },\n        ];\n        const total = statsData.reduce((s,d)=>s+d.value,0)||1;\n        const maxV  = Math.max(...statsData.map(d=>d.value),1);\n        // Donut SVG\n        let cumPct = 0;\n        const R=48, CX=60, CY=60, CIRC=2*Math.PI*R;\n        const donutSegs = statsData.filter(d=>d.value>0).map((d,i)=>{\n          const pct = d.value/total;\n          const dash= pct*CIRC;\n          const off = -cumPct*CIRC + CIRC/4;\n          cumPct += pct;\n          return <circle key={i} cx={CX} cy={CY} r={R} fill=\"none\" stroke={d.color} strokeWidth={20}\n            strokeDasharray={dash + \" \" + (CIRC-dash)} strokeDashoffset={off}\n            style={{ transition:'stroke-dasharray .4s' }}/>;\n        });\n        return (\n          <div onClick={() => setStatsOpen(false)} style={{ position:'fixed', inset:0, background:'white', zIndex:400, overflowY:'auto', display:'flex', flexDirection:'column' }}>\n            {/* Header */}\n            <div style={{ position:'sticky', top:0, background:'white', zIndex:10, padding:'12px 16px', display:'flex', alignItems:'center', gap:10, borderBottom:'1px solid #E4E6EB', boxShadow:'0 1px 4px rgba(0,0,0,.06)' }}\n              onClick={e=>e.stopPropagation()}>\n              <button onClick={() => setStatsOpen(false)} style={{ background:'#F0F2F5', border:'none', borderRadius:'50%', width:36, height:36, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\u2190</button>\n              <NeonChart size={20}/>\n              <div>\n                <p style={{ fontWeight:800, fontSize:16 }}>Statistiques \u2014 {shop.name}</p>\n                <p style={{ fontSize:11, color:'#65676B' }}>Boutique \u00b7 abonn\u00e9s, articles, interactions</p>\n              </div>\n            </div>\n            <div onClick={e=>e.stopPropagation()} style={{ padding:'16px 14px 40px', maxWidth:520, margin:'0 auto', width:'100%' }}>\n              {/* Donut chart */}\n              <div style={{ background:'#F8F9FA', borderRadius:16, padding:'16px', marginBottom:14, display:'flex', alignItems:'center', gap:16 }}>\n                <svg width={120} height={120} viewBox=\"0 0 120 120\" style={{ flexShrink:0 }}>\n                  <circle cx={CX} cy={CY} r={R} fill=\"none\" stroke=\"#F0F2F5\" strokeWidth={20}/>\n                  {donutSegs}\n                  <text x={CX} y={CY-5} textAnchor=\"middle\" fontSize={11} fill=\"#65676B\">Total</text>\n                  <text x={CX} y={CY+10} textAnchor=\"middle\" fontSize={16} fontWeight={800} fill=\"#050505\">{total}</text>\n                </svg>\n                <div style={{ flex:1 }}>\n                  {statsData.filter(d=>d.value>0).map((d,i)=>(\n                    <div key={i} style={{ display:'flex', alignItems:'center', gap:6, marginBottom:5 }}>\n                      <div style={{ width:10, height:10, borderRadius:'50%', background:d.color, flexShrink:0 }}/>\n                      <span style={{ fontSize:12, color:'#65676B', flex:1 }}>{d.label}</span>\n                      <span style={{ fontSize:12, fontWeight:700 }}>{d.value.toLocaleString()}</span>\n                    </div>\n                  ))}\n                </div>\n              </div>\n              {/* Bar chart */}\n              <div style={{ background:'#F8F9FA', borderRadius:16, padding:'14px', marginBottom:14 }}>\n                <p style={{ fontWeight:700, fontSize:13, marginBottom:10, color:'#050505' }}>Distribution</p>\n                <div style={{ display:'flex', alignItems:'flex-end', gap:8, height:80 }}>\n                  {statsData.map((d,i)=>{\n                    const h = Math.max((d.value/maxV)*64,2);\n                    return (\n                      <div key={i} style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>\n                        <span style={{ fontSize:9, fontWeight:700, color:d.color }}>{d.value}</span>\n                        <div style={{ width:'100%', height:h, background:d.color, borderRadius:'6px 6px 2px 2px', opacity:0.85 }}/>\n                        <span style={{ fontSize:8, color:'#65676B', textAlign:'center', lineHeight:1.2 }}>{d.label}</span>\n                      </div>\n                    );\n                  })}\n                </div>\n              </div>\n              {/* Cards clicables */}\n              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>\n                {statsData.map((d,i)=>(\n                  <div key={i} style={{ background:'white', borderRadius:14, padding:'12px', border:'1px solid #E4E6EB', display:'flex', alignItems:'center', gap:10 }}>\n                    <span style={{ width:40, height:40, borderRadius:12, background:`linear-gradient(145deg,${d.color}99,${d.color})`, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{d.icon}</span>\n                    <div>\n                      <p style={{ fontWeight:800, fontSize:20, lineHeight:1 }}>{d.value.toLocaleString()}</p>\n                      <p style={{ fontSize:11, color:'#65676B', marginTop:2 }}>{d.label}</p>\n                    </div>\n                  </div>\n                ))}\n              </div>\n            </div>\n          </div>\n        );\n      })()}\n    </div>\n  );\n}\n\nfunction InfoRow({ label, value }) {\n  return (\n    <div style={{ display:'flex', justifyContent:'space-between', gap:12, padding:'8px 0', borderBottom:'1px solid #F0F2F5' }}>\n      <span style={{ fontSize:13, color:'#65676B', flexShrink:0 }}>{label}</span>\n      <span style={{ fontSize:13, fontWeight:600, textAlign:'right' }}>{value}</span>\n    </div>\n  );\n}\n";

const fs = require('fs');
let OK = 0, SKIP = 0, FAIL = 0;
const ok = (m) => { OK++; console.log('OK ' + m); };
const skip = (m) => { SKIP++; console.log('SKIP ' + m); };
const fail = (m) => { FAIL++; console.log('FAIL ' + m); };

try {
  if (!fs.existsSync('src/components')) throw new Error('src/components introuvable');
  fs.writeFileSync('src/components/Skeleton.jsx', SKELETON_SRC);
  ok('Skeleton.jsx cree (squelettes reutilisables)');
} catch (e) { fail('Skeleton.jsx: ' + e.message); }

try {
  const p = 'src/index.css';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('Skeleton loading')) skip('index.css : shimmer deja present');
  else { fs.writeFileSync(p, CSS_SRC); ok('index.css : animation shimmer'); }
} catch (e) { fail('index.css: ' + e.message); }

try {
  const p = 'src/pages/Home.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonPost')) skip('Home.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, HOME_SRC); ok('Home.jsx : skeleton pendant le premier chargement du fil'); }
} catch (e) { fail('Home.jsx: ' + e.message); }

try {
  const p = 'src/pages/ArtistDetail.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonChannelPage')) skip('ArtistDetail.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, ARTIST_SRC); ok('ArtistDetail.jsx : skeleton pendant le chargement'); }
} catch (e) { fail('ArtistDetail.jsx: ' + e.message); }

try {
  const p = 'src/pages/ShopDetail.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('SkeletonChannelPage')) skip('ShopDetail.jsx : skeleton deja actif');
  else { fs.writeFileSync(p, SHOP_SRC); ok('ShopDetail.jsx : skeleton pendant le chargement'); }
} catch (e) { fail('ShopDetail.jsx: ' + e.message); }

console.log('\nRESUME: OK=' + OK + ' SKIP=' + SKIP + ' FAIL=' + FAIL);
